function isDelegateWorker(value: string): value is DelegateWorker {
	return [
		"web-authz",
		"identity",
		"cloud",
		"mobile-runtime",
		"native-runtime",
		"pwn-exploit",
		"firmware-dfir",
		"agentsec",
		"malware",
		"reporting",
		"general",
	].includes(value);
}

type WorkerScoreboardEntry = {
	worker: DelegateWorker;
	packetId: string;
	verdict: string;
	score: number;
	retryBudget: number;
	failureCost: number;
	next: string;
	raw: string;
};

function parseWorkerScoreboardLine(line: string): WorkerScoreboardEntry | undefined {
	const match =
		/^(?<worker>[a-z0-9-]+)\s+packet=(?<packet>\S+)\s+verdict=(?<verdict>\w+)\s+score=(?<score>\d+)\s+retry_budget=(?<retry>\d+)\s+failure_cost=(?<cost>\d+)\s+next=(?<next>.*)$/i.exec(
			line.trim().replace(/^- /, ""),
		);
	if (!match?.groups || !isDelegateWorker(match.groups.worker)) return undefined;
	return {
		worker: match.groups.worker,
		packetId: match.groups.packet,
		verdict: match.groups.verdict,
		score: Number(match.groups.score),
		retryBudget: Number(match.groups.retry),
		failureCost: Number(match.groups.cost),
		next: match.groups.next.trim(),
		raw: line.trim().replace(/^- /, ""),
	};
}

function latestWorkerScoreboard(): { path?: string; lines: string[]; entries: WorkerScoreboardEntry[] } {
	const path = latestSupervisorArtifactPath();
	const supervisor = path ? parseSupervisorArtifact(path) : undefined;
	const lines = supervisor?.workerScoreboard ?? [];
	return {
		path,
		lines,
		entries: lines.map(parseWorkerScoreboardLine).filter((entry): entry is WorkerScoreboardEntry => Boolean(entry)),
	};
}

function workerAdaptiveRoutingHints(entries: WorkerScoreboardEntry[], target?: string): string[] {
	const suffix = commandTargetSuffix(target);
	return entries
		.flatMap((entry) => {
			if (entry.score >= 80 && /pass/i.test(entry.verdict)) return [];
			if (entry.score >= 60 && /watch/i.test(entry.verdict))
				return [
					`watch:${entry.worker} score=${entry.score} -> collect one more runtime/traffic/artifact anchor before expansion; command=re_swarm run${suffix} 1 1`,
				];
			const tools = delegateTools(entry.worker).slice(0, 5).join(" ");
			return [
				`repair:${entry.worker} score=${entry.score} verdict=${entry.verdict} -> reroute via evidence-repair lane; commands=re_bootstrap plan ${tools} && re_delegate plan${suffix} && re_swarm run${suffix} 1 1 && re_verifier matrix`,
				`verify:${entry.worker} packet=${entry.packetId} -> require negative control + replay artifact before merge; next=${entry.next}`,
			];
		})
		.slice(0, 24);
}

function buildWorkerPromotionQueue(entries: WorkerScoreboardEntry[], target?: string): string[] {
	const suffix = commandTargetSuffix(target);
	return entries
		.filter((entry) => entry.score >= 80 && /pass/i.test(entry.verdict))
		.map(
			(entry) =>
				`promote:${entry.worker} score=${entry.score} packet=${entry.packetId} -> re_reflect write${suffix}; re_knowledge_graph build${suffix}; memory/playbooks reuse`,
		)
		.slice(0, 16);
}

function dispatcherAdaptiveRoutingHints(target?: string): string[] {
	const suffix = commandTargetSuffix(target);
	return latestDispatcherFeedbackBoard()
		.hints.map((hint) => {
			const score = Number(/\bscore=(\d+)/.exec(hint)?.[1] ?? 50);
			const category = /\bcategory=([A-Za-z0-9_-]+)/.exec(hint)?.[1] ?? "unknown";
			const command = /\bcommand=(.+?)(?:\s+->|$)/.exec(hint)?.[1]?.trim() ?? "re_operator dispatch";
			if (/promote_dispatcher/i.test(hint)) {
				return `promote:dispatcher category=${category} score=${score} -> reuse ${command}; re_reflect write${suffix}; re_knowledge_graph build${suffix}`;
			}
			if (/demote_dispatcher/i.test(hint)) {
				return `repair:dispatcher category=${category} score=${score} -> demote ${command}; commands=re_autofix plan${suffix} && re_context pack${suffix} && re_operator dispatch${suffix} 1`;
			}
			return `watch:dispatcher category=${category} score=${score} -> bounded retry ${command}; command=re_operator dispatch${suffix} 1`;
		})
		.slice(0, 24);
}

function dispatcherPromotionQueue(target?: string): string[] {
	const suffix = commandTargetSuffix(target);
	return latestDispatcherFeedbackBoard()
		.hints.filter((hint) => /promote_dispatcher/i.test(hint))
		.map((hint) => {
			const score = Number(/\bscore=(\d+)/.exec(hint)?.[1] ?? 80);
			const category = /\bcategory=([A-Za-z0-9_-]+)/.exec(hint)?.[1] ?? "unknown";
			return `promote:dispatcher-feedback category=${category} score=${score} -> re_reflect write${suffix}; re_knowledge_graph build${suffix}; memory/dispatcher-feedback-board reuse`;
		})
		.slice(0, 16);
}

type DispatcherFeedbackParsedRow = {
	category: string;
	status: "passed" | "failed" | "queued";
	score: number;
	command: string;
	raw: string;
};

function parseShellQuotedValue(value: string | undefined): string | undefined {
	if (!value) return undefined;
	return value.replace(/'\\''/g, "'");
}

function parseDispatcherFeedbackRow(row: string): DispatcherFeedbackParsedRow | undefined {
	if (!/dispatcher_score/i.test(row)) return undefined;
	const category = /\bcategory=([A-Za-z0-9_-]+)/i.exec(row)?.[1] ?? "unknown";
	const statusText = /\bstatus=(passed|failed|queued)\b/i.exec(row)?.[1]?.toLowerCase() ?? "queued";
	const status = (["passed", "failed", "queued"].includes(statusText) ? statusText : "queued") as
		| "passed"
		| "failed"
		| "queued";
	const score = Math.max(0, Math.min(100, Number(/\bscore=(\d+)/i.exec(row)?.[1] ?? 0)));
	const commandMatch = /\bcommand=(?:'((?:'\\''|[^'])*)'|"([^"]+)"|(\S+))/i.exec(row);
	const command =
		parseShellQuotedValue(commandMatch?.[1]) ?? commandMatch?.[2] ?? commandMatch?.[3] ?? "re_operator dispatch";
	return { category, status, score, command: command.trim(), raw: row.trim().replace(/^- /, "") };
}

function dispatcherFeedbackParsedRows(rows?: string[]): DispatcherFeedbackParsedRow[] {
	const source = rows ?? latestDispatcherFeedbackBoard().lines;
	const seen = new Set<string>();
	return source
		.map(parseDispatcherFeedbackRow)
		.filter((row): row is DispatcherFeedbackParsedRow => Boolean(row))
		.filter((row) => {
			const key = `${row.category}:${row.status}:${row.score}:${row.command}`;
			if (seen.has(key)) return false;
			seen.add(key);
			return true;
		});
}

function dispatcherScoreDecayRows(rows?: string[]): string[] {
	const parsed = dispatcherFeedbackParsedRows(rows);
	return parsed
		.map((row) => {
			const decay = row.status === "passed" ? 0 : row.status === "failed" ? 30 : row.score >= 75 ? 6 : 10;
			const effective = Math.max(0, row.score - decay);
			const action =
				row.status === "passed" && row.score >= 80
					? "promote_dispatcher"
					: row.status === "failed" || effective < 40
						? "demote_dispatcher"
						: "retry_dispatcher";
			return [
				"score_decay dispatcher",
				`category=${row.category}`,
				`status=${row.status}`,
				`score=${row.score}`,
				`decay=${decay}`,
				`effective=${effective}`,
				`action=${action}`,
				`command=${shellQuote(row.command)}`,
			].join(" ");
		})
		.slice(0, 32);
}

function repeatedFailureDemotionRows(rows?: string[], target?: string): string[] {
	const suffix = commandTargetSuffix(target);
	const grouped = new Map<string, DispatcherFeedbackParsedRow[]>();
	for (const row of dispatcherFeedbackParsedRows(rows)) {
		const key = `${row.category}:${row.command}`;
		grouped.set(key, [...(grouped.get(key) ?? []), row]);
	}
	const demotions: string[] = [];
	for (const group of grouped.values()) {
		const latest = group[group.length - 1];
		if (!latest) continue;
		const failed = group.filter((row) => row.status === "failed").length;
		const queued = group.filter((row) => row.status === "queued").length;
		const effective = Math.max(
			0,
			latest.score - (latest.status === "failed" ? 30 : latest.status === "queued" ? 10 : 0),
		);
		if (failed === 0 && queued < 2 && effective >= 40) continue;
		demotions.push(
			[
				"demote_dispatcher repeated_failure",
				`category=${latest.category}`,
				`failed=${failed}`,
				`queued=${queued}`,
				`effective=${effective}`,
				`command=${shellQuote(latest.command)}`,
				`-> re_autofix plan${suffix} && re_context pack${suffix} && re_operator dispatch${suffix} 1`,
			].join(" "),
		);
	}
	return Array.from(new Set(demotions)).slice(0, 24);
}

function highScorePromotionRows(rows?: string[], target?: string): string[] {
	const suffix = commandTargetSuffix(target);
	const dispatcherPromotions = dispatcherFeedbackParsedRows(rows)
		.filter((row) => row.status === "passed" && row.score >= 80)
		.map((row) =>
			[
				"promote_dispatcher high_score_route",
				`category=${row.category}`,
				`score=${row.score}`,
				`command=${shellQuote(row.command)}`,
				`-> re_reflect write${suffix} && re_knowledge_graph build${suffix} && memory/dispatcher-promotion-playbook reuse`,
			].join(" "),
		);
	const workerPromotions = buildWorkerPromotionQueue(latestWorkerScoreboard().entries, target).map(
		(row) => `promote_worker high_score_route ${row}`,
	);
	return Array.from(new Set([...dispatcherPromotions, ...workerPromotions])).slice(0, 24);
}

function autonomousBudgetLedgerPath(): string {
	return memoryPath("autonomous-budget-ledger.md");
}

function latestAutonomousBudgetLedger(): AutonomousBudgetLedgerSnapshot {
	const path = autonomousBudgetLedgerPath();
	const text = readText(path);
	const rows = interestingLines(
		text,
		/score_decay|historical_score_decay|demote_|promote_|autonomous_budget|next=|re[-_]|formal_playbook/i,
		260,
	);
	const scoreDecay = rows.filter((row) => /score_decay|historical_score_decay/i.test(row));
	const laneDemotions = rows.filter((row) => /demote_lane|lane_demotion/i.test(row));
	const workerDemotions = rows.filter((row) => /demote_worker|worker_demotion/i.test(row));
	const dispatcherDemotions = rows.filter((row) => /demote_dispatcher|dispatcher_demotion/i.test(row));
	const demotions = rows.filter((row) => /demote_|repeated_failure|failure_demotion/i.test(row));
	const playbookPromotions = rows.filter((row) =>
		/formal_playbook|dispatcher-promotion-playbook|playbook_promotion/i.test(row),
	);
	const promotions = rows.filter((row) => /promote_|high_score|playbook_promotion|formal_playbook/i.test(row));
	const nextActions = rows
		.flatMap((row) => row.match(/re[-_][\w-]+(?:\s+[^\s;&|]+){0,5}/gi) ?? [])
		.map((command) => command.trim());
	return {
		path,
		turns: (text.match(/^## Turn /gm) ?? []).length,
		scoreDecay,
		demotions,
		laneDemotions,
		workerDemotions,
		dispatcherDemotions,
		promotions,
		playbookPromotions,
		nextActions: Array.from(new Set(nextActions)).slice(0, 24),
		rows,
	};
}

function historicalCategoryCount(rows: string[], category: string, pattern: RegExp): number {
	return rows.filter((row) => pattern.test(row) && row.includes(`category=${category}`)).length;
}

function cumulativeDispatcherScoreDecayRows(
	rows?: string[],
	ledger: AutonomousBudgetLedgerSnapshot = latestAutonomousBudgetLedger(),
): string[] {
	return dispatcherFeedbackParsedRows(rows)
		.map((row) => {
			const previous = historicalCategoryCount(
				ledger.scoreDecay,
				row.category,
				/score_decay|historical_score_decay/i,
			);
			if (previous <= 0) return undefined;
			const historicalDecay = Math.min(36, previous * (row.status === "passed" ? 1 : 4));
			const effective = Math.max(0, row.score - historicalDecay);
			const action =
				row.status === "passed" && effective >= 80
					? "promote_dispatcher"
					: effective < 45
						? "demote_dispatcher"
						: "retry_dispatcher";
			return [
				"historical_score_decay dispatcher",
				`category=${row.category}`,
				`status=${row.status}`,
				`previous=${previous}`,
				`score=${row.score}`,
				`historical_decay=${historicalDecay}`,
				`effective=${effective}`,
				`action=${action}`,
				`command=${shellQuote(row.command)}`,
			].join(" ");
		})
		.filter((row): row is string => Boolean(row))
		.slice(0, 24);
}

function workerScoreDemotionRows(
	target?: string,
	ledger: AutonomousBudgetLedgerSnapshot = latestAutonomousBudgetLedger(),
): string[] {
	const suffix = commandTargetSuffix(target);
	return latestWorkerScoreboard()
		.entries.filter((entry) => entry.score < 50 || /blocked|repair/i.test(entry.verdict))
		.map((entry) => {
			const previous = ledger.workerDemotions.filter((row) => row.includes(`worker=${entry.worker}`)).length;
			const effective = Math.max(0, entry.score - Math.min(24, previous * 4));
			return [
				"demote_worker repeated_low_score",
				`worker=${entry.worker}`,
				`verdict=${entry.verdict}`,
				`score=${entry.score}`,
				`previous=${previous}`,
				`effective=${effective}`,
				`packet=${entry.packetId}`,
				`-> re_delegate plan${suffix} && re_swarm run${suffix} 1 1 && re_supervisor repair${suffix}`,
			].join(" ");
		})
		.slice(0, 16);
}

function autonomousLaneDemotionRows(params: {
	dispatcherDemotions: string[];
	workerDemotions: string[];
	ledger: AutonomousBudgetLedgerSnapshot;
	target?: string;
}): string[] {
	const mission = readCurrentMission();
	const active = mission ? activeLane(mission) : undefined;
	if (!mission || !active) return [];
	if (active.name === "autonomous-dispatcher-repair") return [];
	const pressure =
		params.dispatcherDemotions.length + params.workerDemotions.length + params.ledger.laneDemotions.length;
	const repeatedDispatcher = params.ledger.dispatcherDemotions.length + params.dispatcherDemotions.length;
	const repeatedWorker = params.ledger.workerDemotions.length + params.workerDemotions.length;
	if (pressure < 3 && repeatedDispatcher < 3 && repeatedWorker < 3) return [];
	const suffix = commandTargetSuffix(params.target ?? mission.task);
	return [
		[
			"demote_lane autonomous_budget",
			`active=${active.name}`,
			`pressure=${pressure}`,
			`dispatcher_repeats=${repeatedDispatcher}`,
			`worker_repeats=${repeatedWorker}`,
			"target_lane=autonomous-dispatcher-repair",
			`-> re_lane plan autonomous-dispatcher-repair${suffix} && re_operator dispatch${suffix} 1 && re_proof_loop run${suffix} 4 2`,
		].join(" "),
	];
}

function applyAutonomousBudgetDemotions(budget: AutonomousExecutionBudget, source?: string): string[] {
	if (!budget.laneDemotions.length) return [];
	const mission = readCurrentMission();
	const active = mission ? activeLane(mission) : undefined;
	if (!mission || !active || active.name === "autonomous-dispatcher-repair") return [];
	if (/autonomous_budget_demoted/i.test(active.note ?? "")) return [];
	const timestamp = new Date().toISOString();
	const repairLaneName = "autonomous-dispatcher-repair";
	const repairNext = Array.from(
		new Set([
			...budget.nextActions,
			...budget.demotionRules.flatMap((row) => row.match(/re[-_][\w-]+(?:\s+[^\s;&|]+){0,5}/gi) ?? []),
			"re_context pack",
			"re_operator dispatch <target> 1",
			"re_proof_loop run <target> 4 2",
		]),
	).slice(0, 16);
	const existing = mission.lanes.find((lane) => lane.name === repairLaneName);
	let lanes: MissionLane[];
	if (existing) {
		lanes = mission.lanes.map((lane) => {
			if (lane.name === repairLaneName) {
				return {
					...lane,
					status: "in_progress" as const,
					next: Array.from(new Set([...lane.next, ...repairNext])).slice(0, 24),
					note: truncateMiddle(`autonomous_budget_repair; source=${active.name}; ${budget.laneDemotions[0]}`, 500),
					updatedAt: timestamp,
				};
			}
			if (lane.name === active.name) {
				return {
					...lane,
					status: "pending" as const,
					note: truncateMiddle(
						`autonomous_budget_demoted; repair_lane=${repairLaneName}; source=${source ?? "budget"}`,
						500,
					),
					updatedAt: timestamp,
				};
			}
			if (lane.status === "in_progress") return { ...lane, status: "pending" as const, updatedAt: timestamp };
			return lane;
		});
	} else {
		const currentIndex = mission.lanes.findIndex((lane) => lane.name === active.name);
		const repairLane: MissionLane = {
			name: repairLaneName,
			objective: "跨 turn autonomous budget 发现 dispatcher/worker/lane 重复低效，先降级旧路线并修复调度证据闭环",
			next: repairNext,
			status: "in_progress",
			note: truncateMiddle(`autonomous_budget_added; source=${active.name}; ${budget.laneDemotions[0]}`, 500),
			updatedAt: timestamp,
		};
		lanes = mission.lanes.map((lane) => {
			if (lane.name === active.name) {
				return {
					...lane,
					status: "pending" as const,
					note: truncateMiddle(
						`autonomous_budget_demoted; repair_lane=${repairLaneName}; source=${source ?? "budget"}`,
						500,
					),
					updatedAt: timestamp,
				};
			}
			if (lane.status === "in_progress") return { ...lane, status: "pending" as const, updatedAt: timestamp };
			return lane;
		});
		lanes.splice(Math.max(0, currentIndex + 1), 0, repairLane);
	}
	writeCurrentMission({ ...mission, lanes, updatedAt: timestamp });
	updateMissionGate("autonomous_budget_ready", "done", source ?? budget.ledgerPath ?? "autonomous-budget");
	return budget.laneDemotions;
}

function writeFormalDispatcherPromotionPlaybook(params: {
	budget: AutonomousExecutionBudget;
	timestamp: string;
	target?: string;
	artifactPath?: string;
	learningHints?: string[];
}): string | undefined {
	if (params.budget.playbookPromotions.length === 0) return undefined;
	const route = readCurrentMission()?.route.domain ?? "dispatcher";
	const score = Math.max(
		82,
		...params.budget.playbookPromotions.map((row) => Number(/\bscore=(\d+)/.exec(row)?.[1] ?? 0)),
	);
	const title = `dispatcher-promotion ${route}`;
	const path = join(memoryPlaybooksDir(), `${params.timestamp.replace(/[:.]/g, "-")}-${slug(title)}.md`);
	writeFileSync(
		path,
		[
			"# Pi-RECON Dispatcher Promotion Playbook",
			"",
			`timestamp: ${params.timestamp}`,
			`route: ${route}`,
			"requested_lane: dispatcher-promotion",
			`target: ${params.target ?? "<none>"}`,
			`source_artifact: ${params.artifactPath ?? "none"}`,
			`quality_score: ${score}`,
			`promotion_count: ${params.budget.playbookPromotions.length}`,
			`demotion_count: ${params.budget.demotionRules.length}`,
			"",
			"## High-score promotions",
			...(params.budget.playbookPromotions.length
				? params.budget.playbookPromotions.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Autonomous budget",
			...autonomousBudgetLines(params.budget).map((item) => `- ${item}`),
			"",
			"## Reusable commands",
			...(params.budget.nextActions.length ? params.budget.nextActions.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Dispatcher learning hints",
			...(params.learningHints?.length ? params.learningHints.map((item) => `- ${item}`) : ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	appendJournal(
		"dispatcher-promotion-playbook",
		title,
		[
			`formal_playbook: ${path}`,
			`quality_score=${score}; promotions=${params.budget.playbookPromotions.length}; demotions=${params.budget.demotionRules.length}`,
			...params.budget.playbookPromotions.slice(0, 6).map((item) => `promotion: ${item}`),
		].join("\n"),
	);
	appendEvolution(
		`dispatcher promotion ${route}`,
		[
			`Promoted high-score dispatcher/worker route into formal playbook: ${path}`,
			`target=${params.target ?? "<none>"}; source=${params.artifactPath ?? "none"}`,
			`autonomous_budget=${params.budget.maxTurns}/${params.budget.maxDispatch}/${params.budget.maxProofLoops}; score_decay=${params.budget.scoreDecay.length}`,
			"Policy: future case-memory migrations should prefer this route before repeating low-score dispatcher fallbacks.",
		].join("\n"),
	);
	maintainPlaybooks({ archive: true });
	return path;
}

function writeAutonomousBudgetLedger(params: {
	budget: AutonomousExecutionBudget;
	timestamp: string;
	target?: string;
	artifactPath?: string;
	formalPlaybookPath?: string;
}): string {
	ensureReconStorage();
	const path = autonomousBudgetLedgerPath();
	const header = "# Pi-RECON Autonomous Budget Ledger\n\n";
	const previous = readText(path, header);
	const turn = [
		`## Turn ${params.timestamp}`,
		`target=${params.target ?? "<none>"}`,
		`artifact=${params.artifactPath ?? "none"}`,
		`budget=max_turns:${params.budget.maxTurns},max_dispatch:${params.budget.maxDispatch},max_proof_loops:${params.budget.maxProofLoops},max_worker_retries:${params.budget.maxWorkerRetries}`,
		params.formalPlaybookPath ? `formal_playbook=${params.formalPlaybookPath}` : undefined,
		"### Score decay",
		...(params.budget.scoreDecay.length ? params.budget.scoreDecay.map((item) => `- ${item}`) : ["- none"]),
		"### Demotions",
		...(params.budget.demotionRules.length ? params.budget.demotionRules.map((item) => `- ${item}`) : ["- none"]),
		"### Promotions",
		...(params.budget.promotionRules.length ? params.budget.promotionRules.map((item) => `- ${item}`) : ["- none"]),
		"### Next actions",
		...(params.budget.nextActions.length ? params.budget.nextActions.map((item) => `- ${item}`) : ["- none"]),
		"",
	]
		.filter((item): item is string => Boolean(item))
		.join("\n");
	const combined = `${previous.endsWith("\n") ? previous : `${previous}\n`}${turn}`;
	const lines = combined.split("\n");
	const trimmed = lines.length > 1200 ? [header.trimEnd(), ...lines.slice(-1150)].join("\n") : combined;
	writeFileSync(path, trimmed.endsWith("\n") ? trimmed : `${trimmed}\n`, "utf-8");
	updateMissionGate("autonomous_budget_ready", "done", path);
	return path;
}

function autonomousExecutionBudget(target?: string, rows?: string[]): AutonomousExecutionBudget {
	const board = latestDispatcherFeedbackBoard();
	const ledger = latestAutonomousBudgetLedger();
	const scoreboardRows = rows ?? board.lines;
	const immediateScoreDecay = dispatcherScoreDecayRows(scoreboardRows);
	const historicalScoreDecay = cumulativeDispatcherScoreDecayRows(scoreboardRows, ledger);
	const dispatcherDemotions = repeatedFailureDemotionRows(scoreboardRows, target);
	const workerDemotions = workerScoreDemotionRows(target, ledger);
	const laneDemotions = autonomousLaneDemotionRows({ dispatcherDemotions, workerDemotions, ledger, target });
	const playbookPromotions = highScorePromotionRows(scoreboardRows, target);
	const scoreDecay = Array.from(new Set([...immediateScoreDecay, ...historicalScoreDecay])).slice(0, 40);
	const demotionRules = Array.from(new Set([...dispatcherDemotions, ...workerDemotions, ...laneDemotions])).slice(
		0,
		40,
	);
	const promotionRules = Array.from(new Set(playbookPromotions)).slice(0, 32);
	const queuedPressure = dispatcherFeedbackParsedRows(scoreboardRows).filter((row) => row.status === "queued").length;
	const historicalFailurePressure = Math.min(
		4,
		ledger.demotions.length + historicalScoreDecay.filter((row) => /demote_dispatcher/i.test(row)).length,
	);
	const failurePressure = demotionRules.length + historicalFailurePressure;
	const promotionPressure = promotionRules.length + Math.min(3, ledger.promotions.length);
	const maxTurns = Math.max(3, Math.min(9, 5 + Math.min(2, promotionPressure) - Math.min(3, failurePressure)));
	const maxDispatch = Math.max(
		1,
		Math.min(6, 2 + Math.min(2, promotionPressure) - Math.min(3, queuedPressure + failurePressure)),
	);
	const maxProofLoops = Math.max(1, Math.min(5, 2 + (promotionPressure > 0 ? 1 : 0) - (failurePressure > 3 ? 1 : 0)));
	const maxWorkerRetries = Math.max(1, Math.min(4, 2 + (failurePressure > 0 ? 1 : 0)));
	const suffix = commandTargetSuffix(target);
	const nextActions = Array.from(
		new Set([
			...(laneDemotions.length
				? [`re_lane plan autonomous-dispatcher-repair${suffix}`, `re_lane run-auto autonomous-dispatcher-repair 2`]
				: []),
			...(demotionRules.length ? [`re_autofix plan${suffix}`, `re_context pack${suffix}`] : []),
			...(promotionRules.length
				? [`re_reflect write${suffix}`, `re_knowledge_graph build${suffix}`, "re_memory playbooks"]
				: []),
			`re_operator dispatch${suffix} ${Math.min(3, maxDispatch)}`,
			`re_proof_loop run${suffix} ${Math.min(6, maxProofLoops + 2)} 2`,
		]),
	).slice(0, 14);
	return {
		maxTurns,
		maxDispatch,
		maxProofLoops,
		maxWorkerRetries,
		dispatcherBoardPath: board.path,
		promotionPlaybookPath: memoryPath("dispatcher-promotion-playbook.md"),
		ledgerPath: ledger.path,
		scoreDecay,
		historicalScoreDecay,
		demotionRules,
		laneDemotions,
		workerDemotions,
		dispatcherDemotions,
		promotionRules,
		playbookPromotions,
		ledgerRows: ledger.rows.slice(0, 40),
		nextActions,
	};
}

function autonomousBudgetLines(budget: AutonomousExecutionBudget | undefined): string[] {
	const current = budget ?? autonomousExecutionBudget();
	return [
		`max_turns=${current.maxTurns}`,
		`max_dispatch=${current.maxDispatch}`,
		`max_proof_loops=${current.maxProofLoops}`,
		`max_worker_retries=${current.maxWorkerRetries}`,
		`dispatcher_board=${current.dispatcherBoardPath ?? "none"}`,
		`promotion_playbook=${current.promotionPlaybookPath ?? "none"}`,
		`ledger=${current.ledgerPath ?? "none"}`,
		`formal_playbook=${current.formalPlaybookPath ?? "none"}`,
		`score_decay=${current.scoreDecay.length}`,
		`historical_score_decay=${current.historicalScoreDecay.length}`,
		`demotions=${current.demotionRules.length}`,
		`lane_demotions=${current.laneDemotions.length}`,
		`worker_demotions=${current.workerDemotions.length}`,
		`dispatcher_demotions=${current.dispatcherDemotions.length}`,
		`promotions=${current.promotionRules.length}`,
		`playbook_promotions=${current.playbookPromotions.length}`,
		`ledger_rows=${current.ledgerRows.length}`,
		...(current.nextActions.length ? current.nextActions.map((item) => `next=${item}`) : ["next=none"]),
	];
}

function writeDispatcherPromotionPlaybook(options: {
	target?: string;
	timestamp?: string;
	artifactPath?: string;
	scoreboard?: string[];
	learningHints?: string[];
}): string {
	ensureReconStorage();
	const timestamp = options.timestamp ?? new Date().toISOString();
	const path = memoryPath("dispatcher-promotion-playbook.md");
	const budget = autonomousExecutionBudget(options.target, options.scoreboard);
	const formalPlaybookPath = writeFormalDispatcherPromotionPlaybook({
		budget,
		timestamp,
		target: options.target,
		artifactPath: options.artifactPath,
		learningHints: options.learningHints,
	});
	if (formalPlaybookPath) budget.formalPlaybookPath = formalPlaybookPath;
	const ledgerPath = writeAutonomousBudgetLedger({
		budget,
		timestamp,
		target: options.target,
		artifactPath: options.artifactPath,
		formalPlaybookPath,
	});
	budget.ledgerPath = ledgerPath;
	const appliedDemotions = applyAutonomousBudgetDemotions(budget, options.artifactPath ?? ledgerPath);
	writeFileSync(
		path,
		[
			"# Pi-RECON Dispatcher Promotion Playbook",
			"",
			`Updated: ${timestamp}`,
			`Source artifact: ${options.artifactPath ?? "none"}`,
			`Target: ${options.target ?? "<none>"}`,
			`Ledger: ${ledgerPath}`,
			`Formal playbook: ${formalPlaybookPath ?? "none"}`,
			"",
			"## Autonomous execution budget",
			...autonomousBudgetLines(budget).map((item) => `- ${item}`),
			"",
			"## Score decay",
			...(budget.scoreDecay.length ? budget.scoreDecay.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Historical score decay",
			...(budget.historicalScoreDecay.length ? budget.historicalScoreDecay.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Repeated failure demotions",
			...(budget.demotionRules.length ? budget.demotionRules.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Applied lane demotions",
			...(appliedDemotions.length ? appliedDemotions.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## High-score promotions",
			...(budget.promotionRules.length ? budget.promotionRules.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Dispatcher learning hints",
			...(options.learningHints?.length ? options.learningHints.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Reusable next actions",
			...(budget.nextActions.length ? budget.nextActions.map((item) => `- ${item}`) : ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	return path;
}

function adaptiveToolsForWorker(worker: DelegateWorker, entries: WorkerScoreboardEntry[]): string[] {
	const entry = entries.find((item) => item.worker === worker);
	if (!entry || entry.score >= 80) return [];
	const extra: Record<DelegateWorker, string[]> = {
		"web-authz": ["re_web_authz_state", "playwright", "curl"],
		identity: ["re_verifier", "jq", "python3"],
		cloud: ["kubectl", "aws", "jq"],
		"mobile-runtime": ["frida", "adb", "jadx"],
		"native-runtime": ["gdb", "r2", "readelf"],
		"pwn-exploit": ["gdb", "python3", "ROPgadget"],
		"firmware-dfir": ["binwalk", "tshark", "python3"],
		agentsec: ["rg", "jq", "python3"],
		malware: ["yara", "capa", "strings"],
		reporting: ["re_compiler", "re_complete", "python3"],
		general: ["re_verifier", "re_replayer", "python3"],
	};
	return extra[worker];
}

function buildDelegate(options: { target?: string; task?: string; mode?: "plan" | "merge" } = {}): DelegateArtifact {
	ensureReconStorage();
	const { operation, path: operationArtifact } = latestOrBuildOperation(options);
	const scoreboard = latestWorkerScoreboard();
	const target = operation.target ?? options.target;
	const autonomousBudget = autonomousExecutionBudget(target);
	const adaptiveRoutingHints = Array.from(
		new Set([
			...workerAdaptiveRoutingHints(scoreboard.entries, target),
			...dispatcherAdaptiveRoutingHints(target),
			...autonomousBudget.scoreDecay.slice(0, 8),
		]),
	).slice(0, 32);
	const workerPromotionQueue = Array.from(
		new Set([
			...buildWorkerPromotionQueue(scoreboard.entries, target),
			...dispatcherPromotionQueue(target),
			...autonomousBudget.promotionRules,
		]),
	).slice(0, 24);
	const groups = new Map<DelegateWorker, OperationStep[]>();
	for (const step of operation.steps) {
		const worker = delegateWorkerForStep(step);
		groups.set(worker, [...(groups.get(worker) ?? []), step]);
	}
	const packets: DelegatePacket[] = [...groups.entries()].map(([worker, steps], index) => {
		const status = steps.every((step) => step.status === "done")
			? "done"
			: steps.some((step) => step.status === "ready")
				? "ready"
				: "blocked";
		const phases = Array.from(new Set(steps.map((step) => step.phase)));
		const sourceArtifacts = Array.from(new Set(steps.flatMap((step) => step.sourceArtifacts))).slice(0, 16);
		return {
			id: `worker:${index + 1}:${worker}`,
			worker,
			objective: delegateObjective(worker),
			status,
			phases,
			steps,
			evidenceContract: Array.from(
				new Set([
					...delegateEvidenceContract(worker),
					...(scoreboard.entries.some((entry) => entry.worker === worker && entry.score < 80)
						? ["adaptive worker score closure", "negative control or replay artifact"]
						: []),
				]),
			).slice(0, 8),
			recommendedTools: Array.from(
				new Set([...delegateTools(worker), ...adaptiveToolsForWorker(worker, scoreboard.entries)]),
			).slice(0, 12),
			handoffPrompt: [
				`worker=${worker}`,
				`objective=${delegateObjective(worker)}`,
				`target=${target ?? "<target>"}`,
				`evidence_contract=${delegateEvidenceContract(worker).join(" | ")}`,
				`adaptive_score=${scoreboard.entries.find((entry) => entry.worker === worker)?.score ?? "none"}`,
				`adaptive_route=${
					adaptiveRoutingHints.find((hint) => hint.includes(`:${worker} `) || hint.includes(`:${worker}:`)) ??
					workerPromotionQueue.find((hint) => hint.includes(`:${worker} `)) ??
					"none"
				}`,
				`next_steps=${
					steps
						.filter((step) => step.status === "ready")
						.map((step) => step.command)
						.join(" || ") || "none"
				}`,
			],
			sourceArtifacts,
		};
	});
	const gaps = Array.from(
		new Set(
			[
				...operation.blocked.map((item) => `operation: ${item}`),
				...packets
					.filter((packet) => packet.status === "blocked")
					.map((packet) => `worker blocked: ${packet.worker}`),
				...adaptiveRoutingHints.map((hint) => `adaptive routing: ${hint}`),
				...autonomousBudget.demotionRules.map((item) => `budget demotion: ${item}`),
				packets.length === 0 ? "no delegate packets generated" : undefined,
			].filter((item): item is string => Boolean(item)),
		),
	).slice(0, 24);
	const mergeQueue = [
		...packets.map((packet) => `${packet.id} ${packet.worker} status=${packet.status}`),
		...workerPromotionQueue,
		...autonomousBudget.demotionRules,
	].slice(0, 32);
	const specialistCoverage = packets.map(
		(packet) => `${packet.worker}: phases=${packet.phases.length} steps=${packet.steps.length}`,
	);
	const nextActions = Array.from(
		new Set([
			...packets
				.filter((packet) => packet.status === "ready")
				.flatMap((packet) =>
					packet.steps
						.filter((step) => step.status === "ready")
						.slice(0, 2)
						.map((step) => step.command),
				),
			...adaptiveRoutingHints
				.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? [])
				.map((command) => operatorCommandConcrete(command, target).command),
			...workerPromotionQueue
				.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? [])
				.map((command) => operatorCommandConcrete(command, target).command),
			...autonomousBudget.nextActions,
			"re_operation run <target> 1",
			"re_delegate merge",
			"re_complete audit",
		]),
	).slice(0, 16);
	return {
		timestamp: new Date().toISOString(),
		missionId: operation.missionId,
		route: operation.route,
		target,
		mode: options.mode ?? "plan",
		operationArtifact,
		packets,
		mergeQueue,
		specialistCoverage,
		workerScoreboard: scoreboard.lines.slice(0, 32),
		adaptiveRoutingHints,
		workerPromotionQueue,
		autonomousBudget,
		dispatcherScoreDecay: autonomousBudget.scoreDecay,
		repeatedFailureDemotions: autonomousBudget.demotionRules,
		highScorePromotions: autonomousBudget.promotionRules,
		gaps,
		nextActions,
		sourceArtifacts: Array.from(
			new Set([operationArtifact, scoreboard.path, ...operation.sourceArtifacts].filter(Boolean) as string[]),
		).slice(0, 32),
	};
}

function formatDelegate(delegate: DelegateArtifact, path?: string): string {
	return [
		"delegation_plan:",
		path ? `delegation_artifact: ${path}` : undefined,
		`timestamp: ${delegate.timestamp}`,
		`mode: ${delegate.mode}`,
		`mission_id: ${delegate.missionId ?? "none"}`,
		`route: ${delegate.route ?? "none"}`,
		`target: ${delegate.target ?? "<none>"}`,
		`operation_artifact: ${delegate.operationArtifact ?? "none"}`,
		"worker_packets:",
		...(delegate.packets.length
			? delegate.packets.flatMap((packet) => [
					`- ${packet.id} [${packet.status}] worker=${packet.worker} phases=${packet.phases.join(",") || "none"} steps=${packet.steps.length}`,
					`  objective: ${packet.objective}`,
					`  evidence_contract: ${packet.evidenceContract.join(" | ")}`,
					`  recommended_tools: ${packet.recommendedTools.join(", ")}`,
					`  handoff: ${packet.handoffPrompt.join(" ; ")}`,
				])
			: ["- none"]),
		"merge_queue:",
		...(delegate.mergeQueue.length ? delegate.mergeQueue.map((item) => `- ${item}`) : ["- none"]),
		"specialist_coverage:",
		...(delegate.specialistCoverage.length ? delegate.specialistCoverage.map((item) => `- ${item}`) : ["- none"]),
		"worker_scoreboard:",
		...(delegate.workerScoreboard?.length ? delegate.workerScoreboard.map((item) => `- ${item}`) : ["- none"]),
		"adaptive_routing_hints:",
		...(delegate.adaptiveRoutingHints?.length
			? delegate.adaptiveRoutingHints.map((item) => `- ${item}`)
			: ["- none"]),
		"worker_promotion_queue:",
		...(delegate.workerPromotionQueue?.length
			? delegate.workerPromotionQueue.map((item) => `- ${item}`)
			: ["- none"]),
		"autonomous_execution_budget:",
		...autonomousBudgetLines(delegate.autonomousBudget).map((item) => `- ${item}`),
		"dispatcher_score_decay:",
		...(delegate.dispatcherScoreDecay?.length
			? delegate.dispatcherScoreDecay.map((item) => `- ${item}`)
			: ["- none"]),
		"repeated_failure_demotions:",
		...(delegate.repeatedFailureDemotions?.length
			? delegate.repeatedFailureDemotions.map((item) => `- ${item}`)
			: ["- none"]),
		"high_score_promotions:",
		...(delegate.highScorePromotions?.length ? delegate.highScorePromotions.map((item) => `- ${item}`) : ["- none"]),
		"evidence_gaps:",
		...(delegate.gaps.length ? delegate.gaps.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(delegate.nextActions.length ? delegate.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_delegate_command: ${delegate.mode === "merge" ? "re_complete audit" : "re_delegate merge"}`,
		"source_artifacts:",
		...(delegate.sourceArtifacts.length ? delegate.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeDelegateArtifact(delegate: DelegateArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceDelegationsDir(),
		`${delegate.timestamp.replace(/[:.]/g, "-")}-${slug(delegate.route ?? "delegation")}-${delegate.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Delegation Artifact",
			"",
			formatDelegate(delegate, path),
			"",
			"## Worker packets",
			"",
			...delegate.packets.map(
				(packet) => `- ${packet.id} worker=${packet.worker} status=${packet.status} steps=${packet.steps.length}`,
			),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(delegate, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `delegation-${delegate.mode} ${delegate.missionId ?? "no-mission"}`,
		fact: `Built delegation plan with ${delegate.packets.length} worker packet(s), ${delegate.mergeQueue.length} merge item(s), ${delegate.gaps.length} gap(s), adaptive_routes=${delegate.adaptiveRoutingHints.length}, promotions=${delegate.workerPromotionQueue.length}`,
		command: `re_delegate ${delegate.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "operation/campaign specialist delegation",
	});
	updateMissionGate("delegation_packets_ready", "done", path);
	return path;
}

function buildDelegateOutput(
	action: "plan" | "show" | "merge" = "plan",
	options: { target?: string; task?: string } = {},
): string {
	if (action === "show") {
		const path = latestDelegateArtifactPath();
		if (!path) return "delegation_plan:\nstatus: missing\nnext: re_delegate plan";
		return truncateMiddle(readText(path), 16000);
	}
	const delegate = buildDelegate({ ...options, mode: action === "merge" ? "merge" : "plan" });
	const path = writeDelegateArtifact(delegate);
	const mergeSummary =
		action === "merge"
			? [
					"",
					"merge_summary:",
					`- packets: ${delegate.packets.length}`,
					`- ready: ${delegate.packets.filter((packet) => packet.status === "ready").length}`,
					`- done: ${delegate.packets.filter((packet) => packet.status === "done").length}`,
					`- blocked: ${delegate.packets.filter((packet) => packet.status === "blocked").length}`,
				].join("\n")
			: "";
	return `${formatDelegate(delegate, path)}${mergeSummary}`;
}

function latestSwarmArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceSwarmsDir(), 1)[0];
}

function swarmArtifactPath(swarm: Pick<SwarmArtifact, "timestamp" | "route" | "mode">): string {
	return join(
		evidenceSwarmsDir(),
		`${swarm.timestamp.replace(/[:.]/g, "-")}-${slug(swarm.route ?? "swarm")}-${swarm.mode}.md`,
	);
}

function swarmClaimLedgerPath(swarm: Pick<SwarmArtifact, "timestamp" | "route" | "mode">): string {
	return swarmArtifactPath(swarm).replace(/\.md$/i, "-claim-ledger.jsonl");
}

function swarmSubagentRuntimeManifestIndexPath(swarm: Pick<SwarmArtifact, "timestamp" | "route" | "mode">): string {
	return swarmArtifactPath(swarm).replace(/\.md$/i, "-subagent-runtime-manifests.json");
}

function swarmSubagentSessionRoot(swarm: Pick<SwarmArtifact, "timestamp" | "route" | "mode">): string {
	return swarmArtifactPath(swarm).replace(/\.md$/i, "-sessions");
}

function parseSwarmArtifact(path: string): SwarmArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as SwarmArtifact;
	} catch {
		return undefined;
	}
}

function splitRetryNextCommands(next: string): string[] {
	return next
		.split(/\s*(?:&&|;)\s*/g)
		.map((item) => item.trim().replace(/^\//, ""))
		.filter((item) => /^re[-_]/i.test(item));
}

function latestSwarmRetryQueue(target?: string): { path?: string; rows: string[]; commands: string[] } {
	const path = latestSwarmArtifactPath();
	const swarm = path ? parseSwarmArtifact(path) : undefined;
	if (!swarm) return { path, rows: [], commands: [] };
	if (target && swarm.target && target !== swarm.target) return { path, rows: [], commands: [] };
	const concreteTarget = target ?? swarm.target;
	const rows = Array.from(new Set(swarm.retryQueue ?? [])).slice(0, 32);
	const commands = rows
		.flatMap((row) => /\bnext=(.+)$/i.exec(row)?.[1]?.trim() ?? "")
		.flatMap(splitRetryNextCommands)
		.map((command) => operatorCommandConcrete(command, concreteTarget).command)
		.filter((command) => /^re[-_]/i.test(command))
		.filter((command) => !/^re[-_]operator\s+dispatch\b/i.test(command));
	return { path, rows, commands: Array.from(new Set(commands)).slice(0, 12) };
}

function swarmMergeKeys(packet: DelegatePacket): string[] {
	return Array.from(
		new Set([
			`worker=${packet.worker}`,
			...packet.phases.map((phase) => `phase=${phase}`),
			...packet.evidenceContract.map((item) => `evidence=${slug(item).slice(0, 32)}`),
		]),
	).slice(0, 14);
}

function swarmDependencies(packet: DelegatePacket): string[] {
	const deps = new Set<string>();
	for (const step of packet.steps) {
		if (/re_map|passive map/i.test(step.command)) deps.add("passive_map_done");
		if (/re_lane plan|repro/i.test(step.command)) deps.add("repro_commands_ready");
		if (/re_lane run|run-auto|runtime|proof/i.test(step.command)) deps.add("minimal_path_proven");
		if (/re_verifier/i.test(step.command)) deps.add("verifier_matrix_ready");
		if (/re_compiler|report/i.test(step.command)) deps.add("compiler_ready");
		if (/re_replayer|replay/i.test(step.command)) deps.add("replay_ready");
		if (/re_autofix|repair/i.test(step.command)) deps.add("autofix_ready");
	}
	if (deps.size === 0) deps.add("delegation_packets_ready");
	return Array.from(deps).slice(0, 10);
}

function swarmSpawnPrompt(packet: DelegatePacket, target?: string): string[] {
	return [
		`role=${packet.worker}`,
		`target=${target ?? "<target>"}`,
		`objective=${packet.objective}`,
		`evidence_contract=${packet.evidenceContract.join(" | ")}`,
		`source_artifacts=${packet.sourceArtifacts.join(" | ") || "none"}`,
		`commands=${
			packet.steps
				.filter((step) => step.status === "ready")
				.slice(0, 5)
				.map((step) => step.command)
				.join(" || ") || "inspect source artifacts and return gap"
		}`,
		"return_format=Outcome -> Key Evidence -> Verification -> Next Step; include paths/hashes/commands only",
	];
}


const RECON_PARALLEL_EVIDENCE_ORDER = [
	"same_window_live",
	"runtime_artifact",
	"network",
	"served_asset",
	"process_config",
	"persisted_state",
];

function swarmArtifactGlobs(worker: SwarmWorkerRuntime, delegationArtifact?: string): string[] {
	return Array.from(
		new Set([
			delegationArtifact,
			...worker.sourceArtifacts,
			"memory/evidence-ledger.md",
			"memory/commander-merge-board.md",
			"recon/evidence/**",
		].filter((item): item is string => Boolean(item))),
	).slice(0, 16);
}

function buildSwarmParallelPlan(params: {
	delegate: DelegateArtifact;
	delegationArtifact?: string;
	workers: SwarmWorkerRuntime[];
	timestamp: string;
	target?: string;
	mode?: "plan" | "run" | "merge";
}): ReconParallelPlanV1 {
	const { delegate, delegationArtifact, workers, timestamp } = params;
	const target = delegate.target ?? params.target;
	const planIdBase = delegate.missionId ?? delegate.route ?? target ?? "mission";
	return {
		kind: "ReconParallelPlanV1",
		schemaVersion: 1,
		planId: `re_swarm/${slug(planIdBase).slice(0, 64)}/${timestamp}`,
		target,
		source: "re_swarm",
		strategy: `${delegate.route ?? "operation"}:${params.mode ?? "plan"}`,
		workers: workers.map((worker) => ({
			id: worker.id,
			role: worker.worker,
			objective: worker.objective,
			commands: worker.commands,
			evidenceContract: worker.evidenceContract,
			mergeKeys: worker.mergeKeys,
			dependencies: worker.dependencies,
			artifactGlobs: swarmArtifactGlobs(worker, delegationArtifact),
			limits: {
				timeoutMs: 60000,
				maxCommands: Math.max(1, Math.min(5, worker.commands.length || 1)),
				recommendedTools: worker.recommendedTools.slice(0, 8),
			},
			prompt: worker.spawnPrompt,
			sourceWorkerId: worker.worker,
		})),
		merge: {
			strategy: "supervisor",
			evidenceOrder: RECON_PARALLEL_EVIDENCE_ORDER,
			expectedArtifacts: Array.from(
				new Set([
					delegationArtifact,
					...workers.flatMap((worker) => worker.sourceArtifacts),
					"memory/evidence-ledger.md",
					"memory/commander-merge-board.md",
				].filter((item): item is string => Boolean(item))),
			).slice(0, 40),
			command: "re_supervisor review",
			conflictPolicy:
				"supervisor coverage_matrix, execution_audit, and runtime artifacts overrule narrative-only worker summaries; unresolved conflicts block final claim promotion",
		},
	};
}

function swarmPlanCoverage(swarm: Pick<SwarmArtifact, "workers" | "parallelPlan" | "coverageMatrix" | "collisionMatrix">): string[] {
	const plan = swarm.parallelPlan;
	if (!plan) return ["parallel_plan=missing status=fail next=re_swarm plan"];
	const workerIds = new Set(swarm.workers.map((worker) => worker.id));
	const planWorkerIds = new Set(plan.workers.map((worker) => worker.id));
	const missingFromPlan = [...workerIds].filter((id) => !planWorkerIds.has(id));
	const orphanPlanWorkers = [...planWorkerIds].filter((id) => !workerIds.has(id));
	const contractRows = plan.workers.map((worker) => {
		const coverageRows = swarm.coverageMatrix.filter((row) => row.includes(`worker=${worker.id}`));
		const missingRows = coverageRows.filter((row) => /status=missing/i.test(row));
		return `worker=${worker.id} contract=${worker.evidenceContract.length} coverage_rows=${coverageRows.length} missing=${missingRows.length}`;
	});
	return [
		`parallel_plan_id=${plan.planId}`,
		`parallel_plan_source=${plan.source}`,
		`parallel_plan_workers=${plan.workers.length} swarm_workers=${swarm.workers.length}`,
		`worker_binding=${missingFromPlan.length || orphanPlanWorkers.length ? "fail" : "pass"}`,
		`missing_from_plan=${missingFromPlan.join(",") || "none"}`,
		`orphan_plan_workers=${orphanPlanWorkers.join(",") || "none"}`,
		`merge_strategy=${plan.merge.strategy}`,
		`evidence_order=${plan.merge.evidenceOrder.join(">")}`,
		`collision_rows=${swarm.collisionMatrix.length}`,
		...contractRows,
	].slice(0, 48);
}

function swarmReleaseGateMetadata(plan?: ReconParallelPlanV1): string[] {
	if (!plan) return ["release_gate.parallel_plan_present=false", "release_gate.next=re_swarm plan"];
	return [
		"release_gate.parallel_plan_present=true",
		`release_gate.parallel_plan_id=${plan.planId}`,
		`release_gate.source=${plan.source}`,
		`release_gate.worker_count=${plan.workers.length}`,
		`release_gate.worker_required_fields=id,role,objective,commands,evidenceContract,mergeKeys,dependencies,artifactGlobs,limits`,
		`release_gate.merge_strategy=${plan.merge.strategy}`,
		`release_gate.evidence_order=${plan.merge.evidenceOrder.join(">")}`,
		"release_gate.claim_promotion=blocked_until_supervisor_claim_gate_passes",
	];
}

function swarmClaimLedgerEventHash(event: SwarmClaimLedgerEventV1): string {
	const { eventHash: _eventHash, ...withoutHash } = event;
	return createHash("sha256").update(JSON.stringify(withoutHash)).digest("hex");
}

function appendSwarmClaimLedgerEvent(
	events: SwarmClaimLedgerEventV1[],
	event: Omit<SwarmClaimLedgerEventV1, "kind" | "seq" | "prevHash" | "eventHash" | "timestamp" | "source">,
	timestamp: string,
): SwarmClaimLedgerEventV1 {
	const row: SwarmClaimLedgerEventV1 = {
		kind: "ClaimLedgerEventV1",
		seq: events.length + 1,
		prevHash: events.at(-1)?.eventHash ?? "0".repeat(64),
		eventHash: "",
		timestamp,
		source: "re_swarm",
		...event,
	};
	row.eventHash = swarmClaimLedgerEventHash(row);
	events.push(row);
	return row;
}

function swarmClaimLedgerHashChainOk(events: SwarmClaimLedgerEventV1[]): boolean {
	let prevHash = "0".repeat(64);
	for (const event of events) {
		if (event.kind !== "ClaimLedgerEventV1" || event.prevHash !== prevHash) return false;
		if (event.eventHash !== swarmClaimLedgerEventHash(event)) return false;
		prevHash = event.eventHash;
	}
	return events.length > 0;
}

function buildSwarmRuntimeClaimLedger(swarm: SwarmArtifact): SwarmClaimLedgerEventV1[] {
	const events: SwarmClaimLedgerEventV1[] = [];
	const timestamp = swarm.timestamp;
	const planId = swarm.parallelPlan?.planId ?? "missing";
	const scope = swarm.target ?? swarm.missionId ?? swarm.route ?? "re_swarm";
	appendSwarmClaimLedgerEvent(
		events,
		{
			type: "artifact_handoff",
			claimId: `${planId}:artifact_handoff`,
			workerId: "re_swarm",
			role: "swarm",
			scope,
			statement: "re_swarm emitted ReconParallelPlanV1-bound worker runtime packets and merge contract.",
			evidenceRefs: [
				swarm.delegationArtifact,
				swarm.subagentRuntimeManifestPath,
				...(swarm.parallelPlan?.merge.expectedArtifacts ?? []),
				...(swarm.subagentRuntimeManifests ?? []).flatMap((manifest) => [
					manifest.runtimeManifestFile,
					manifest.stdoutPath,
					manifest.stderrPath,
				]),
				...swarm.sourceArtifacts,
			].filter((item): item is string => Boolean(item)),
			artifactHashes: runtimeArtifactHashes([
				swarm.delegationArtifact,
				swarm.subagentRuntimeManifestPath,
				...(swarm.subagentRuntimeManifests ?? []).flatMap((manifest) => [
					manifest.runtimeManifestFile,
					manifest.stdoutPath,
					manifest.stderrPath,
				]),
				...swarm.sourceArtifacts,
			]),
			metadata: {
				mode: swarm.mode,
				planId,
				workerCount: swarm.workers.length,
				executionCount: swarm.executions.length,
				subagentRuntimeManifestCount: swarm.subagentRuntimeManifestCount,
				subagentRuntimeManifestsCaptured: swarm.subagentRuntimeManifestsCaptured,
				mergeStrategy: swarm.parallelPlan?.merge.strategy ?? "missing",
			},
		},
		timestamp,
	);
	for (const worker of swarm.workers) {
		const executions = swarm.executions.filter((execution) => execution.workerId === worker.id);
		const runtimeManifests = (swarm.subagentRuntimeManifests ?? []).filter((manifest) => manifest.workerId === worker.id);
		const runtimeManifestRefs = runtimeManifests.flatMap((manifest) => [
			manifest.runtimeManifestFile,
			manifest.stdoutPath,
			manifest.stderrPath,
		]);
		const blocked = executions.filter((execution) => execution.status === "blocked");
		const coverageRows = swarm.coverageMatrix.filter((row) => row.includes(`worker=${worker.id}`));
		const missingCoverageRows = coverageRows.filter((row) => /status=missing/i.test(row));
		const auditRows = swarm.executionAudit.filter((row) => row.includes(`worker=${worker.id}`));
		const claimPassed = executions.length > 0 && blocked.length === 0 && missingCoverageRows.length === 0;
		const claimId = `${planId}:worker:${slug(worker.id).slice(0, 48)}`;
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "artifact_handoff",
				claimId,
				workerId: worker.id,
				role: worker.worker,
				scope,
				statement: "worker packet handoff binds commands, dependencies, merge keys, and evidence contract before execution.",
				evidenceRefs: [swarm.delegationArtifact, ...worker.sourceArtifacts, ...runtimeManifestRefs].filter((item): item is string => Boolean(item)),
				artifactHashes: runtimeArtifactHashes([swarm.delegationArtifact, ...worker.sourceArtifacts, ...runtimeManifestRefs]),
				metadata: {
					objective: worker.objective,
					commands: worker.commands,
					dependencies: worker.dependencies,
					mergeKeys: worker.mergeKeys,
					evidenceContract: worker.evidenceContract,
					runtimeManifestFiles: runtimeManifests.map((manifest) => manifest.runtimeManifestFile),
				},
			},
			timestamp,
		);
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "claim",
				claimId,
				workerId: worker.id,
				role: worker.worker,
				scope,
				status: claimPassed ? "proven" : executions.length ? "gap" : "pending",
				statement: claimPassed
					? "worker claim is artifact-backed and coverage-complete for this swarm run."
					: "worker claim is not promotable until runtime execution, coverage, and repair gates close.",
				evidenceRefs: [
					swarm.delegationArtifact,
					...worker.sourceArtifacts,
					...executions.flatMap((execution) => execution.sourceArtifacts),
					...runtimeManifestRefs,
				].filter((item): item is string => Boolean(item)),
				artifactHashes: runtimeArtifactHashes([
					swarm.delegationArtifact,
					...worker.sourceArtifacts,
					...executions.flatMap((execution) => execution.sourceArtifacts),
					...runtimeManifestRefs,
				]),
				metadata: {
					workerStatus: worker.status,
					executions: executions.length,
					runtimeManifests: runtimeManifests.length,
					blocked: blocked.length,
					coverageRows: coverageRows.length,
					missingCoverageRows: missingCoverageRows.length,
				},
			},
			timestamp,
		);
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "validation",
				claimId,
				workerId: worker.id,
				role: "supervisor",
				scope,
				status: claimPassed ? "pass" : "fail",
				statement: "runtime coverage validation checks execution status, blocked rows, and evidence-contract coverage.",
				evidenceRefs: [swarm.delegationArtifact, ...worker.sourceArtifacts, ...runtimeManifestRefs].filter((item): item is string => Boolean(item)),
				metadata: {
					auditRows,
					coverageRows,
					missingCoverageRows,
					runtimeManifestFiles: runtimeManifests.map((manifest) => manifest.runtimeManifestFile),
					blockedCommands: blocked.map((execution) => execution.command),
				},
			},
			timestamp,
		);
		if (!claimPassed) {
			const reason =
				executions.length === 0
					? "pending_execution"
					: blocked.length
						? "blocked_execution"
						: "missing_evidence_contract";
			appendSwarmClaimLedgerEvent(
				events,
				{
					type: "challenge",
					claimId,
					workerId: worker.id,
					role: "adversary",
					scope,
					status: "blocked",
					challenge: `worker claim challenged: ${reason}`,
					evidenceRefs: [swarm.delegationArtifact, ...worker.sourceArtifacts, ...runtimeManifestRefs].filter((item): item is string => Boolean(item)),
					metadata: {
						reason,
						blockedRows: blocked.map((execution) => truncateMiddle(execution.output.replace(/\s+/g, " "), 240)),
						missingCoverageRows,
					},
				},
				timestamp,
			);
			appendSwarmClaimLedgerEvent(
				events,
				{
					type: "resolution",
					claimId,
					workerId: worker.id,
					role: "re_swarm",
					scope,
					status: "queued_repair",
					resolution: "claim remains downgraded; retryQueue and supervisor repair must close before final promotion.",
					evidenceRefs: [swarm.claimLedgerPath, ...swarm.retryQueue].filter((item): item is string => Boolean(item)),
					metadata: {
						retryQueue: swarm.retryQueue.filter((row) => row.includes(`worker=${worker.id}`)),
						next: `re_swarm run ${swarm.target ?? "<target>"} 1 1 && re_supervisor repair ${swarm.target ?? "<target>"}`,
					},
				},
				timestamp,
			);
		}
	}
	for (const collision of swarm.collisionMatrix) {
		const claimId = `${planId}:collision:${createHash("sha256").update(collision).digest("hex").slice(0, 12)}`;
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "challenge",
				claimId,
				workerId: "collision_matrix",
				role: "adversary",
				scope,
				status: "blocked",
				challenge: `merge conflict requires supervisor arbitration: ${collision}`,
				evidenceRefs: [swarm.delegationArtifact, ...swarm.sourceArtifacts].filter((item): item is string => Boolean(item)),
			},
			timestamp,
		);
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "resolution",
				claimId,
				workerId: "collision_matrix",
				role: "supervisor",
				scope,
				status: "queued_repair",
				resolution: "collision is preserved for re_supervisor review; final claim promotion is blocked until conflict is resolved.",
				evidenceRefs: [swarm.claimLedgerPath, "re_supervisor review"].filter((item): item is string => Boolean(item)),
			},
			timestamp,
		);
	}
	if (!events.some((event) => event.type === "challenge")) {
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "challenge",
				claimId: `${planId}:final_promotion_policy`,
				workerId: "re_swarm",
				role: "adversary",
				scope,
				status: "accepted",
				challenge: "no unresolved worker challenge in this swarm artifact; retain final-promotion adversary gate.",
				evidenceRefs: [swarm.claimLedgerPath, swarm.delegationArtifact].filter((item): item is string => Boolean(item)),
			},
			timestamp,
		);
		appendSwarmClaimLedgerEvent(
			events,
			{
				type: "resolution",
				claimId: `${planId}:final_promotion_policy`,
				workerId: "re_swarm",
				role: "supervisor",
				scope,
				status: "accepted",
				resolution: "role claims may only promote after supervisor claimGatePolicy and strict claim marker pass.",
				evidenceRefs: [swarm.claimLedgerPath, "gate:claim-release", "re_supervisor review"].filter((item): item is string => Boolean(item)),
			},
			timestamp,
		);
	}
	return events;
}

function refreshSwarmRuntimeClaimLedger(swarm: SwarmArtifact): SwarmArtifact {
	const claimLedger = buildSwarmRuntimeClaimLedger(swarm);
	const runtimeClaimLedgerCaptured =
		swarmClaimLedgerHashChainOk(claimLedger) &&
		(["artifact_handoff", "claim", "validation", "challenge", "resolution"] as const).every((type) =>
			claimLedger.some((event) => event.type === type),
		);
	return {
		...swarm,
		claimLedger,
		claimLedgerEventCount: claimLedger.length,
		claimLedgerTipHash: claimLedger.at(-1)?.eventHash,
		runtimeClaimLedgerCaptured,
		sourceArtifacts: Array.from(
			new Set([
				...swarm.sourceArtifacts,
				swarm.claimLedgerPath,
				swarm.subagentRuntimeManifestPath,
				...(swarm.subagentRuntimeManifests ?? []).flatMap((manifest) => [
					manifest.runtimeManifestFile,
					manifest.stdoutPath,
					manifest.stderrPath,
				]),
			].filter((item): item is string => Boolean(item))),
		).slice(0, 64),
	};
}

function buildSwarm(options: { target?: string; task?: string; mode?: "plan" | "run" | "merge" } = {}): SwarmArtifact {
	ensureReconStorage();
	const { delegate, path: delegationArtifact } = latestOrBuildDelegate(options);
	const timestamp = new Date().toISOString();
	const workers: SwarmWorkerRuntime[] = delegate.packets.map((packet, index) => {
		const readyCommands = packet.steps
			.filter((step) => step.status === "ready")
			.map((step) => step.command)
			.slice(0, 8);
		const commands = readyCommands.length
			? readyCommands
			: [`re_delegate show # inspect ${packet.id}`, `re_evidence search ${packet.worker}`];
		return {
			id: `swarm:${index + 1}:${packet.worker}`,
			worker: packet.worker,
			status:
				options.mode === "merge" && packet.status === "done"
					? "merged"
					: packet.status === "blocked"
						? "blocked"
						: "ready",
			objective: packet.objective,
			spawnPrompt: swarmSpawnPrompt(packet, delegate.target ?? options.target),
			commands,
			evidenceContract: packet.evidenceContract,
			mergeKeys: swarmMergeKeys(packet),
			dependencies: swarmDependencies(packet),
			recommendedTools: packet.recommendedTools,
			sourceArtifacts: packet.sourceArtifacts,
		};
	});
	const parallelGroups = [
		workers.filter((worker) => /web-authz|agentsec|cloud|identity/.test(worker.worker)).map((worker) => worker.id),
		workers
			.filter((worker) => /mobile-runtime|native-runtime|pwn-exploit|firmware-dfir|malware/.test(worker.worker))
			.map((worker) => worker.id),
		workers.filter((worker) => /reporting|general/.test(worker.worker)).map((worker) => worker.id),
	]
		.filter((group) => group.length > 0)
		.map((group, index) => `group:${index + 1} ${group.join(" ")}`);
	const mergeProtocol = [
		"1. collect each worker's Outcome/Key Evidence/Verification/Next Step packet",
		"2. reject claims without command/path/hash/request/offset/state-transition evidence",
		"3. resolve conflicts by runtime/replay/verifier evidence order",
		"4. write merged evidence to ledger, then re_supervisor review and re_verifier matrix",
		"5. preserve unresolved gaps as re_operator escalation_queue or re_autofix evidence_recapture_queue",
	];
	const collisionMatrix = workers.flatMap((worker, index) =>
		workers.slice(index + 1).flatMap((other) => {
			const overlap = worker.mergeKeys.filter((key) => other.mergeKeys.includes(key));
			return overlap.length ? [`${worker.id} <-> ${other.id}: ${overlap.join(",")}`] : [];
		}),
	);
	const evidenceContract = Array.from(new Set(workers.flatMap((worker) => worker.evidenceContract))).slice(0, 24);
	const commanderNextActions = Array.from(
		new Set([
			...workers.filter((worker) => worker.status === "ready").flatMap((worker) => worker.commands.slice(0, 2)),
			"re_swarm merge",
			"re_supervisor review",
			"re_verifier matrix",
			"re_context pack",
		]),
	).slice(0, 18);
	const handoffDigest = workers.map(
		(worker) =>
			`${worker.id} status=${worker.status} deps=${worker.dependencies.join(",")} tools=${worker.recommendedTools.slice(0, 5).join(",")}`,
	);
	const parallelPlan = buildSwarmParallelPlan({
		delegate,
		delegationArtifact,
		workers,
		timestamp,
		target: options.target,
		mode: options.mode ?? "plan",
	});
	const basePlanCoverage = swarmPlanCoverage({ workers, parallelPlan, coverageMatrix: [], collisionMatrix: collisionMatrix.slice(0, 24) });
	const releaseGateMetadata = swarmReleaseGateMetadata(parallelPlan);
	const swarm: SwarmArtifact = {
		timestamp,
		missionId: delegate.missionId,
		route: delegate.route,
		target: delegate.target ?? options.target,
		mode: options.mode ?? "plan",
		delegationArtifact,
		workers,
		executions: [],
		workerResults: [],
		blocked: [],
		mergeDigest: [],
		executionAudit: [],
		coverageMatrix: [],
		retryQueue: [],
		parallelGroups,
		mergeProtocol,
		collisionMatrix: collisionMatrix.slice(0, 24),
		evidenceContract,
		commanderNextActions,
		handoffDigest,
		parallelPlan,
		planCoverage: basePlanCoverage,
		releaseGateMetadata,
		claimLedger: [],
		claimLedgerEventCount: 0,
		runtimeClaimLedgerCaptured: false,
		subagentRuntimeManifests: [],
		subagentRuntimeManifestCount: 0,
		subagentRuntimeManifestsCaptured: false,
		sourceArtifacts: Array.from(
			new Set([
				delegationArtifact,
				...delegate.sourceArtifacts,
				...workers.flatMap((worker) => worker.sourceArtifacts),
			]),
		).slice(0, 40),
	};
	const auditFields = deriveSwarmAuditFields(swarm);
	const swarmWithAudit = { ...swarm, ...auditFields };
	return refreshSwarmRuntimeClaimLedger({
		...swarmWithAudit,
		planCoverage: swarmPlanCoverage(swarmWithAudit),
		releaseGateMetadata: swarmReleaseGateMetadata(swarmWithAudit.parallelPlan),
	});
}

function sanitizeSwarmCommand(command: string): string {
	return command.trim().replace(/\s+#.*$/g, "");
}

function swarmExecutionDigest(value: string): string {
	return createHash("sha256").update(value).digest("hex");
}

function stripSwarmPidMarker(stderr: string): {
	stderr: string;
	pid: number | null;
	parentPid: number | null;
} {
	const match = /^__pi_recon_swarm_pid=(\d+)\s+ppid=(\d+)\s*\n?/m.exec(stderr);
	if (!match) return { stderr, pid: null, parentPid: null };
	return {
		stderr: stderr.replace(match[0], ""),
		pid: Number(match[1]),
		parentPid: Number(match[2]),
	};
}

async function executeSwarmWorkerCommand(
	pi: ExtensionAPI,
	worker: SwarmWorkerRuntime,
	rawCommand: string,
	target?: string,
): Promise<SwarmWorkerExecution> {
	const command = sanitizeSwarmCommand(rawCommand);
	const startedMs = Date.now();
	const startedAt = new Date(startedMs).toISOString();
	const finalize = (execution: Omit<SwarmWorkerExecution, "startedAt" | "endedAt" | "elapsedMs">): SwarmWorkerExecution => {
		const endedMs = Date.now();
		const stdout = execution.stdout ?? execution.output;
		const stderr = execution.stderr ?? "";
		return {
			...execution,
			stdout,
			stderr,
			stdoutSha256: execution.stdoutSha256 ?? swarmExecutionDigest(stdout),
			stderrSha256: execution.stderrSha256 ?? swarmExecutionDigest(stderr),
			startedAt,
			endedAt: new Date(endedMs).toISOString(),
			elapsedMs: Math.max(0, endedMs - startedMs),
			exitCode: execution.exitCode ?? (execution.status === "done" ? 0 : 1),
			signal: execution.signal ?? null,
		};
	};
	const blocked = (output: string): SwarmWorkerExecution =>
		finalize({
			workerId: worker.id,
			worker: worker.worker,
			command: command || rawCommand,
			status: "blocked",
			output,
			stdout: output,
			stderr: "",
			pid: process.pid,
			parentPid: process.ppid,
			exitCode: 1,
			signal: null,
			sourceArtifacts: worker.sourceArtifacts,
		});
	if (!command) return blocked("empty swarm worker command");
	if (/^re[-_]swarm\s+run\b/i.test(command)) return blocked("recursive swarm run command is not allowed");
	if (/^re[-_]/i.test(command)) {
		const result = await executeOperatorStep(
			pi,
			{
				id: `${worker.id}:${slug(command).slice(0, 24)}`,
				command,
				status: "ready",
				priority: 1,
				sourceArtifacts: worker.sourceArtifacts,
			},
			target,
		);
		return finalize({
			workerId: worker.id,
			worker: worker.worker,
			command: result.command,
			status: result.status,
			output: result.output,
			stdout: result.output,
			stderr: "",
			pid: process.pid,
			parentPid: process.ppid,
			exitCode: result.status === "done" ? 0 : 1,
			signal: null,
			sourceArtifacts: worker.sourceArtifacts,
		});
	}
	const result = await pi.exec(
		"bash",
		["-lc", `printf '__pi_recon_swarm_pid=%s ppid=%s\\n' "$$" "$PPID" >&2\nset -o pipefail\n${command}`],
		{ timeout: 60000 },
	);
	const marker = stripSwarmPidMarker(result.stderr);
	const stdout = result.stdout;
	const stderr = marker.stderr;
	const output = [
		`exit=${result.code}${result.killed ? " killed=true" : ""}`,
		`pid=${marker.pid ?? "unknown"} parent_pid=${marker.parentPid ?? "unknown"}`,
		`stdout_sha256=${swarmExecutionDigest(stdout)}`,
		`stderr_sha256=${swarmExecutionDigest(stderr)}`,
		`stdout=${truncateMiddle(stdout.trim(), 1200)}`,
		`stderr=${truncateMiddle(stderr.trim(), 1200)}`,
	].join("\n");
	return finalize({
		workerId: worker.id,
		worker: worker.worker,
		command,
		status: result.code === 0 && !result.killed ? "done" : "blocked",
		output,
		stdout,
		stderr,
		stdoutSha256: swarmExecutionDigest(stdout),
		stderrSha256: swarmExecutionDigest(stderr),
		pid: marker.pid,
		parentPid: marker.parentPid,
		exitCode: result.code,
		signal: result.killed ? "SIGTERM" : null,
		sourceArtifacts: worker.sourceArtifacts,
	});
}

function swarmWorkerGroups(swarm: SwarmArtifact, selected: Set<string>): SwarmWorkerRuntime[][] {
	const byId = new Map(swarm.workers.map((worker) => [worker.id, worker]));
	const used = new Set<string>();
	const groups = swarm.parallelGroups
		.map((group) =>
			group
				.replace(/^group:\d+\s+/i, "")
				.split(/\s+/)
				.map((id) => byId.get(id))
				.filter((worker): worker is SwarmWorkerRuntime => Boolean(worker && selected.has(worker.id))),
		)
		.filter((group) => group.length > 0)
		.map((group) => {
			for (const worker of group) used.add(worker.id);
			return group;
		});
	const leftovers = swarm.workers.filter((worker) => selected.has(worker.id) && !used.has(worker.id));
	return leftovers.length ? [...groups, leftovers] : groups;
}

function swarmContractCovered(text: string, contract: string): boolean {
	const haystack = text.toLowerCase();
	if (!contract.trim()) return true;
	if (haystack.includes(contract.toLowerCase())) return true;
	const tokens = contract.toLowerCase().match(/[a-z0-9_./:-]{4,}/g);
	if (!tokens?.length) return false;
	return tokens.some((token) => haystack.includes(token));
}

function swarmWorkerEvidenceText(swarm: SwarmArtifact, worker: SwarmWorkerRuntime): string {
	const manifestRows = (swarm.subagentRuntimeManifests ?? []).filter((manifest) => manifest.workerId === worker.id);
	return [
		worker.worker,
		worker.objective,
		...worker.commands,
		...worker.mergeKeys,
		...swarm.executions
			.filter((execution) => execution.workerId === worker.id)
			.flatMap((execution) => [execution.command, execution.output]),
		...swarm.workerResults.filter(
			(result) => result.includes(worker.id) || result.includes(`worker=${worker.worker}`),
		),
		...swarm.mergeDigest.filter((item) => item.includes(worker.id) || item.includes(`worker=${worker.worker}`)),
		...manifestRows.flatMap((manifest) => [
			manifest.runtimeManifestFile,
			manifest.sessionDir,
			manifest.stdoutPath,
			manifest.stderrPath,
			manifest.stdoutSha256,
			manifest.stderrSha256,
			manifest.toolCallDigest,
		]),
	].join("\n");
}

function deriveSwarmAuditFields(
	swarm: SwarmArtifact,
): Pick<SwarmArtifact, "executionAudit" | "coverageMatrix" | "retryQueue"> {
	const executionAudit: string[] = [];
	const coverageMatrix: string[] = [];
	const retryQueue: string[] = [];
	const target = swarm.target ?? "<target>";
	for (const worker of swarm.workers) {
		const executions = swarm.executions.filter((execution) => execution.workerId === worker.id);
		const done = executions.filter((execution) => execution.status === "done").length;
		const blocked = executions.filter((execution) => execution.status === "blocked").length;
		const text = swarmWorkerEvidenceText(swarm, worker);
		const hashes = new Set(text.match(/\b(?:stdout_sha256|stderr_sha256|sha256|hash)=[0-9a-f]{8,64}\b/gi) ?? []);
		const artifacts = new Set(
			text.match(/(?:^|\s)(?:\.\/|\.\.\/|\/tmp\/|\/root\/|\/home\/|[A-Za-z0-9_.-]+\/)[^\s`'"]{3,}/g) ?? [],
		);
		const anchors = new Set(
			text.match(/\[[A-Za-z0-9_.:/-]+\]|anchors?:|artifact=|status=|route=|offset=|RIP|EIP/gi) ?? [],
		);
		const coveredContracts = worker.evidenceContract.filter((contract) => swarmContractCovered(text, contract));
		const missingContracts = worker.evidenceContract.filter((contract) => !swarmContractCovered(text, contract));
		const auditStatus =
			blocked > 0
				? "needs_repair"
				: executions.length === 0
					? "pending_execution"
					: missingContracts.length
						? "needs_evidence"
						: "covered";
		executionAudit.push(
			[
				`worker=${worker.id}`,
				`role=${worker.worker}`,
				`status=${auditStatus}`,
				`commands=${executions.length}/${worker.commands.length}`,
				`passed=${done}`,
				`blocked=${blocked}`,
				`contract=${coveredContracts.length}/${worker.evidenceContract.length}`,
				`hashes=${hashes.size}`,
				`artifacts=${artifacts.size}`,
				`anchors=${anchors.size}`,
			].join(" "),
		);
		for (const contract of worker.evidenceContract) {
			const covered = swarmContractCovered(text, contract);
			coverageMatrix.push(
				`worker=${worker.id} role=${worker.worker} contract=${shellQuote(contract)} status=${covered ? "covered" : "missing"}`,
			);
		}
		if (executions.length === 0 && worker.status === "ready") {
			retryQueue.push(`worker=${worker.id} reason=no_execution next=re_swarm run ${target} 1 1`);
		}
		for (const execution of executions.filter((item) => item.status === "blocked")) {
			retryQueue.push(
				`worker=${worker.id} reason=blocked command=${shellQuote(execution.command)} next=re_swarm run ${target} 1 1`,
			);
		}
		if (executions.length > 0 && missingContracts.length > 0) {
			retryQueue.push(
				`worker=${worker.id} reason=contract_gap missing=${missingContracts
					.slice(0, 3)
					.map((item) => shellQuote(item))
					.join(",")} next=re_delegate plan ${target} && re_swarm run ${target} 1 1`,
			);
		}
	}
	return {
		executionAudit: executionAudit.slice(0, 48),
		coverageMatrix: coverageMatrix.slice(0, 96),
		retryQueue: Array.from(new Set(retryQueue)).slice(0, 32),
	};
}

function refreshSwarmRunDerivedFields(swarm: SwarmArtifact): SwarmArtifact {
	const executionsByWorker = new Map<string, SwarmWorkerExecution[]>();
	for (const execution of swarm.executions)
		executionsByWorker.set(execution.workerId, [...(executionsByWorker.get(execution.workerId) ?? []), execution]);
	const workers = swarm.workers.map((worker) => {
		const executions = executionsByWorker.get(worker.id) ?? [];
		if (executions.length === 0) return worker;
		const status: SwarmWorkerRuntime["status"] = executions.some((execution) => execution.status === "blocked")
			? "blocked"
			: "done";
		return {
			...worker,
			status,
		};
	});
	const blocked = swarm.executions
		.filter((execution) => execution.status === "blocked")
		.map((execution) => `${execution.workerId} ${execution.command} — ${truncateMiddle(execution.output, 220)}`);
	const workerResults = workers.map((worker) => {
		const executions = executionsByWorker.get(worker.id) ?? [];
		const last = executions.at(-1);
		return `${worker.id} worker=${worker.worker} status=${worker.status} executed=${executions.length} evidence=${worker.evidenceContract.join(" | ")} last=${last ? truncateMiddle(last.output.replace(/\s+/g, " "), 220) : "none"}`;
	});
	const mergeDigest = Array.from(
		new Set([
			`mode=${swarm.mode} workers=${workers.length} executed=${swarm.executions.length} blocked=${blocked.length}`,
			...workerResults,
			...blocked.map((item) => `repair: ${item}`),
			...swarm.collisionMatrix.map((item) => `collision: ${item}`),
		]),
	).slice(0, 32);
	const auditFields = deriveSwarmAuditFields({
		...swarm,
		workers,
		blocked,
		workerResults,
		mergeDigest,
		executionAudit: [],
		coverageMatrix: [],
		retryQueue: [],
	});
	const target = swarm.target ?? "<target>";
	const refreshedForPlan = {
		...swarm,
		workers,
		blocked,
		workerResults,
		mergeDigest,
		executionAudit: auditFields.executionAudit,
		coverageMatrix: auditFields.coverageMatrix,
		retryQueue: auditFields.retryQueue,
	};
	const planCoverage = swarmPlanCoverage(refreshedForPlan);
	const releaseGateMetadata = swarmReleaseGateMetadata(swarm.parallelPlan);
	const commanderNextActions = Array.from(
		new Set([
			...auditFields.retryQueue
				.flatMap((item) => item.match(/next=([^&;]+)/i)?.[1]?.trim() ?? [])
				.filter((item) => /^re[-_]/i.test(item)),
			...(blocked.length ? [`re_supervisor repair ${target}`, "re_autofix plan", "re_operator escalate"] : []),
			"re_swarm merge",
			"re_supervisor review",
			"re_verifier matrix",
			`re_proof_loop run ${target} 4 2`,
			"re_context pack",
		]),
	).slice(0, 18);
	return refreshSwarmRuntimeClaimLedger({
		...swarm,
		workers,
		blocked,
		workerResults,
		mergeDigest,
		...auditFields,
		planCoverage,
		releaseGateMetadata,
			commanderNextActions,
			sourceArtifacts: Array.from(
				new Set([
					...swarm.sourceArtifacts,
					...swarm.executions.flatMap((execution) => execution.sourceArtifacts),
				...(swarm.subagentRuntimeManifests ?? []).flatMap((manifest) => [
					manifest.runtimeManifestFile,
					manifest.stdoutPath,
					manifest.stderrPath,
				]),
					swarm.subagentRuntimeManifestPath,
				].filter((item): item is string => Boolean(item))),
			).slice(0, 64),
		});
}

function swarmRuntimeStatus(executions: SwarmWorkerExecution[]): SwarmRuntimeState {
	if (executions.length === 0) return "queued";
	if (executions.some((execution) => execution.status === "blocked")) return "blocked";
	if (executions.some((execution) => execution.status === "skipped")) return "cancelled";
	return "done";
}

function swarmRuntimeTimeWindow(
	executions: SwarmWorkerExecution[],
	fallback = new Date().toISOString(),
): { startedAt: string; endedAt: string; elapsedMs: number } {
	const startedAt = executions.map((execution) => execution.startedAt).filter((item): item is string => Boolean(item)).sort()[0] ?? fallback;
	const endedAt =
		executions
			.map((execution) => execution.endedAt)
			.filter((item): item is string => Boolean(item))
			.sort()
			.at(-1) ?? startedAt;
	const parsedStarted = Date.parse(startedAt);
	const parsedEnded = Date.parse(endedAt);
	const elapsedMs =
		Number.isFinite(parsedStarted) && Number.isFinite(parsedEnded)
			? Math.max(0, parsedEnded - parsedStarted)
			: executions.reduce((sum, execution) => sum + Math.max(0, execution.elapsedMs ?? 0), 0);
	return { startedAt, endedAt, elapsedMs };
}

function swarmRuntimeModel(executions: SwarmWorkerExecution[]): SwarmRuntimeModelSummary {
	return {
		provider: "re_swarm",
		modelId: "command-level-worker",
		modelCalls: 0,
		toolCalls: executions.length,
		toolResults: executions.length,
	};
}

function swarmRuntimeRetryBudget(worker: SwarmWorkerRuntime, attempt: number): SwarmRuntimeRetryBudget {
	return {
		signature: `re_swarm:${slug(worker.id)}:${createHash("sha256").update(worker.commands.join("\n")).digest("hex").slice(0, 16)}`,
		attempt,
		maxAttempts: 3,
		remaining: Math.max(0, 3 - attempt),
		exhausted: attempt >= 3,
	};
}

function writeSwarmSubagentRuntimeManifest(params: {
	swarm: SwarmArtifact;
	worker: SwarmWorkerRuntime;
	executions: SwarmWorkerExecution[];
	attempt: number;
	maxCommands: number;
}): SwarmSubagentRuntimeManifestRow {
	const { swarm, worker, executions, attempt, maxCommands } = params;
	const sessionDir = join(swarmSubagentSessionRoot(swarm), slug(worker.id));
	mkdirSync(sessionDir, { recursive: true });
	const stdoutPath = join(sessionDir, "stdout.txt");
	const stderrPath = join(sessionDir, "stderr.txt");
	const runtimeManifestFile = join(sessionDir, "runtime-manifest.json");
	const stdout = executions.length
		? executions
				.map((execution, index) =>
					[`## command ${index + 1}: ${execution.command}`, execution.stdout ?? execution.output ?? ""].join("\n"),
				)
				.join("\n\n")
		: `worker=${worker.id} status=queued no command selected for this bounded re_swarm run\n`;
	const stderr = executions.length
		? executions
				.map((execution, index) => [`## command ${index + 1}: ${execution.command}`, execution.stderr ?? ""].join("\n"))
				.join("\n\n")
		: "";
	writeFileSync(stdoutPath, stdout, "utf-8");
	writeFileSync(stderrPath, stderr, "utf-8");
	const stdoutSha256 = swarmExecutionDigest(stdout);
	const stderrSha256 = swarmExecutionDigest(stderr);
	const status = swarmRuntimeStatus(executions);
	const timing = swarmRuntimeTimeWindow(executions, swarm.timestamp);
	const pid = executions.find((execution) => Number.isInteger(execution.pid))?.pid ?? process.pid;
	const parentPid = executions.find((execution) => Number.isInteger(execution.parentPid))?.parentPid ?? process.ppid;
	const exitCode =
		status === "queued"
			? null
			: status === "done"
				? 0
				: executions.find((execution) => execution.status === "blocked")?.exitCode ?? 1;
	const signal = executions.find((execution) => execution.signal)?.signal ?? null;
	const model = swarmRuntimeModel(executions);
	const evidenceRefs = Array.from(
		new Set([
			swarm.delegationArtifact,
			...worker.sourceArtifacts,
			...executions.flatMap((execution) => execution.sourceArtifacts),
			stdoutPath,
			stderrPath,
		].filter((item): item is string => Boolean(item))),
	).slice(0, 32);
	const toolCallDigest = createHash("sha256")
		.update(
			JSON.stringify({
				workerId: worker.id,
				attempt,
				commands: executions.map((execution) => execution.command),
				statuses: executions.map((execution) => execution.status),
				stdoutSha256,
				stderrSha256,
				model,
			}),
		)
		.digest("hex");
	const manifest: SwarmSubagentRuntimeManifestV1 = {
		kind: "SubagentRuntimeManifestV1",
		schemaVersion: 1,
		runId: swarm.parallelPlan?.planId ?? `re_swarm/${swarm.timestamp}`,
		roleId: worker.worker,
		workerId: worker.id,
		attempt,
		status,
		pid,
		parentPid,
		sessionDir,
		stdoutPath,
		stderrPath,
		stdoutSha256,
		stderrSha256,
		startedAt: timing.startedAt,
		endedAt: timing.endedAt,
		elapsedMs: timing.elapsedMs,
		exitCode,
		signal,
		model,
		toolCallDigest,
		claimLedgerPath: swarm.claimLedgerPath ?? swarmClaimLedgerPath(swarm),
		failureLedgerPath: runtimeFailureLedgerPath(),
		repairQueuePath: runtimeRepairQueuePath(),
		resourceLimits: {
			timeoutMs: 60000,
			maxCommands,
			maxOutputBytes: Buffer.byteLength(stdout) + Buffer.byteLength(stderr),
			cancelOnTimeout: true,
		},
		retryBudget: swarmRuntimeRetryBudget(worker, attempt),
		mergeKeys: worker.mergeKeys,
		evidenceRefs,
	};
	writeFileSync(runtimeManifestFile, `${JSON.stringify(manifest, null, 2)}\n`, "utf-8");
	return {
		...manifest,
		runtimeManifestFile,
	};
}

function refreshSwarmSubagentRuntimeManifestCapture(swarm: SwarmArtifact): SwarmArtifact {
	const manifests = swarm.subagentRuntimeManifests ?? [];
	const subagentRuntimeManifestCount = manifests.length;
	const expectedWorkers = swarm.workers.length;
	const subagentRuntimeManifestsCaptured =
		expectedWorkers > 0 &&
		subagentRuntimeManifestCount >= expectedWorkers &&
		manifests.every(
			(manifest) =>
				manifest.kind === "SubagentRuntimeManifestV1" &&
				manifest.schemaVersion === 1 &&
				Boolean(manifest.runtimeManifestFile && existsSync(manifest.runtimeManifestFile)) &&
				Boolean(manifest.sessionDir && existsSync(manifest.sessionDir)) &&
				Boolean(manifest.stdoutPath && existsSync(manifest.stdoutPath)) &&
				Boolean(manifest.stderrPath && existsSync(manifest.stderrPath)) &&
				Boolean(manifest.stdoutSha256 && manifest.stderrSha256 && manifest.toolCallDigest) &&
				Number.isInteger(manifest.pid) &&
				Number.isInteger(manifest.parentPid) &&
				Boolean(manifest.model?.provider && manifest.model?.modelId),
		);
	return {
		...swarm,
		subagentRuntimeManifests: manifests,
		subagentRuntimeManifestCount,
		subagentRuntimeManifestsCaptured,
		sourceArtifacts: Array.from(
			new Set([
				...swarm.sourceArtifacts,
				swarm.subagentRuntimeManifestPath,
				...manifests.flatMap((manifest) => [
					manifest.runtimeManifestFile,
					manifest.stdoutPath,
					manifest.stderrPath,
				]),
			].filter((item): item is string => Boolean(item))),
		).slice(0, 64),
	};
}

async function runSwarm(
	pi: ExtensionAPI,
	options: { target?: string; task?: string; maxWorkers?: number; maxCommands?: number } = {},
): Promise<string> {
	let swarm = buildSwarm({ target: options.target, task: options.task, mode: "run" });
	swarm.claimLedgerPath = swarmClaimLedgerPath(swarm);
	swarm.subagentRuntimeManifestPath = swarmSubagentRuntimeManifestIndexPath(swarm);
	const maxWorkers = Math.max(1, Math.min(8, Math.floor(options.maxWorkers ?? 3)));
	const maxCommands = Math.max(1, Math.min(5, Math.floor(options.maxCommands ?? 1)));
	const selected = new Set(
		swarm.workers
			.filter((worker) => worker.status === "ready")
			.slice(0, maxWorkers)
			.map((worker) => worker.id),
	);
	for (const group of swarmWorkerGroups(swarm, selected)) {
		const groupRuns = await Promise.all(
			group.map(async (worker) => {
				const executions: SwarmWorkerExecution[] = [];
				for (const command of worker.commands.slice(0, maxCommands))
					executions.push(await executeSwarmWorkerCommand(pi, worker, command, swarm.target));
				const manifest = writeSwarmSubagentRuntimeManifest({
					swarm,
					worker,
					executions,
					attempt: 1,
					maxCommands,
				});
				return { executions, manifest };
			}),
		);
		swarm.executions.push(...groupRuns.flatMap((run) => run.executions));
		swarm.subagentRuntimeManifests.push(...groupRuns.map((run) => run.manifest));
		swarm = refreshSwarmSubagentRuntimeManifestCapture(swarm);
		swarm = refreshSwarmRunDerivedFields(swarm);
	}
	const manifestedWorkers = new Set(swarm.subagentRuntimeManifests.map((manifest) => manifest.workerId));
	const queuedManifests = swarm.workers
		.filter((worker) => !manifestedWorkers.has(worker.id))
		.map((worker) =>
			writeSwarmSubagentRuntimeManifest({
				swarm,
				worker,
				executions: [],
				attempt: 1,
				maxCommands,
			}),
		);
	if (queuedManifests.length) {
		swarm.subagentRuntimeManifests.push(...queuedManifests);
		swarm = refreshSwarmSubagentRuntimeManifestCapture(swarm);
	}
	swarm = refreshSwarmRunDerivedFields(swarm);
	const path = writeSwarmArtifact(swarm);
	return formatSwarm(swarm, path);
}

function formatSwarm(swarm: SwarmArtifact, path?: string): string {
	return [
		"swarm_plan:",
		path ? `swarm_artifact: ${path}` : undefined,
		`timestamp: ${swarm.timestamp}`,
		`mode: ${swarm.mode}`,
		`mission_id: ${swarm.missionId ?? "none"}`,
		`route: ${swarm.route ?? "none"}`,
		`target: ${swarm.target ?? "<none>"}`,
		`delegation_artifact: ${swarm.delegationArtifact ?? "none"}`,
		"worker_runtime_packets:",
		...(swarm.workers.length
			? swarm.workers.flatMap((worker) => [
					`- ${worker.id} [${worker.status}] worker=${worker.worker}`,
					`  objective: ${worker.objective}`,
					`  dependencies: ${worker.dependencies.join(", ") || "none"}`,
					`  merge_keys: ${worker.mergeKeys.join(" | ")}`,
					`  evidence_contract: ${worker.evidenceContract.join(" | ")}`,
					`  spawn_prompt: ${worker.spawnPrompt.join(" ; ")}`,
					`  commands: ${worker.commands.join(" || ")}`,
				])
			: ["- none"]),
		`worker_executions: ${swarm.executions.length}`,
		...(swarm.executions.length
			? swarm.executions.map(
					(execution) =>
						`- ${execution.workerId} [${execution.status}] worker=${execution.worker} command=${execution.command} :: ${truncateMiddle(execution.output.replace(/\s+/g, " "), 260)}`,
				)
			: []),
		"worker_results:",
		...(swarm.workerResults.length ? swarm.workerResults.map((item) => `- ${item}`) : ["- none"]),
		"blocked:",
		...(swarm.blocked.length ? swarm.blocked.map((item) => `- ${item}`) : ["- none"]),
		"merge_digest:",
		...(swarm.mergeDigest.length ? swarm.mergeDigest.map((item) => `- ${item}`) : ["- none"]),
		"execution_audit:",
		...(swarm.executionAudit.length ? swarm.executionAudit.map((item) => `- ${item}`) : ["- none"]),
		"coverage_matrix:",
		...(swarm.coverageMatrix.length ? swarm.coverageMatrix.map((item) => `- ${item}`) : ["- none"]),
		"retry_queue:",
		...(swarm.retryQueue.length ? swarm.retryQueue.map((item) => `- ${item}`) : ["- none"]),
		"parallel_groups:",
		...(swarm.parallelGroups.length ? swarm.parallelGroups.map((item) => `- ${item}`) : ["- none"]),
		"merge_protocol:",
		...(swarm.mergeProtocol.length ? swarm.mergeProtocol.map((item) => `- ${item}`) : ["- none"]),
		"collision_matrix:",
		...(swarm.collisionMatrix.length ? swarm.collisionMatrix.map((item) => `- ${item}`) : ["- none"]),
		"evidence_contract:",
		...(swarm.evidenceContract.length ? swarm.evidenceContract.map((item) => `- ${item}`) : ["- none"]),
		"commander_next_actions:",
		...(swarm.commanderNextActions.length
			? swarm.commanderNextActions.map((item) => `- ${item}`)
			: ["- re_supervisor review"]),
		"handoff_digest:",
		...(swarm.handoffDigest.length ? swarm.handoffDigest.map((item) => `- ${item}`) : ["- none"]),
		"parallel_plan:",
		...(swarm.parallelPlan
			? [
					`- plan_id=${swarm.parallelPlan.planId}`,
					`- source=${swarm.parallelPlan.source}`,
					`- workers=${swarm.parallelPlan.workers.length}`,
					`- merge=${swarm.parallelPlan.merge.strategy}`,
				]
			: ["- none"]),
		"plan_coverage:",
		...(swarm.planCoverage.length ? swarm.planCoverage.map((item) => `- ${item}`) : ["- none"]),
		"release_gate_metadata:",
		...(swarm.releaseGateMetadata.length ? swarm.releaseGateMetadata.map((item) => `- ${item}`) : ["- none"]),
		"runtime_claim_ledger:",
		`- path=${swarm.claimLedgerPath ?? "pending"}`,
		`- events=${swarm.claimLedgerEventCount}`,
		`- tip_hash=${swarm.claimLedgerTipHash ?? "none"}`,
		`- hash_chain=${swarm.runtimeClaimLedgerCaptured ? "pass" : "fail"}`,
		...(swarm.claimLedger.length
			? swarm.claimLedger
					.slice(0, 10)
					.map(
						(event) =>
							`- seq=${event.seq} type=${event.type} claim=${event.claimId ?? "none"} status=${event.status ?? "n/a"} hash=${event.eventHash.slice(0, 16)}`,
					)
			: ["- none"]),
		"subagent_runtime_manifests:",
		`- path=${swarm.subagentRuntimeManifestPath ?? "pending"}`,
		`- count=${swarm.subagentRuntimeManifestCount ?? 0}`,
		`- captured=${swarm.subagentRuntimeManifestsCaptured ? "pass" : "fail"}`,
		...((swarm.subagentRuntimeManifests ?? []).length
			? (swarm.subagentRuntimeManifests ?? [])
					.slice(0, 12)
					.map(
						(manifest) =>
							`- worker=${manifest.workerId} role=${manifest.roleId} status=${manifest.status} pid=${manifest.pid ?? "null"} sessionDir=${manifest.sessionDir} runtimeManifestFile=${manifest.runtimeManifestFile} stdoutSha256=${manifest.stdoutSha256.slice(0, 16)} stderrSha256=${manifest.stderrSha256.slice(0, 16)} toolCallDigest=${manifest.toolCallDigest.slice(0, 16)}`,
					)
			: ["- none"]),
		`next_swarm_command: ${
			swarm.mode === "merge"
				? "re_supervisor review"
				: swarm.mode === "run"
					? "re_swarm merge"
					: `re_swarm run ${swarm.target ?? "<target>"} 3 1`
		}`,
		"source_artifacts:",
		...(swarm.sourceArtifacts.length ? swarm.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeSwarmArtifact(swarm: SwarmArtifact): string {
	ensureReconStorage();
	const path = swarmArtifactPath(swarm);
	swarm.claimLedgerPath = swarmClaimLedgerPath(swarm);
	swarm.subagentRuntimeManifestPath = swarmSubagentRuntimeManifestIndexPath(swarm);
	Object.assign(swarm, refreshSwarmSubagentRuntimeManifestCapture(swarm));
	Object.assign(swarm, refreshSwarmRuntimeClaimLedger(swarm));
	writeFileSync(
		swarm.claimLedgerPath,
		`${swarm.claimLedger.map((event) => JSON.stringify(event)).join("\n")}${swarm.claimLedger.length ? "\n" : ""}`,
		"utf-8",
	);
	writeFileSync(
		swarm.subagentRuntimeManifestPath,
		`${JSON.stringify(
			{
				kind: "pi-recon-swarm-subagent-runtime-manifest-index",
				schemaVersion: 1,
				planId: swarm.parallelPlan?.planId ?? "missing",
				swarmArtifact: path,
				manifestCount: swarm.subagentRuntimeManifestCount,
				captured: swarm.subagentRuntimeManifestsCaptured,
				manifests: swarm.subagentRuntimeManifests,
			},
			null,
			2,
		)}\n`,
		"utf-8",
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Swarm Artifact",
			"",
			formatSwarm(swarm, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(swarm, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	if (swarm.mode === "run") {
		writeFileSync(
			memoryPath("swarm-run-board.md"),
			[
				"# Pi-RECON Swarm Run Board",
				"",
				`Updated: ${swarm.timestamp}`,
				`Artifact: ${path}`,
				"",
				"## Worker results",
				...(swarm.workerResults.length ? swarm.workerResults.map((item) => `- ${item}`) : ["- none"]),
				"",
				"## Merge digest",
				...(swarm.mergeDigest.length ? swarm.mergeDigest.map((item) => `- ${item}`) : ["- none"]),
				"",
				"## Execution audit",
				...(swarm.executionAudit.length ? swarm.executionAudit.map((item) => `- ${item}`) : ["- none"]),
				"",
				"## Retry queue",
				...(swarm.retryQueue.length ? swarm.retryQueue.map((item) => `- ${item}`) : ["- none"]),
				"",
			].join("\n"),
			"utf-8",
		);
	}
	if (swarm.mode === "merge") {
		writeFileSync(
			memoryPath("swarm-board.md"),
			[
				"# Pi-RECON Swarm Board",
				"",
				`Updated: ${swarm.timestamp}`,
				`Artifact: ${path}`,
				"",
				"## Handoff digest",
				...swarm.handoffDigest.map((item) => `- ${item}`),
				"",
				"## Merge protocol",
				...swarm.mergeProtocol.map((item) => `- ${item}`),
				"",
				"## Coverage matrix",
				...(swarm.coverageMatrix.length ? swarm.coverageMatrix.map((item) => `- ${item}`) : ["- none"]),
				"",
			].join("\n"),
			"utf-8",
		);
	}
	appendEvidence({
		kind: swarm.mode === "run" ? "runtime" : "artifact",
		title: `swarm-${swarm.mode} ${swarm.missionId ?? "no-mission"}`,
		fact: `Built swarm ${swarm.mode} with ${swarm.workers.length} worker runtime packet(s), ${swarm.executions.length} execution(s), ${swarm.parallelGroups.length} parallel group(s), ${swarm.collisionMatrix.length} collision(s), ${swarm.blocked.length} blocked, audit=${swarm.executionAudit.length}, retries=${swarm.retryQueue.length}, parallel_plan=${swarm.parallelPlan?.planId ?? "missing"}, plan_coverage=${swarm.planCoverage.length}, release_gate_metadata=${swarm.releaseGateMetadata.length}, subagent_runtime_manifests=${swarm.subagentRuntimeManifestCount} captured=${swarm.subagentRuntimeManifestsCaptured ? "pass" : "fail"}, runtime_claim_ledger=${swarm.claimLedgerEventCount} hash_chain=${swarm.runtimeClaimLedgerCaptured ? "pass" : "fail"}`,
		command: `re_swarm ${swarm.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "multi-specialist swarm orchestration",
	});
	updateMissionGate("swarm_plan_ready", "done", path);
	return path;
}

function buildSwarmOutput(
	action: "plan" | "show" | "merge" = "plan",
	options: { target?: string; task?: string } = {},
): string {
	if (action === "show") {
		const path = latestSwarmArtifactPath();
		if (!path) return "swarm_plan:\nstatus: missing\nnext: re_swarm plan";
		return truncateMiddle(readText(path), 18000);
	}
	let swarm =
		action === "merge"
			? (() => {
					const latest = latestSwarmArtifactPath();
					const parsed = latest ? parseSwarmArtifact(latest) : undefined;
					return parsed
						? refreshSwarmRunDerivedFields({
								...parsed,
								timestamp: new Date().toISOString(),
								mode: "merge",
							})
						: undefined;
				})()
			: undefined;
	swarm ??= buildSwarm({ ...options, mode: action === "merge" ? "merge" : "plan" });
	const path = writeSwarmArtifact(swarm);
	return formatSwarm(swarm, path);
}

function latestSupervisorArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceSupervisorsDir(), 1)[0];
}

function parseDelegateArtifact(path: string): DelegateArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as DelegateArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildDelegate(options: { target?: string; task?: string } = {}): {
	delegate: DelegateArtifact;
	path: string;
} {
	const latest = !options.target && !options.task ? latestDelegateArtifactPath() : undefined;
	if (latest) {
		const delegate = parseDelegateArtifact(latest);
		if (delegate) return { delegate, path: latest };
	}
	const delegate = buildDelegate({ target: options.target, task: options.task, mode: "plan" });
	const path = writeDelegateArtifact(delegate);
	return { delegate, path };
}

function evidenceHitForPacket(packet: DelegatePacket, ledger: string): boolean {
	const haystack = ledger.toLowerCase();
	const needles = [packet.worker, ...packet.phases, ...packet.evidenceContract]
		.map((item) => item.toLowerCase())
		.filter((item) => item.length > 3);
	return needles.some((needle) => haystack.includes(needle));
}

function reviewDelegatePacket(packet: DelegatePacket, ledger: string): SupervisorWorkerReview {
	const rationale: string[] = [];
	const conflicts: string[] = [];
	const evidenceGaps: string[] = [];
	const repairActions: string[] = [];
	let score = 45;
	if (packet.status === "done") {
		score += 30;
		rationale.push("packet status is done");
	}
	if (packet.status === "ready") {
		score += 10;
		rationale.push("packet has ready steps");
	}
	if (packet.status === "blocked") {
		score -= 25;
		conflicts.push("packet is blocked");
		repairActions.push("re_operation next");
	}
	if (packet.steps.length === 0) {
		score -= 20;
		evidenceGaps.push("no operation steps assigned");
	}
	if (packet.sourceArtifacts.length > 0) {
		score += 10;
		rationale.push("source artifacts attached");
	} else {
		score -= 10;
		evidenceGaps.push("no source artifact attached to packet");
		repairActions.push("re_operation plan");
	}
	if (evidenceHitForPacket(packet, ledger)) {
		score += 15;
		rationale.push("evidence ledger contains worker/contract anchors");
	} else {
		score -= 10;
		evidenceGaps.push(`ledger lacks ${packet.worker} evidence-contract anchors`);
	}
	const readySteps = packet.steps.filter((step) => step.status === "ready");
	if (readySteps.length > 0) repairActions.push(...readySteps.slice(0, 3).map((step) => step.command));
	if (packet.recommendedTools.length > 0)
		repairActions.push(`re_bootstrap plan ${packet.recommendedTools.slice(0, 6).join(" ")}`);
	const uniqueCommands = new Set(packet.steps.map((step) => step.command));
	if (uniqueCommands.size < packet.steps.length) conflicts.push("duplicate operation commands inside packet");
	score = Math.max(0, Math.min(100, score));
	const verdict: SupervisorVerdict =
		packet.status === "blocked" ? "blocked" : score >= 80 ? "pass" : score >= 60 ? "watch" : "repair";
	const priority = verdict === "blocked" ? 1 : verdict === "repair" ? 2 : verdict === "watch" ? 3 : 4;
	return {
		packetId: packet.id,
		worker: packet.worker,
		verdict,
		score,
		priority,
		rationale: rationale.length ? rationale : ["packet requires supervisor follow-up"],
		conflicts,
		evidenceGaps,
		repairActions: Array.from(new Set(repairActions)).slice(0, 8),
	};
}

function latestSwarmForSupervisor(
	options: { target?: string } = {},
): { swarm: SwarmArtifact; path: string } | undefined {
	const path = latestSwarmArtifactPath();
	if (!path) return undefined;
	const swarm = parseSwarmArtifact(path);
	if (!swarm) return undefined;
	if (options.target && swarm.target && options.target !== swarm.target) return undefined;
	return { swarm, path };
}

function reviewSwarmWorkerRuntime(
	worker: SwarmWorkerRuntime,
	swarm: SwarmArtifact,
	ledger: string,
): SupervisorWorkerReview {
	const executions = swarm.executions.filter((execution) => execution.workerId === worker.id);
	const blocked = executions.filter((execution) => execution.status === "blocked");
	const rationale: string[] = [];
	const conflicts: string[] = [];
	const evidenceGaps: string[] = [];
	const repairActions: string[] = [];
	let score = 50;
	if (executions.length > 0) {
		score += 15;
		rationale.push(`swarm worker executed ${executions.length} command(s)`);
	} else {
		score -= 15;
		evidenceGaps.push("swarm worker has no runtime execution yet");
		repairActions.push(`re_swarm run ${swarm.target ?? "<target>"} 1 1`);
	}
	if (worker.status === "done") {
		score += 25;
		rationale.push("swarm worker completed without blocked execution");
	}
	if (worker.status === "blocked" || blocked.length > 0) {
		score -= 35;
		conflicts.push(...blocked.map((execution) => `${execution.command}: ${truncateMiddle(execution.output, 180)}`));
		repairActions.push(`re_swarm run ${swarm.target ?? "<target>"} 1 1`);
		repairActions.push("re_context pack");
	}
	if (swarm.workerResults.some((result) => result.includes(worker.id))) {
		score += 10;
		rationale.push("worker_results contains runtime merge row");
	} else {
		score -= 10;
		evidenceGaps.push("worker_results lacks runtime merge row");
	}
	if (swarm.mergeDigest.some((item) => item.includes(worker.id) || item.includes(`worker=${worker.worker}`))) {
		score += 10;
		rationale.push("merge_digest contains worker evidence");
	}
	if (
		swarm.executionAudit.some(
			(item) => item.includes(`worker=${worker.id}`) && /status=(covered|needs_evidence)/i.test(item),
		)
	) {
		score += 10;
		rationale.push("execution_audit contains worker runtime coverage row");
	} else {
		score -= 5;
		evidenceGaps.push("execution_audit lacks worker coverage row");
	}
	const workerCoverageRows = swarm.coverageMatrix.filter((item) => item.includes(`worker=${worker.id}`));
	const missingCoverageRows = workerCoverageRows.filter((item) => /status=missing/i.test(item));
	if (workerCoverageRows.length > 0 && missingCoverageRows.length === 0) {
		score += 10;
		rationale.push("coverage_matrix satisfies worker evidence contract");
	} else if (missingCoverageRows.length > 0) {
		score -= 10;
		evidenceGaps.push(`coverage_matrix missing ${missingCoverageRows.length} contract row(s)`);
	}
	const workerRetries = swarm.retryQueue.filter((item) => item.includes(`worker=${worker.id}`));
	if (workerRetries.length > 0) {
		score -= 10;
		repairActions.push(...workerRetries.slice(0, 3).map((item) => item.replace(/^.*\bnext=/, "")));
	}
	if (
		evidenceHitForPacket(
			{
				id: worker.id,
				worker: worker.worker,
				objective: worker.objective,
				status:
					worker.status === "done" || worker.status === "merged"
						? "done"
						: worker.status === "blocked"
							? "blocked"
							: "ready",
				phases: worker.mergeKeys.filter((key) => key.startsWith("phase=")).map((key) => key.replace(/^phase=/, "")),
				steps: worker.commands.map((command, index) => ({
					id: `${worker.id}:cmd:${index + 1}`,
					phase: "swarm",
					command,
					status: worker.status === "blocked" ? "blocked" : worker.status === "done" ? "done" : "ready",
					sourceArtifacts: worker.sourceArtifacts,
				})),
				evidenceContract: worker.evidenceContract,
				recommendedTools: worker.recommendedTools,
				handoffPrompt: worker.spawnPrompt,
				sourceArtifacts: worker.sourceArtifacts,
			},
			ledger,
		)
	) {
		score += 10;
		rationale.push("ledger contains swarm worker anchors");
	}
	if (worker.commands.length > 0 && (blocked.length > 0 || executions.length === 0))
		repairActions.push(...worker.commands.slice(0, 2));
	repairActions.push(`re_proof_loop run ${swarm.target ?? "<target>"} 4 2`);
	score = Math.max(0, Math.min(100, score));
	const verdict: SupervisorVerdict =
		worker.status === "blocked" ? "blocked" : score >= 80 ? "pass" : score >= 60 ? "watch" : "repair";
	const priority = verdict === "blocked" ? 1 : verdict === "repair" ? 2 : verdict === "watch" ? 3 : 4;
	return {
		packetId: worker.id,
		worker: worker.worker,
		verdict,
		score,
		priority,
		rationale: rationale.length ? rationale : ["swarm worker requires commander merge follow-up"],
		conflicts,
		evidenceGaps,
		repairActions: Array.from(new Set(repairActions)).slice(0, 10),
	};
}

function swarmCommanderMergeQueue(swarm?: SwarmArtifact): string[] {
	if (!swarm) return [];
	const target = swarm.target ?? "<target>";
	return Array.from(
		new Set([
			...(swarm.blocked.length ? [`re_supervisor repair ${target}`, `re_context pack ${target}`] : []),
			...swarm.retryQueue
				.flatMap((item) => item.match(/next=([^&;]+)/i)?.[1]?.trim() ?? [])
				.filter((item) => /^re[-_]/i.test(item)),
			...swarm.blocked.slice(0, 8).map(() => `re_swarm run ${target} 1 1`),
			...(swarm.workerResults.length ? ["re_verifier matrix", `re_proof_loop run ${target} 4 2`] : []),
			...(swarm.mergeDigest.length ? ["re_swarm merge", "re_supervisor review"] : []),
			...(swarm.executions.length ? [`re_context pack ${target}`, `re_operator dispatch ${target} 2`] : []),
		]),
	).slice(0, 18);
}

function commanderWorkerScoreboard(reviews: SupervisorWorkerReview[]): string[] {
	return reviews
		.slice()
		.sort((left, right) => left.priority - right.priority || left.score - right.score)
		.map((review) => {
			const retryBudget = review.verdict === "blocked" ? 2 : review.verdict === "repair" ? 1 : 0;
			const failureCost = review.verdict === "blocked" ? 2 : review.verdict === "repair" ? 1 : 0;
			const next = review.repairActions[0] ?? "none";
			return `${review.worker} packet=${review.packetId} verdict=${review.verdict} score=${review.score} retry_budget=${retryBudget} failure_cost=${failureCost} next=${next}`;
		})
		.slice(0, 32);
}

function buildCommanderMergeBudget(
	reviews: SupervisorWorkerReview[],
	queue: string[],
	swarm?: SwarmArtifact,
): string[] {
	const blockedWorkers = reviews.filter((review) => review.verdict === "blocked").length;
	const repairWorkers = reviews.filter((review) => review.verdict === "repair").length;
	const watchWorkers = reviews.filter((review) => review.verdict === "watch").length;
	const queueDepth = queue.length;
	const maxDispatch = Math.max(1, Math.min(6, queueDepth ? Math.ceil(queueDepth / 2) : 1));
	const retryLimit = Math.max(1, Math.min(3, blockedWorkers ? 2 : repairWorkers ? 1 : 1));
	const failureBudget = Math.max(
		1,
		Math.min(6, blockedWorkers * 2 + repairWorkers + (swarm?.blocked.length ?? 0) || 1),
	);
	const proofRerun = queue.some((item) => /^re[-_]proof[-_]loop\s+run/i.test(item));
	return [
		`max_dispatch=${maxDispatch}`,
		`retry_limit_per_worker=${retryLimit}`,
		`failure_budget=${failureBudget}`,
		`queue_depth=${queueDepth}`,
		`blocked_workers=${blockedWorkers}`,
		`repair_workers=${repairWorkers}`,
		`watch_workers=${watchWorkers}`,
		`swarm_executions=${swarm?.executions.length ?? 0}`,
		`swarm_blocked=${swarm?.blocked.length ?? 0}`,
		`proof_rerun=${proofRerun ? "yes" : "no"}`,
	];
}

function supervisorClaimGatePolicy(plan?: ReconParallelPlanV1, planCoverage: string[] = []): string[] {
	const workerBinding = planCoverage.find((row) => row.startsWith("worker_binding="))?.replace(/^worker_binding=/, "") ?? "missing";
	const missingContractRows = planCoverage.filter((row) => /\bmissing=[1-9]/.test(row));
	return [
		`claim_gate_policy.parallel_plan_id=${plan?.planId ?? "missing"}`,
		`claim_gate_policy.parallel_plan_source=${plan?.source ?? "missing"}`,
		`claim_gate_policy.worker_binding=${workerBinding}`,
		`claim_gate_policy.plan_contract_gaps=${missingContractRows.length}`,
		"claim_gate_policy.proven_requires_artifact_sha256=true",
		"claim_gate_policy.proven_requires_json_query=true",
		"claim_gate_policy.final_pass_requires_verifier=true",
		"claim_gate_policy.unresolved_challenge_blocks=true",
		"claim_gate_policy.orchestration_score_never_implies_platform_success=true",
		"claim_gate_policy.final_pass_blocks_on_plan_coverage_gap=true",
	];
}

function supervisorPlanCoverage(swarm?: SwarmArtifact): string[] {
	if (!swarm) return ["parallel_plan=missing status=blocked next=re_swarm plan"];
	return swarmPlanCoverage(swarm);
}

function buildSupervisor(
	options: { target?: string; task?: string; mode?: "review" | "repair" } = {},
): SupervisorArtifact {
	ensureReconStorage();
	const { delegate, path: delegationArtifact } = latestOrBuildDelegate(options);
	const ledger = readText(evidenceLedgerPath());
	const latestSwarm = latestSwarmForSupervisor({ target: options.target ?? delegate.target });
	const swarm = latestSwarm?.swarm;
	const parallelPlan = swarm?.parallelPlan;
	const planCoverage = supervisorPlanCoverage(swarm);
	const releaseGateMetadata = swarm?.releaseGateMetadata ?? [];
	const claimGatePolicy = supervisorClaimGatePolicy(parallelPlan, planCoverage);
	const strictClaimGate = strictClaimGateSnapshot();
	const claimGateResult = buildClaimGateResult(releaseGateMetadata, claimGatePolicy, strictClaimGate);
	const claimGateBlocks = strictClaimGate.status !== "pass" && (releaseGateMetadata.length > 0 || claimGatePolicy.length > 0);
	const swarmReviews = swarm?.workers.map((worker) => reviewSwarmWorkerRuntime(worker, swarm, ledger)) ?? [];
	const reviews = [...delegate.packets.map((packet) => reviewDelegatePacket(packet, ledger)), ...swarmReviews];
	const commanderMergeQueue = swarmCommanderMergeQueue(swarm);
	const workerScoreboard = commanderWorkerScoreboard(reviews);
	const commanderMergeBudget = buildCommanderMergeBudget(reviews, commanderMergeQueue, swarm);
	const conflicts = Array.from(
		new Set(
			[
				...delegate.gaps,
				...(swarm?.blocked.map((item) => `swarm blocked: ${item}`) ?? []),
				...(planCoverage.some((row) => /worker_binding=fail|parallel_plan=missing|\bmissing=[1-9]/.test(row))
					? planCoverage.map((row) => `parallel plan coverage: ${row}`)
					: []),
				...(swarm?.mergeDigest.filter((item) => /^collision:/i.test(item)) ?? []),
				...(claimGateBlocks ? claimGateResult.map((item) => `strict claim gate: ${item}`) : []),
				...reviews.flatMap((review) => review.conflicts.map((item) => `${review.worker}: ${item}`)),
				delegate.packets.length === 0 ? "no worker packets available" : undefined,
			].filter((item): item is string => Boolean(item)),
		),
	).slice(0, 32);
	const repairQueue = Array.from(
		new Set([
			...reviews
				.filter(
					(review) => review.verdict === "blocked" || review.verdict === "repair" || options.mode === "repair",
				)
				.sort((left, right) => left.priority - right.priority || left.score - right.score)
				.flatMap((review) => review.repairActions.map((action) => `${review.worker}: ${action}`)),
			...commanderMergeQueue.map((action) => `commander: ${action}`),
			...(claimGateBlocks
				? [
						strictClaimGate.status === "missing"
							? "claim_gate: run npm run gate:claim-release to write strict claim release marker"
							: "claim_gate: resolve required platform gaps and rerun npm run gate:claim-release",
					]
				: []),
		]),
	).slice(0, 24);
	const priorityQueue = reviews
		.slice()
		.sort((left, right) => left.priority - right.priority || left.score - right.score)
		.map((review) => `${review.worker} ${review.verdict} score=${review.score} packet=${review.packetId}`);
	const hasBlocked = reviews.some((review) => review.verdict === "blocked");
	const hasRepair = reviews.some((review) => review.verdict === "repair");
	const hasWatch = reviews.some((review) => review.verdict === "watch");
	const supervisorVerdict: SupervisorVerdict = hasBlocked
		? "blocked"
		: claimGateBlocks
			? "blocked"
			: hasRepair
			? "repair"
			: hasWatch
				? "watch"
				: "pass";
	const mission = readCurrentMission();
	const gates = mission
		? mission.gates.map((gate) => `${gate.name}:${gate.status}${gate.note ? `:${gate.note}` : ""}`)
		: ["mission:none"];
	const nextActions = Array.from(
		new Set([
			...repairQueue.map((item) => item.replace(/^.+?:\s*/, "")),
			...commanderMergeQueue,
			...(parallelPlan ? [] : ["re_swarm plan"]),
			"re_delegate merge",
			"re_swarm merge",
			"re_operation next",
			"re_complete audit",
		]),
	).slice(0, 16);
	return {
		timestamp: new Date().toISOString(),
		missionId: delegate.missionId,
		route: delegate.route,
		target: options.target ?? delegate.target,
		mode: options.mode ?? "review",
		delegationArtifact,
		swarmArtifact: latestSwarm?.path,
		supervisorVerdict,
		reviews,
		conflicts,
		repairQueue,
		commanderMergeQueue,
		commanderMergeBudget,
		workerScoreboard,
		priorityQueue,
		gates,
		nextActions,
		parallelPlan,
		planCoverage,
		releaseGateMetadata,
		claimGatePolicy,
		strictClaimGate,
		claimGateResult,
		sourceArtifacts: Array.from(
			new Set(
				[
					delegationArtifact,
					latestSwarm?.path,
					...delegate.sourceArtifacts,
					...(swarm?.sourceArtifacts ?? []),
				].filter(Boolean) as string[],
			),
		).slice(0, 36),
	};
}

function formatSupervisor(supervisor: SupervisorArtifact, path?: string): string {
	return [
		"supervisor_review:",
		path ? `supervisor_artifact: ${path}` : undefined,
		`timestamp: ${supervisor.timestamp}`,
		`mode: ${supervisor.mode}`,
		`supervisor_verdict: ${supervisor.supervisorVerdict}`,
		`mission_id: ${supervisor.missionId ?? "none"}`,
		`route: ${supervisor.route ?? "none"}`,
		`target: ${supervisor.target ?? "<none>"}`,
		`delegation_artifact: ${supervisor.delegationArtifact ?? "none"}`,
		`swarm_artifact: ${supervisor.swarmArtifact ?? "none"}`,
		"worker_reviews:",
		...(supervisor.reviews.length
			? supervisor.reviews.flatMap((review) => [
					`- ${review.worker} [${review.verdict}] score=${review.score} priority=${review.priority} packet=${review.packetId}`,
					`  rationale: ${review.rationale.join(" | ")}`,
					`  conflicts: ${review.conflicts.length ? review.conflicts.join(" | ") : "none"}`,
					`  evidence_gaps: ${review.evidenceGaps.length ? review.evidenceGaps.join(" | ") : "none"}`,
					`  repair_actions: ${review.repairActions.length ? review.repairActions.join(" | ") : "none"}`,
				])
			: ["- none"]),
		"conflict_matrix:",
		...(supervisor.conflicts.length ? supervisor.conflicts.map((item) => `- ${item}`) : ["- none"]),
		"repair_queue:",
		...(supervisor.repairQueue.length ? supervisor.repairQueue.map((item) => `- ${item}`) : ["- none"]),
		"commander_merge_queue:",
		...(supervisor.commanderMergeQueue.length
			? supervisor.commanderMergeQueue.map((item) => `- ${item}`)
			: ["- none"]),
		"commander_merge_budget:",
		...(supervisor.commanderMergeBudget.length
			? supervisor.commanderMergeBudget.map((item) => `- ${item}`)
			: ["- none"]),
		"worker_scoreboard:",
		...(supervisor.workerScoreboard.length ? supervisor.workerScoreboard.map((item) => `- ${item}`) : ["- none"]),
		"priority_queue:",
		...(supervisor.priorityQueue.length ? supervisor.priorityQueue.map((item) => `- ${item}`) : ["- none"]),
		"gates:",
		...(supervisor.gates.length ? supervisor.gates.map((item) => `- ${item}`) : ["- none"]),
		"parallel_plan:",
		...(supervisor.parallelPlan
			? [
					`- plan_id=${supervisor.parallelPlan.planId}`,
					`- source=${supervisor.parallelPlan.source}`,
					`- workers=${supervisor.parallelPlan.workers.length}`,
					`- merge=${supervisor.parallelPlan.merge.strategy}`,
				]
			: ["- none"]),
		"plan_coverage:",
		...(supervisor.planCoverage.length ? supervisor.planCoverage.map((item) => `- ${item}`) : ["- none"]),
		"release_gate_metadata:",
		...(supervisor.releaseGateMetadata.length
			? supervisor.releaseGateMetadata.map((item) => `- ${item}`)
			: ["- none"]),
		"claim_gate_policy:",
		...(supervisor.claimGatePolicy.length ? supervisor.claimGatePolicy.map((item) => `- ${item}`) : ["- none"]),
		"strict_claim_gate:",
		...formatStrictClaimGateSnapshot(supervisor.strictClaimGate),
		"claim_gate_result:",
		...(supervisor.claimGateResult.length ? supervisor.claimGateResult.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(supervisor.nextActions.length ? supervisor.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_supervisor_command: ${supervisor.mode === "repair" ? "re_supervisor review" : "re_supervisor repair"}`,
		"source_artifacts:",
		...(supervisor.sourceArtifacts.length ? supervisor.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeSupervisorArtifact(supervisor: SupervisorArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceSupervisorsDir(),
		`${supervisor.timestamp.replace(/[:.]/g, "-")}-${slug(supervisor.route ?? "supervisor")}-${supervisor.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Supervisor Artifact",
			"",
			formatSupervisor(supervisor, path),
			"",
			"## Worker reviews",
			"",
			...supervisor.reviews.map(
				(review) => `- ${review.worker} verdict=${review.verdict} score=${review.score} packet=${review.packetId}`,
			),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(supervisor, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	writeFileSync(
		memoryPath("commander-merge-board.md"),
		[
			"# Pi-RECON Commander Merge Board",
			"",
			`Updated: ${supervisor.timestamp}`,
			`Artifact: ${path}`,
			`Swarm artifact: ${supervisor.swarmArtifact ?? "none"}`,
			"",
			"## Worker scoreboard",
			...(supervisor.workerScoreboard.length ? supervisor.workerScoreboard.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Commander merge budget",
			...(supervisor.commanderMergeBudget.length
				? supervisor.commanderMergeBudget.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Commander merge queue",
			...(supervisor.commanderMergeQueue.length
				? supervisor.commanderMergeQueue.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Parallel plan coverage",
			...(supervisor.planCoverage.length ? supervisor.planCoverage.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Claim gate policy",
			...(supervisor.claimGatePolicy.length ? supervisor.claimGatePolicy.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Release gate metadata",
			...(supervisor.releaseGateMetadata.length
				? supervisor.releaseGateMetadata.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Strict claim gate",
			...formatStrictClaimGateSnapshot(supervisor.strictClaimGate),
			"",
			"## Claim gate result",
			...(supervisor.claimGateResult.length ? supervisor.claimGateResult.map((item) => `- ${item}`) : ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `supervisor-${supervisor.mode} ${supervisor.missionId ?? "no-mission"}`,
		fact: `Supervisor verdict ${supervisor.supervisorVerdict} across ${supervisor.reviews.length} worker review(s), ${supervisor.conflicts.length} conflict(s), ${supervisor.repairQueue.length} repair action(s), commander_merge=${supervisor.commanderMergeQueue.length}, commander_budget=${supervisor.commanderMergeBudget.length}, parallel_plan=${supervisor.parallelPlan?.planId ?? "missing"}, release_gate_metadata=${supervisor.releaseGateMetadata.length}, claim_gate_policy=${supervisor.claimGatePolicy.length}, strict_claim_gate=${supervisor.strictClaimGate?.status ?? "missing"}`,
		command: `re_supervisor ${supervisor.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "delegation/operation supervisor critic",
	});
	updateMissionGate(
		"supervisor_review_ready",
		supervisor.supervisorVerdict === "pass" ? "done" : "blocked",
		`${path} verdict=${supervisor.supervisorVerdict}`,
	);
	return path;
}

function buildSupervisorOutput(
	action: "review" | "show" | "repair" = "review",
	options: { target?: string; task?: string } = {},
): string {
	if (action === "show") {
		const path = latestSupervisorArtifactPath();
		if (!path) return "supervisor_review:\nstatus: missing\nnext: re_supervisor review";
		return truncateMiddle(readText(path), 16000);
	}
	const supervisor = buildSupervisor({ ...options, mode: action === "repair" ? "repair" : "review" });
	const path = writeSupervisorArtifact(supervisor);
	return formatSupervisor(supervisor, path);
}

function latestReflectionArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceReflectionsDir(), 1)[0];
}

function parseSupervisorArtifact(path: string): SupervisorArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as SupervisorArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildSupervisor(options: { target?: string; task?: string } = {}): {
	supervisor: SupervisorArtifact;
	path: string;
} {
	const latest = !options.target && !options.task ? latestSupervisorArtifactPath() : undefined;
	if (latest) {
		const supervisor = parseSupervisorArtifact(latest);
		if (supervisor) return { supervisor, path: latest };
	}
	const supervisor = buildSupervisor({ target: options.target, task: options.task, mode: "review" });
	const path = writeSupervisorArtifact(supervisor);
	return { supervisor, path };
}

function buildReflection(
	options: { target?: string; task?: string; mode?: "plan" | "write" } = {},
): ReflectionArtifact {
	ensureReconStorage();
	const { supervisor, path: supervisorArtifact } = latestOrBuildSupervisor(options);
	const failing = supervisor.reviews.filter((review) => review.verdict === "blocked" || review.verdict === "repair");
	const watching = supervisor.reviews.filter((review) => review.verdict === "watch");
	const passing = supervisor.reviews.filter((review) => review.verdict === "pass");
	const scoreboardEntries = supervisor.workerScoreboard
		.map(parseWorkerScoreboardLine)
		.filter((entry): entry is WorkerScoreboardEntry => Boolean(entry));
	const adaptiveRoutingHints = workerAdaptiveRoutingHints(scoreboardEntries, options.target ?? supervisor.target);
	const promotionQueue = buildWorkerPromotionQueue(scoreboardEntries, options.target ?? supervisor.target);
	const lessons = Array.from(
		new Set([
			`supervisor_verdict=${supervisor.supervisorVerdict}; workers=${supervisor.reviews.length}; repairs=${supervisor.repairQueue.length}`,
			...supervisor.workerScoreboard.slice(0, 8).map((item) => `worker_scoreboard: ${item}`),
			...passing.map(
				(review) =>
					`${review.worker}: preserve packet shape; score=${review.score}; ${review.rationale.join(" | ")}`,
			),
			...watching.map((review) => `${review.worker}: watch weak evidence before expansion; score=${review.score}`),
			...failing.map(
				(review) => `${review.worker}: route to repair before claiming completion; score=${review.score}`,
			),
		]),
	).slice(0, 24);
	const failurePatterns = Array.from(
		new Set([
			...supervisor.conflicts,
			...failing.flatMap((review) => review.conflicts.map((item) => `${review.worker}: ${item}`)),
			...failing.flatMap((review) => review.evidenceGaps.map((item) => `${review.worker}: ${item}`)),
			...supervisor.gates.filter((gate) => /pending|blocked/i.test(gate)).map((gate) => `gate: ${gate}`),
		]),
	).slice(0, 32);
	const reuseRules = Array.from(
		new Set([
			"Before broad expansion: re_map → re_live_browser → re_graph → re_campaign → re_operation → re_delegate → re_swarm → re_supervisor → re_reflect.",
			"When supervisor_verdict is repair/blocked: execute repair_queue before report scaffold.",
			"When worker score is watch: collect one more runtime/traffic/artifact anchor before lateral movement.",
			...adaptiveRoutingHints.map((item) => `adaptive_route: ${item}`),
			...promotionQueue.map((item) => `promotion: ${item}`),
			...supervisor.priorityQueue.slice(0, 8).map((item) => `prioritize: ${item}`),
		]),
	).slice(0, 24);
	const repairPlaybook = Array.from(
		new Set([...supervisor.repairQueue, ...supervisor.nextActions, "re_supervisor review", "re_complete audit"]),
	).slice(0, 32);
	return {
		timestamp: new Date().toISOString(),
		missionId: supervisor.missionId,
		route: supervisor.route,
		target: options.target ?? supervisor.target,
		mode: options.mode ?? "plan",
		supervisorArtifact,
		lessons,
		failurePatterns,
		reuseRules,
		repairPlaybook,
		nextActions: [
			...(repairPlaybook.length ? repairPlaybook.slice(0, 6) : ["re_operation next"]),
			"re_memory playbooks",
			"re_complete audit",
		],
		sourceArtifacts: Array.from(new Set([supervisorArtifact, ...supervisor.sourceArtifacts])).slice(0, 28),
	};
}

function writeReflectionMemory(reflection: ReflectionArtifact): ReflectionArtifact {
	ensureReconStorage();
	const title = `supervisor-reflection ${reflection.route ?? "security"}`;
	const playbookPath = join(memoryPlaybooksDir(), `${reflection.timestamp.replace(/[:.]/g, "-")}-${slug(title)}.md`);
	writeFileSync(
		playbookPath,
		[
			"# Pi-RECON Reflection Playbook",
			"",
			`timestamp: ${reflection.timestamp}`,
			`route: ${reflection.route ?? "none"}`,
			`target: ${reflection.target ?? "<none>"}`,
			`supervisor_artifact: ${reflection.supervisorArtifact ?? "none"}`,
			"quality_score: 75",
			"",
			"## Lessons",
			"",
			...(reflection.lessons.length ? reflection.lessons.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Failure patterns",
			"",
			...(reflection.failurePatterns.length ? reflection.failurePatterns.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Reuse rules",
			"",
			...(reflection.reuseRules.length ? reflection.reuseRules.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Worker routing / promotion",
			"",
			...reflection.lessons
				.filter((item) => /worker_scoreboard|adaptive_route|promotion:/i.test(item))
				.map((item) => `- ${item}`),
			"",
			"## Repair playbook",
			"",
			...(reflection.repairPlaybook.length ? reflection.repairPlaybook.map((item) => `- ${item}`) : ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	const journalAnchor = appendJournal(
		"supervisor-reflection",
		title,
		[
			`playbook: ${playbookPath}`,
			`supervisor_artifact: ${reflection.supervisorArtifact ?? "none"}`,
			`lessons=${reflection.lessons.length}; failures=${reflection.failurePatterns.length}; repairs=${reflection.repairPlaybook.length}`,
			...reflection.lessons.slice(0, 6).map((item) => `lesson: ${item}`),
		].join("\n"),
	);
	const evolutionAnchor = appendEvolution(
		`supervisor reflection ${reflection.route ?? "security"}`,
		[
			`Promoted supervisor critique into reusable playbook: ${playbookPath}`,
			`route=${reflection.route ?? "unknown"}; target=${reflection.target ?? "unknown"}`,
			`reuse_rules=${reflection.reuseRules.length}; repair_actions=${reflection.repairPlaybook.length}`,
			"Policy: future security tasks should run re_reflect write after supervisor repair/review before final report.",
		].join("\n"),
	);
	maintainPlaybooks({ archive: true });
	return { ...reflection, journalAnchor, evolutionAnchor, playbookPath };
}

function formatReflection(reflection: ReflectionArtifact, path?: string): string {
	return [
		"reflection_cycle:",
		path ? `reflection_artifact: ${path}` : undefined,
		`timestamp: ${reflection.timestamp}`,
		`mode: ${reflection.mode}`,
		`mission_id: ${reflection.missionId ?? "none"}`,
		`route: ${reflection.route ?? "none"}`,
		`target: ${reflection.target ?? "<none>"}`,
		`supervisor_artifact: ${reflection.supervisorArtifact ?? "none"}`,
		reflection.playbookPath ? `playbook_path: ${reflection.playbookPath}` : undefined,
		reflection.journalAnchor ? `field_journal_anchor: ${reflection.journalAnchor}` : undefined,
		reflection.evolutionAnchor ? `evolution_anchor: ${reflection.evolutionAnchor}` : undefined,
		"lessons:",
		...(reflection.lessons.length ? reflection.lessons.map((item) => `- ${item}`) : ["- none"]),
		"failure_patterns:",
		...(reflection.failurePatterns.length ? reflection.failurePatterns.map((item) => `- ${item}`) : ["- none"]),
		"reuse_rules:",
		...(reflection.reuseRules.length ? reflection.reuseRules.map((item) => `- ${item}`) : ["- none"]),
		"repair_playbook:",
		...(reflection.repairPlaybook.length ? reflection.repairPlaybook.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(reflection.nextActions.length ? reflection.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_reflect_command: ${reflection.mode === "write" ? "re_memory playbooks" : "re_reflect write"}`,
		"source_artifacts:",
		...(reflection.sourceArtifacts.length ? reflection.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeReflectionArtifact(reflection: ReflectionArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceReflectionsDir(),
		`${reflection.timestamp.replace(/[:.]/g, "-")}-${slug(reflection.route ?? "reflection")}-${reflection.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Reflection Artifact",
			"",
			formatReflection(reflection, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(reflection, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `reflection-${reflection.mode} ${reflection.missionId ?? "no-mission"}`,
		fact: `Reflection captured ${reflection.lessons.length} lesson(s), ${reflection.failurePatterns.length} failure pattern(s), ${reflection.repairPlaybook.length} repair action(s)`,
		command: `re_reflect ${reflection.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "supervisor/memory/evolution reflection",
	});
	if (reflection.mode === "write") updateMissionGate("reflection_memory_ready", "done", path);
	return path;
}

function buildReflectOutput(
	action: "plan" | "show" | "write" = "plan",
	options: { target?: string; task?: string } = {},
): string {
	if (action === "show") {
		const path = latestReflectionArtifactPath();
		if (!path) return "reflection_cycle:\nstatus: missing\nnext: re_reflect plan";
		return truncateMiddle(readText(path), 16000);
	}
	let reflection = buildReflection({ ...options, mode: action === "write" ? "write" : "plan" });
	if (action === "write") reflection = writeReflectionMemory(reflection);
	const path = writeReflectionArtifact(reflection);
	return formatReflection(reflection, path);
}

function latestContextPackArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceContextsDir(), 1)[0];
}

function parseReflectionArtifact(path: string): ReflectionArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as ReflectionArtifact;
	} catch {
		return undefined;
	}
}

const CONTEXT_HASH_OMIT = new Set(["contextSha256", "exactResumeVerification", "resumedFromContextPath"]);

function contextEvidenceRank(kind: string): string {
	if (/browser|web_authz|mobile_runtime|native_runtime|exploit_lab|run|replayer|proof_loop/i.test(kind)) return "runtime_artifact";
	if (/map|knowledge|harness|decision_core|kernel/i.test(kind)) return "process_config";
	if (/compiler|verifier|supervisor|swarm|delegation|operation|reflection|operator|autofix/i.test(kind))
		return "persisted_state";
	return "artifact";
}

function contextSourceCommand(kind: string): string {
	return `re_${kind.replace(/-/g, "_")} show`;
}

function contextArtifactEntry(kind: string, path: string): ContextArtifactIndexEntry {
	let exists = false;
	let size = 0;
	let mtime = "";
	let sha: string | null = null;
	try {
		const stat = statSync(path);
		exists = true;
		size = stat.size;
		mtime = stat.mtime.toISOString();
		sha = createHash("sha256").update(readFileSync(path)).digest("hex");
	} catch {
		// keep missing metadata explicit for resume verification
	}
	return {
		kind,
		path,
		artifactId: `${kind}:${createHash("sha256").update(path).digest("hex").slice(0, 16)}`,
		exists,
		size,
		mtime,
		sha256: sha,
		evidenceRank: contextEvidenceRank(kind),
		sourceCommand: contextSourceCommand(kind),
	};
}

function contextPackArtifactPathFor(params: { timestamp: string; route?: string; target?: string; mode: "pack" | "resume" }): string {
	return join(
		evidenceContextsDir(),
		`${params.timestamp.replace(/[:.]/g, "-")}-${slug(params.route ?? params.target ?? "context")}-${params.mode}.md`,
	);
}

function contextSessionId(mission?: MissionState): string {
	return mission?.id ?? process.env.PI_RECON_SESSION_ID ?? process.env.SESSION_ID ?? "manual-session";
}

function contextBranchId(): string {
	return process.env.PI_RECON_BRANCH_ID ?? process.env.GIT_BRANCH ?? process.env.BRANCH_NAME ?? "workspace";
}

function contextPackHashPayload(pack: ContextPackArtifact): unknown {
	const strip = (value: unknown): unknown => {
		if (Array.isArray(value)) return value.map(strip);
		if (value && typeof value === "object") {
			return Object.fromEntries(
				Object.entries(value as Record<string, unknown>)
					.filter(([key]) => !CONTEXT_HASH_OMIT.has(key))
					.map(([key, item]) => [key, strip(item)]),
			);
		}
		return value;
	};
	return strip(pack);
}

function contextPackSha256(pack: ContextPackArtifact): string {
	return createHash("sha256").update(JSON.stringify(contextPackHashPayload(pack))).digest("hex");
}

function contextArtifactHashes(index: ContextArtifactIndexEntry[]): Array<{ artifactId: string; path: string; sha256: string | null; required: boolean }> {
	return index.map((artifact) => ({
		artifactId: artifact.artifactId ?? `${artifact.kind}:${artifact.path}`,
		path: artifact.path,
		sha256: artifact.sha256 ?? null,
		required: artifact.exists === true,
	}));
}

function contextCompactionLedger(timestamp: string): { path: string; appendOnly: true; prevHash: string; entryHash: string } {
	const path = memoryPath("compaction-resume-ledger.jsonl");
	const previous = readText(path);
	const prevHash = previous.trim() ? createHash("sha256").update(previous).digest("hex") : "0".repeat(64);
	const entryHash = createHash("sha256").update(`${prevHash}\n${timestamp}\ncontext-pack`).digest("hex");
	return { path, appendOnly: true, prevHash, entryHash };
}

function contextArtifactIndex(): ContextArtifactIndexEntry[] {
	const pairs: Array<[string, string | undefined]> = [
		["map", recentMarkdownArtifacts(evidenceMapsDir(), 1)[0]],
		["browser", latestLiveBrowserArtifactPath()],
		["web_authz", latestWebAuthzStateArtifactPath()],
		["exploit_lab", latestExploitLabArtifactPath()],
		["mobile_runtime", latestMobileRuntimeArtifactPath()],
		["native_runtime", latestNativeRuntimeArtifactPath()],
		["run", recentMarkdownArtifacts(evidenceRunsDir(), 1)[0]],
		["attack_graph", latestAttackGraphArtifactPath()],
		["exploit_chain", latestExploitChainArtifactPath()],
		["decision_core", latestDecisionCoreArtifactPath()],
		["campaign", latestCampaignArtifactPath()],
		["operation", latestOperationArtifactPath()],
		["delegation", latestDelegateArtifactPath()],
		["swarm", latestSwarmArtifactPath()],
		["supervisor", latestSupervisorArtifactPath()],
		["reflection", latestReflectionArtifactPath()],
		["operator", latestOperatorArtifactPath()],
		["verifier", latestVerifierArtifactPath()],
		["compiler", latestCompilerArtifactPath()],
		["replayer", latestReplayerArtifactPath()],
		["autofix", latestAutofixArtifactPath()],
		["proof_loop", latestProofLoopArtifactPath()],
		["knowledge", latestKnowledgeGraphArtifactPath()],
		["harness", latestHarnessArtifactPath()],
	];
	return pairs.filter((pair): pair is [string, string] => Boolean(pair[1])).map(([kind, path]) => contextArtifactEntry(kind, path));
}

function commandTargetSuffix(target?: string): string {
	return target ? ` ${target}` : "";
}

function buildContextPack(options: { target?: string; mode?: "pack" | "resume" } = {}): ContextPackArtifact {
	ensureReconStorage();
	const timestamp = new Date().toISOString();
	const mission = readCurrentMission();
	const active = mission ? activeLane(mission) : undefined;
	const artifactIndex = contextArtifactIndex();
	const supervisorPath = latestSupervisorArtifactPath();
	const reflectionPath = latestReflectionArtifactPath();
	const supervisor = supervisorPath ? parseSupervisorArtifact(supervisorPath) : undefined;
	const reflection = reflectionPath ? parseReflectionArtifact(reflectionPath) : undefined;
	const target = options.target ?? reflection?.target ?? supervisor?.target;
	const autonomousBudget = autonomousExecutionBudget(target);
	const swarmRetry = latestSwarmRetryQueue(target);
	const gateSummary = mission
		? mission.gates.map(
				(gate) => `${gate.name}=${gate.status}${gate.note ? `:${truncateMiddle(gate.note, 160)}` : ""}`,
			)
		: ["no active mission"];
	const pendingGates = mission?.gates.filter((gate) => gate.status !== "done").map((gate) => gate.name) ?? [];
	const repairQueue = Array.from(
		new Set([
			...swarmRetry.rows,
			...(reflection?.repairPlaybook ?? []),
			...(supervisor?.repairQueue ?? []),
			...(supervisor?.commanderMergeQueue ?? []),
			...(supervisor?.nextActions ?? []),
		]),
	).slice(0, 36);
	const commanderMergeBudget = Array.from(new Set(supervisor?.commanderMergeBudget ?? [])).slice(0, 16);
	const workerScoreboard = Array.from(new Set(supervisor?.workerScoreboard ?? [])).slice(0, 32);
	const swarmRetryQueue = swarmRetry.rows;
	const caseMemoryPlan = currentCaseMemoryLanePlan(target);
	const caseMemoryNextCommands = caseMemoryOperatorCommands(caseMemoryPlan, target);
	const reflectionReuseRules = Array.from(new Set(reflection?.reuseRules ?? [])).slice(0, 24);
	const route = mission?.route.domain ?? reflection?.route ?? supervisor?.route;
	const mode = options.mode ?? "pack";
	const contextPath = contextPackArtifactPathFor({ timestamp, route, target, mode });
	const scope = {
		missionId: mission?.id ?? reflection?.missionId ?? supervisor?.missionId,
		sessionId: contextSessionId(mission),
		cwd: process.cwd(),
		workspaceRoot: process.cwd(),
		target,
		branchId: contextBranchId(),
	};
	const laneCommands = active
		? [
				`re_lane plan ${active.name}${commandTargetSuffix(target)}`,
				`re_lane run ${active.name}${commandTargetSuffix(target)}`,
				...(active.next.some((item) => /^\[auto:/i.test(item)) ? [`re_lane run-auto ${active.name} 2`] : []),
			]
		: ["re_mission show", "re_map <target> 2"];
	const repairCommands = repairQueue
		.filter((item) => /^\/?re[-_]/i.test(item.trim()))
		.map((item) => item.trim().replace(/^\//, ""));
	const commanderCommands = (supervisor?.commanderMergeQueue ?? [])
		.filter((item) => /^\/?re[-_]/i.test(item.trim()))
		.map((item) => item.trim().replace(/^\//, ""));
	const nextCommands = Array.from(
		new Set([
			...swarmRetry.commands,
			...commanderCommands,
			...repairCommands,
			...caseMemoryNextCommands,
			...autonomousBudget.nextActions,
			`re_decision_core tick${commandTargetSuffix(target)}`,
			...laneCommands,
			supervisorPath ? "re_supervisor repair" : `re_supervisor review${commandTargetSuffix(target)}`,
			reflectionPath ? "re_reflect write" : `re_reflect plan${commandTargetSuffix(target)}`,
			"re_verifier matrix",
			"re_compiler draft",
			"re_replayer run",
			"re_autofix plan",
			"re_knowledge_graph build",
			"re_complete audit",
			"re_context pack",
		]),
	).slice(0, 14);
	const resumeBrief = [
		`mission=${mission?.id ?? "none"}`,
		`route=${mission?.route.domain ?? reflection?.route ?? supervisor?.route ?? "unknown"}`,
		`active_lane=${active?.name ?? "none"}`,
		`pending_gates=${pendingGates.length ? pendingGates.join(",") : "none"}`,
		`latest_reflection=${reflectionPath ?? "none"}`,
		`latest_supervisor=${supervisorPath ?? "none"}`,
		`repair_queue_items=${repairQueue.length}`,
		`swarm_retry_queue=${swarmRetryQueue.length}`,
		`autonomous_budget=max_turns:${autonomousBudget.maxTurns},max_dispatch:${autonomousBudget.maxDispatch},score_decay:${autonomousBudget.scoreDecay.length},demotions:${autonomousBudget.demotionRules.length},promotions:${autonomousBudget.promotionRules.length}`,
		`commander_merge_queue=${supervisor?.commanderMergeQueue.length ?? 0}`,
		`commander_budget=${commanderMergeBudget.join(";") || "none"}`,
		`case_memory_lane_plan=${caseMemoryPlan?.action ?? "none"}:${caseMemoryPlan?.targetLane ?? caseMemoryPlan?.addedLane ?? active?.name ?? "none"}`,
		`first_command=${nextCommands[0] ?? "re_mission show"}`,
	];
	const pack: ContextPackArtifact = {
		contractId: `context-pack/${slug(route ?? target ?? "context")}/${timestamp}`,
		schemaVersion: 2,
		timestamp,
		missionId: mission?.id ?? reflection?.missionId ?? supervisor?.missionId,
		route,
		target,
		mode,
		contextPath,
		scope,
		artifactHashes: contextArtifactHashes(artifactIndex),
		resumeQueueStatus: mode === "resume" ? "done" : "queued",
		idempotencyKey: createHash("sha256").update(`${scope.sessionId}\n${contextPath}\n${nextCommands.join("\n")}`).digest("hex"),
		ledgerPath: memoryPath("compaction-resume-ledger.jsonl"),
		closure: {
			status: mode === "resume" ? "closed" : "open",
			closedAt: mode === "resume" ? timestamp : null,
			reason: mode === "resume" ? "resume context rebuilt from verified state" : "context pack awaiting resume",
			verifiedBy: "re_context",
		},
		compactionLedger: contextCompactionLedger(timestamp),
		activeLane: active?.name,
		gateSummary,
		missionSnapshot: mission ? formatMission(mission) : "no active mission",
		evidenceTail: truncateMiddle(buildEvidenceDigest(), 7000),
		memoryTail: truncateMiddle(buildMemoryDigest(), 6000),
		toolDigest: truncateMiddle(buildToolDigest(), 5000),
		completionAudit: truncateMiddle(formatCompletionAudit(), 5000),
		artifactIndex,
		repairQueue,
		commanderMergeBudget,
		workerScoreboard,
		swarmRetryQueue,
		autonomousBudget,
		dispatcherScoreDecay: autonomousBudget.scoreDecay,
		repeatedFailureDemotions: autonomousBudget.demotionRules,
		highScorePromotions: autonomousBudget.promotionRules,
		caseMemoryLanePlan: caseMemoryPlan,
		caseMemoryNextCommands,
		reflectionReuseRules,
		resumeBrief,
		nextCommands,
		sourceArtifacts: Array.from(
			new Set(
				[
					...artifactIndex.map((artifact) => artifact.path),
					swarmRetry.path,
					autonomousBudget.dispatcherBoardPath,
					autonomousBudget.promotionPlaybookPath,
					autonomousBudget.ledgerPath,
					autonomousBudget.formalPlaybookPath,
					existsSync(compactionResumeTelemetryPath()) ? compactionResumeTelemetryPath() : undefined,
				].filter(Boolean) as string[],
			),
		),
	};
	pack.contextSha256 = contextPackSha256(pack);
	return pack;
}

function formatContextPack(pack: ContextPackArtifact, path?: string): string {
	return [
		"context_pack:",
		path ? `context_artifact: ${path}` : undefined,
		`timestamp: ${pack.timestamp}`,
		`mode: ${pack.mode}`,
		`mission_id: ${pack.missionId ?? "none"}`,
		`route: ${pack.route ?? "none"}`,
		`target: ${pack.target ?? "<none>"}`,
		`contract_id: ${pack.contractId ?? "none"}`,
		`schema_version: ${pack.schemaVersion ?? "legacy"}`,
		`context_path: ${pack.contextPath ?? "none"}`,
		`context_sha256: ${pack.contextSha256 ?? "none"}`,
		`resumed_from_context_path: ${pack.resumedFromContextPath ?? "none"}`,
		`resume_queue_status: ${pack.resumeQueueStatus ?? "unknown"}`,
		`idempotency_key: ${pack.idempotencyKey ?? "none"}`,
		`active_lane: ${pack.activeLane ?? "none"}`,
		"closure:",
		`- status=${pack.closure?.status ?? "missing"}`,
		`- closed_at=${pack.closure?.closedAt ?? "none"}`,
		`- reason=${pack.closure?.reason ?? "missing"}`,
		`- verified_by=${pack.closure?.verifiedBy ?? "missing"}`,
		"exact_resume_verification:",
		...(pack.exactResumeVerification
			? [
					`- loaded_by=${pack.exactResumeVerification.loadedBy}`,
					`- source_path=${pack.exactResumeVerification.sourcePath ?? "none"}`,
					`- context_sha256=${pack.exactResumeVerification.contextSha256}`,
					`- artifact_hashes=${pack.exactResumeVerification.artifactHashes}`,
					`- scope=${pack.exactResumeVerification.scope}`,
					`- blocked=${pack.exactResumeVerification.blocked.join(" | ") || "none"}`,
					`- warnings=${pack.exactResumeVerification.warnings.join(" | ") || "none"}`,
				]
			: ["- none"]),
		"resume_brief:",
		...pack.resumeBrief.map((item) => `- ${item}`),
		"gate_summary:",
		...(pack.gateSummary.length ? pack.gateSummary.map((item) => `- ${item}`) : ["- none"]),
		"artifact_index:",
		...(pack.artifactIndex.length
			? pack.artifactIndex.map((item) => `- ${item.kind}: ${item.path} exists=${item.exists ?? "unknown"} sha256=${item.sha256 ?? "none"}`)
			: ["- none"]),
		"repair_queue:",
		...(pack.repairQueue.length ? pack.repairQueue.map((item) => `- ${item}`) : ["- none"]),
		"commander_merge_budget:",
		...(pack.commanderMergeBudget?.length ? pack.commanderMergeBudget.map((item) => `- ${item}`) : ["- none"]),
		"worker_scoreboard:",
		...(pack.workerScoreboard?.length ? pack.workerScoreboard.map((item) => `- ${item}`) : ["- none"]),
		"swarm_retry_queue:",
		...(pack.swarmRetryQueue?.length ? pack.swarmRetryQueue.map((item) => `- ${item}`) : ["- none"]),
		"autonomous_execution_budget:",
		...autonomousBudgetLines(pack.autonomousBudget).map((item) => `- ${item}`),
		"dispatcher_score_decay:",
		...(pack.dispatcherScoreDecay?.length ? pack.dispatcherScoreDecay.map((item) => `- ${item}`) : ["- none"]),
		"repeated_failure_demotions:",
		...(pack.repeatedFailureDemotions?.length
			? pack.repeatedFailureDemotions.map((item) => `- ${item}`)
			: ["- none"]),
		"high_score_promotions:",
		...(pack.highScorePromotions?.length ? pack.highScorePromotions.map((item) => `- ${item}`) : ["- none"]),
		"case_memory_lane_plan:",
		...(pack.caseMemoryLanePlan
			? caseMemoryLanePlanLines(pack.caseMemoryLanePlan).map((item) => `- ${item}`)
			: ["- none"]),
		"case_memory_next_commands:",
		...(pack.caseMemoryNextCommands.length ? pack.caseMemoryNextCommands.map((item) => `- ${item}`) : ["- none"]),
		"reflection_reuse_rules:",
		...(pack.reflectionReuseRules.length ? pack.reflectionReuseRules.map((item) => `- ${item}`) : ["- none"]),
		"next_operator_commands:",
		...(pack.nextCommands.length ? pack.nextCommands.map((item) => `- ${item}`) : ["- re_mission show"]),
		`next_context_command: ${pack.mode === "resume" ? "re_context pack" : "re_context resume"}`,
		"source_artifacts:",
		...(pack.sourceArtifacts.length ? pack.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeContextPackArtifact(pack: ContextPackArtifact): string {
	ensureReconStorage();
	const path = pack.contextPath ?? contextPackArtifactPathFor(pack);
	pack.contextPath = path;
	pack.contextSha256 = contextPackSha256(pack);
	writeFileSync(
		path,
		[
			"# Pi-RECON Context Pack Artifact",
			"",
			formatContextPack(pack, path),
			"",
			"## Mission snapshot",
			"",
			"```text",
			pack.missionSnapshot,
			"```",
			"",
			"## Evidence tail",
			"",
			"```text",
			pack.evidenceTail,
			"```",
			"",
			"## Memory tail",
			"",
			"```text",
			pack.memoryTail,
			"```",
			"",
			"## Completion audit",
			"",
			"```text",
			pack.completionAudit,
			"```",
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(pack, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	if (pack.compactionLedger) {
		appendText(
			pack.compactionLedger.path,
			`${JSON.stringify({
				ts: pack.timestamp,
				contractId: pack.contractId,
				contextPath: pack.contextPath,
				contextSha256: pack.contextSha256,
				idempotencyKey: pack.idempotencyKey,
				resumeQueueStatus: pack.resumeQueueStatus,
				prevHash: pack.compactionLedger.prevHash,
				entryHash: pack.compactionLedger.entryHash,
			})}\n`,
		);
	}
	appendEvidence({
		kind: "artifact",
		title: `context-pack-${pack.mode} ${pack.missionId ?? "no-mission"}`,
		fact: `Context pack captured ${pack.artifactIndex.length} artifact(s), ${pack.repairQueue.length} repair item(s), ${pack.nextCommands.length} next command(s), context_sha256=${pack.contextSha256 ?? "missing"}, exact_resume=${pack.exactResumeVerification?.contextSha256 ?? "none"}, swarm_retry_queue=${pack.swarmRetryQueue.length}, autonomous_budget=${pack.autonomousBudget.maxTurns}/${pack.autonomousBudget.maxDispatch}, score_decay=${pack.dispatcherScoreDecay.length}, demotions=${pack.repeatedFailureDemotions.length}, promotions=${pack.highScorePromotions.length}, case_memory_lane_plan=${pack.caseMemoryLanePlan?.action ?? "none"}`,
		command: `re_context ${pack.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "mission/evidence/memory resume context",
	});
	updateMissionGate("context_pack_ready", "done", path);
	return path;
}

function reconCompactionBullets(rows: string[], fallback = "none"): string[] {
	return rows.length ? rows.map((item) => `- ${item}`) : [`- ${fallback}`];
}

function buildReconCompactionDetails(contextPack: ContextPackArtifact, contextPath: string): ReconCompactionDetails {
	return {
		kind: "pi-recon-compaction",
		version: 1,
		contextPath,
		missionId: contextPack.missionId,
		route: contextPack.route,
		target: contextPack.target,
		activeLane: contextPack.activeLane,
		nextCommands: contextPack.nextCommands,
		sourceArtifacts: contextPack.sourceArtifacts,
		autonomousBudget: contextPack.autonomousBudget,
		checkpointEntryType: "pi-recon-compaction-checkpoint",
		resumeCommand: "re_context resume",
	};
}

function buildReconCompactionSummary(params: {
	event: ReconCompactionEventView;
	contextPack: ContextPackArtifact;
	contextPath: string;
}): string {
	const { event, contextPack, contextPath } = params;
	const targetSuffix = contextPack.target ? ` ${contextPack.target}` : "";
	const proofTarget = contextPack.target ?? "<target>";
	const resumeCommands = Array.from(
		new Set([
			"re_context resume",
			`re_operator plan${targetSuffix}`,
			`re_operator dispatch${targetSuffix} 1`,
			`re_proof_loop run ${proofTarget} 4 2`,
			...contextPack.nextCommands,
		]),
	).slice(0, 18);
	const memoryArtifacts = [
		`dispatcher_feedback_board: ${contextPack.autonomousBudget.dispatcherBoardPath ?? memoryPath("dispatcher-feedback-board.md")}`,
		`dispatcher_promotion_playbook: ${contextPack.autonomousBudget.promotionPlaybookPath ?? memoryPath("dispatcher-promotion-playbook.md")}`,
		`autonomous_budget_ledger: ${contextPack.autonomousBudget.ledgerPath ?? memoryPath("autonomous-budget-ledger.md")}`,
		`formal_playbook: ${contextPack.autonomousBudget.formalPlaybookPath ?? "none"}`,
		`knowledge_graph_index: ${memoryPath("knowledge-graph-index.md")}`,
	];
	return [
		"# Pi-RECON Compaction Summary",
		"",
		"kind: pi-recon-compaction",
		"",
		"## Resume contract",
		`- context_path: ${contextPath}`,
		...resumeCommands.map((command) => `- next: ${command}`),
		"",
		"## Compaction boundary",
		`- first_kept_entry_id: ${event.preparation.firstKeptEntryId}`,
		`- tokens_before: ${event.preparation.tokensBefore}`,
		`- branch_entries: ${event.branchEntries?.length ?? 0}`,
		`- summarized_messages: ${event.preparation.messagesToSummarize?.length ?? 0}`,
		`- turn_prefix_messages: ${event.preparation.turnPrefixMessages?.length ?? 0}`,
		`- split_turn: ${event.preparation.isSplitTurn ? "yes" : "no"}`,
		`- previous_summary: ${event.preparation.previousSummary ? "present" : "none"}`,
		`- custom_instructions: ${event.customInstructions ? truncateMiddle(event.customInstructions, 360) : "none"}`,
		"",
		"## Mission",
		`- mission_id: ${contextPack.missionId ?? "none"}`,
		`- route: ${contextPack.route ?? "unknown"}`,
		`- target: ${contextPack.target ?? "<none>"}`,
		`- active_lane: ${contextPack.activeLane ?? "none"}`,
		...reconCompactionBullets(contextPack.resumeBrief.slice(0, 16)),
		"",
		"## Gates",
		...reconCompactionBullets(contextPack.gateSummary.slice(0, 24)),
		"",
		"## Evidence / artifacts",
		...reconCompactionBullets(
			contextPack.artifactIndex.slice(0, 32).map((artifact) => `${artifact.kind}: ${artifact.path}`),
		),
		"",
		"## Operator state",
		`- repair_queue_items: ${contextPack.repairQueue.length}`,
		...reconCompactionBullets(contextPack.repairQueue.slice(0, 16)),
		`- swarm_retry_queue_items: ${contextPack.swarmRetryQueue.length}`,
		...reconCompactionBullets(contextPack.swarmRetryQueue.slice(0, 12)),
		`- commander_budget_items: ${contextPack.commanderMergeBudget.length}`,
		...reconCompactionBullets(contextPack.commanderMergeBudget.slice(0, 12)),
		"",
		"## Autonomous / dispatcher state",
		"autonomous_execution_budget:",
		...autonomousBudgetLines(contextPack.autonomousBudget)
			.slice(0, 18)
			.map((item) => `- ${item}`),
		"dispatcher_score_decay:",
		...reconCompactionBullets(contextPack.dispatcherScoreDecay.slice(0, 16)),
		"repeated_failure_demotions:",
		...reconCompactionBullets(contextPack.repeatedFailureDemotions.slice(0, 16)),
		"high_score_promotions:",
		...reconCompactionBullets(contextPack.highScorePromotions.slice(0, 16)),
		"",
		"## Case memory / worker routing",
		...(contextPack.caseMemoryLanePlan
			? caseMemoryLanePlanLines(contextPack.caseMemoryLanePlan).map((item) => `- ${item}`)
			: ["- none"]),
		...reconCompactionBullets(contextPack.caseMemoryNextCommands.slice(0, 12)),
		"",
		"## Memory / ledger",
		...memoryArtifacts.map((item) => `- ${item}`),
		"",
		"## Rules after resume",
		"1. Run `re_context resume` before answering from memory.",
		"2. Then run `re_operator plan` and one bounded `re_operator dispatch` from the recovered queue.",
		"3. If verifier/compiler/replayer/autofix reports partial or needs_repair, run `re_proof_loop run <target> 4 2`.",
		"4. Preserve Outcome → Key Evidence → Verification → Next Step and cite decisive artifact paths.",
	].join("\n");
}

function parseReconCompactionDetails(details: unknown): ReconCompactionDetails | undefined {
	if (!details || typeof details !== "object") return undefined;
	const record = details as Record<string, unknown>;
	if (record.kind !== "pi-recon-compaction") return undefined;
	if (typeof record.contextPath !== "string") return undefined;
	const nextCommands = Array.isArray(record.nextCommands)
		? record.nextCommands.filter((item): item is string => typeof item === "string")
		: [];
	const sourceArtifacts = Array.isArray(record.sourceArtifacts)
		? record.sourceArtifacts.filter((item): item is string => typeof item === "string")
		: [];
	return {
		kind: "pi-recon-compaction",
		version: typeof record.version === "number" ? record.version : 1,
		contextPath: record.contextPath,
		missionId: typeof record.missionId === "string" ? record.missionId : undefined,
		route: typeof record.route === "string" ? record.route : undefined,
		target: typeof record.target === "string" ? record.target : undefined,
		activeLane: typeof record.activeLane === "string" ? record.activeLane : undefined,
		nextCommands,
		sourceArtifacts,
		autonomousBudget: record.autonomousBudget as AutonomousExecutionBudget,
		checkpointEntryType: "pi-recon-compaction-checkpoint",
		resumeCommand: typeof record.resumeCommand === "string" ? record.resumeCommand : "re_context resume",
	};
}

function reconCompactionNextCommandsFromSummary(summary: string): string[] {
	return summary
		.split(/\r?\n/)
		.map((line) => /^-\s*next:\s*(.+)\s*$/i.exec(line)?.[1]?.trim())
		.filter((item): item is string => Boolean(item));
}

function contextPathFromReconCompactionSummary(summary: string): string | undefined {
	return /^-\s*context_path:\s*(.+)\s*$/im.exec(summary)?.[1]?.trim();
}

function buildReconCompactionResumeContract(params: {
	compactionEntry: ReconCompactionEntryView;
	fromExtension: boolean;
}): ReconCompactionResumeContract {
	const { compactionEntry, fromExtension } = params;
	const details = parseReconCompactionDetails(compactionEntry.details);
	const summary = compactionEntry.summary ?? "";
	const contextPath = details?.contextPath ?? contextPathFromReconCompactionSummary(summary);
	const nextCommands = Array.from(
		new Set([
			details?.resumeCommand ?? "re_context resume",
			...(details?.nextCommands ?? []),
			...reconCompactionNextCommandsFromSummary(summary),
		]),
	).slice(0, 24);
	const sourceArtifacts = Array.from(new Set(details?.sourceArtifacts ?? [])).slice(0, 40);
	const hasResume =
		/\bre_context\s+resume\b/i.test(summary) || nextCommands.some((item) => /re_context\s+resume/i.test(item));
	const hasOperator =
		/\bre_operator\s+(?:plan|dispatch)\b/i.test(summary) ||
		nextCommands.some((item) => /re_operator\s+(?:plan|dispatch)/i.test(item));
	const hasProofLoop =
		/\bre_proof_loop\s+run\b/i.test(summary) || nextCommands.some((item) => /re_proof_loop\s+run/i.test(item));
	const verified = Boolean(fromExtension && details && contextPath && hasResume && hasOperator && hasProofLoop);
	const resumeContract = [
		`context_path=${contextPath ?? "missing"}`,
		`resume=${details?.resumeCommand ?? "re_context resume"}`,
		"operator=re_operator plan -> re_operator dispatch 1",
		"proof=re_proof_loop run <target> 4 2 on partial/needs_repair",
		"report=Outcome -> Key Evidence -> Verification -> Next Step",
	];
	const verification = [
		`from_extension=${fromExtension}`,
		`details_kind=${details?.kind ?? "missing"}`,
		`context_path=${contextPath ?? "missing"}`,
		`has_resume=${hasResume}`,
		`has_operator=${hasOperator}`,
		`has_proof_loop=${hasProofLoop}`,
		`next_commands=${nextCommands.length}`,
		`source_artifacts=${sourceArtifacts.length}`,
		`verified=${verified}`,
	];
	return {
		kind: "pi-recon-compaction-resume-contract",
		version: 1,
		timestamp: new Date().toISOString(),
		fromExtension,
		verified,
		compactionEntryId: compactionEntry.id,
		firstKeptEntryId: compactionEntry.firstKeptEntryId,
		tokensBefore: compactionEntry.tokensBefore,
		compactionKind: details?.kind ?? "unknown",
		contextPath,
		resumeCommand: details?.resumeCommand ?? "re_context resume",
		nextCommands,
		sourceArtifacts,
		autonomousBudget: details?.autonomousBudget,
		resumeContract,
		verification,
		summaryHead: truncateMiddle(summary, 2400),
	};
}

function buildReconCompactionAutoResume(
	contract: ReconCompactionResumeContract,
	triggered: boolean,
	reason: string,
): ReconCompactionAutoResume {
	return {
		kind: "pi-recon-compaction-auto-resume",
		version: 1,
		timestamp: new Date().toISOString(),
		triggered,
		reason,
		compactionEntryId: contract.compactionEntryId,
		contextPath: contract.contextPath,
		resumeCommands: contract.nextCommands.slice(0, 8),
		contractVerified: contract.verified,
	};
}

function reconCompactionAutoResumePrompt(contract: ReconCompactionResumeContract): string {
	const commands = Array.from(
		new Set([
			"re_context resume",
			...contract.nextCommands.filter((command) =>
				/\bre_(?:context|operator|proof_loop|verifier|compiler|replayer|autofix|knowledge_graph)\b/i.test(command),
			),
		]),
	).slice(0, 10);
	return [
		"## Pi-RECON Auto Resume Trigger",
		"",
		"Compact finished and the Pi-RECON resume contract is verified. Resume the operation now; do not answer from stale pre-compact narrative.",
		"",
		"resume_contract:",
		...contract.resumeContract.map((item) => `- ${item}`),
		"",
		"verification:",
		...contract.verification.map((item) => `- ${item}`),
		"",
		"bounded_resume_commands:",
		...commands.map((command) => `- ${command}`),
		"",
		"execution_order:",
		"1. Run or inspect `re_context resume` first.",
		"2. Build the operator queue with `re_operator plan`.",
		"3. Dispatch only one bounded operator step.",
		"4. If proof is partial/needs_repair, run `re_proof_loop run <target> 4 2`.",
		"5. Return Outcome → Key Evidence → Verification → Next Step.",
		"",
		`context_path: ${contract.contextPath ?? "missing"}`,
	].join("\n");
}

function compactionResumeTelemetryPath(): string {
	return memoryPath("compaction-auto-resume-board.md");
}

function missionGateStatusLines(): string[] {
	const mission = readCurrentMission();
	return (
		mission?.gates.map(
			(gate) => `${gate.name}=${gate.status}${gate.note ? `:${truncateMiddle(gate.note, 160)}` : ""}`,
		) ?? ["mission=missing"]
	);
}

function normalizeReconCommand(command: string): string {
	return command.trim().replace(/^\//, "").replace(/^re-/i, "re_").replace(/\s+/g, " ");
}

function reconCommandMatches(expected: string, actual: string): boolean {
	const normalizedExpected = normalizeReconCommand(expected);
	const normalizedActual = normalizeReconCommand(actual);
	if (normalizedExpected === normalizedActual) return true;
	const wildcardPattern = escapeRegExp(normalizedExpected).replace(/<target>|<TARGET>|<URL>|<none>/g, ".+?");
	return new RegExp(`^${wildcardPattern}$`, "i").test(normalizedActual);
}

function formatReconCompactionResumeTelemetry(telemetry: ReconCompactionResumeTelemetry): string[] {
	return [
		`kind=${telemetry.kind} triggered=${telemetry.autoResumeTriggered} contract_verified=${telemetry.contractVerified} proof_loop_entered=${telemetry.proofLoopEntered} context_path=${telemetry.contextPath ?? "none"}`,
		...telemetry.commandStatus.map((row) =>
			[
				"compact_resume_command",
				`status=${row.status}`,
				`proof_loop=${row.enteredProofLoop}`,
				row.outputSha256 ? `output_sha256=${row.outputSha256}` : undefined,
				`command=${shellQuote(row.command)}`,
			]
				.filter(Boolean)
				.join(" "),
		),
		...telemetry.gateStatus.map((gate) => `compact_resume_gate ${gate}`),
	].slice(0, 80);
}

function writeReconCompactionResumeTelemetry(telemetry: ReconCompactionResumeTelemetry): string {
	ensureReconStorage();
	const path = compactionResumeTelemetryPath();
	writeFileSync(
		path,
		[
			"# Pi-RECON Compaction Auto Resume Board",
			"",
			`Updated: ${telemetry.timestamp}`,
			`Compaction entry: ${telemetry.compactionEntryId ?? "none"}`,
			`Context path: ${telemetry.contextPath ?? "none"}`,
			`Contract verified: ${telemetry.contractVerified}`,
			`Auto resume triggered: ${telemetry.autoResumeTriggered}`,
			`Proof loop entered: ${telemetry.proofLoopEntered}`,
			"",
			"## Telemetry",
			...formatReconCompactionResumeTelemetry(telemetry).map((item) => `- ${item}`),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(telemetry, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	updateMissionGate("compaction_auto_resume_telemetry_ready", "done", path);
	if (telemetry.proofLoopEntered) updateMissionGate("compaction_proof_resume_entered", "done", path);
	return path;
}

function parseReconCompactionResumeTelemetry(path: string): ReconCompactionResumeTelemetry | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		const parsed = JSON.parse(match[1]) as ReconCompactionResumeTelemetry;
		return parsed.kind === "pi-recon-compaction-resume-telemetry" ? parsed : undefined;
	} catch {
		return undefined;
	}
}

function latestReconCompactionResumeTelemetry(): {
	path: string;
	telemetry?: ReconCompactionResumeTelemetry;
	lines: string[];
} {
	const path = compactionResumeTelemetryPath();
	const telemetry = parseReconCompactionResumeTelemetry(path);
	return {
		path,
		telemetry,
		lines: telemetry
			? formatReconCompactionResumeTelemetry(telemetry)
			: interestingLines(readText(path), /compact_resume|proof_loop|re[-_]/i, 80),
	};
}

function compactResumeProofQueue(): string[] {
	return (
		latestReconCompactionResumeTelemetry()
			.telemetry?.commandStatus.filter((row) => row.status === "queued")
			.map((row) => row.command)
			.filter((command) => /^re[-_]/i.test(command)) ?? []
	).slice(0, 8);
}

function initialReconCompactionResumeTelemetry(
	contract: ReconCompactionResumeContract,
	autoResume: ReconCompactionAutoResume,
): ReconCompactionResumeTelemetry {
	return {
		kind: "pi-recon-compaction-resume-telemetry",
		version: 1,
		timestamp: new Date().toISOString(),
		compactionEntryId: contract.compactionEntryId,
		contextPath: contract.contextPath,
		contractVerified: contract.verified,
		autoResumeTriggered: autoResume.triggered,
		commandStatus: Array.from(
			new Set(autoResume.resumeCommands.length ? autoResume.resumeCommands : contract.nextCommands),
		)
			.slice(0, 12)
			.map((command) => ({
				command,
				status: "queued",
				enteredProofLoop: /^re[-_]proof[-_]loop\s+run\b/i.test(command),
			})),
		gateStatus: missionGateStatusLines(),
		proofLoopEntered: false,
		sourceArtifacts: Array.from(
			new Set([contract.contextPath, ...contract.sourceArtifacts].filter(Boolean) as string[]),
		).slice(0, 40),
	};
}

function updateReconCompactionTelemetryFromExecutions(
	executionsList: OperationExecution[],
	sourceArtifacts: string[] = [],
): ReconCompactionResumeTelemetry | undefined {
	const latest = latestReconCompactionResumeTelemetry();
	const current = latest.telemetry;
	if (!current) return undefined;
	const executions = new Map(executionsList.map((item) => [normalizeReconCommand(item.command), item]));
	const commandStatus = current.commandStatus.map((row) => {
		const execution =
			executions.get(normalizeReconCommand(row.command)) ??
			executionsList.find((item) => reconCommandMatches(row.command, item.command));
		if (!execution) return row;
		const enteredProofLoop =
			row.enteredProofLoop ||
			/^re[-_]proof[-_]loop\s+run\b/i.test(execution.command) ||
			/\bproof_loop:/i.test(execution.output);
		return {
			...row,
			status: execution.status === "blocked" ? ("blocked" as const) : ("done" as const),
			enteredProofLoop,
			outputSha256: createHash("sha256").update(execution.output).digest("hex"),
		};
	});
	const telemetry: ReconCompactionResumeTelemetry = {
		...current,
		timestamp: new Date().toISOString(),
		commandStatus,
		gateStatus: missionGateStatusLines(),
		proofLoopEntered: commandStatus.some((row) => row.enteredProofLoop),
		sourceArtifacts: Array.from(
			new Set([...current.sourceArtifacts, ...sourceArtifacts].filter(Boolean) as string[]),
		).slice(0, 40),
	};
	writeReconCompactionResumeTelemetry(telemetry);
	return telemetry;
}

function updateReconCompactionTelemetryFromOperator(
	operator: OperatorArtifact,
): ReconCompactionResumeTelemetry | undefined {
	return updateReconCompactionTelemetryFromExecutions(
		operator.executed,
		[operator.contextArtifact].filter(Boolean) as string[],
	);
}

function buildContextDigest(limit = 5000): string {
	const path = latestContextPackArtifactPath();
	if (!path) return "no context pack yet; call re_context pack after reflection/supervisor or before compaction.";
	return truncateMiddle(readText(path), limit);
}

function contextPackReferenceMatches(pack: ContextPackArtifact, path: string, ref: string): boolean {
	return [
		path,
		pack.contextPath,
		pack.contractId,
		pack.idempotencyKey,
		pack.compactionLedger?.entryHash,
		pack.compactionLedger?.prevHash,
	].some((item) => Boolean(item && item.includes(ref)));
}

function resolveContextPackPathByRef(ref?: string): { path?: string; loadedBy: ContextResumeVerification["loadedBy"] } {
	const trimmed = ref?.trim();
	if (trimmed) {
		const direct = [trimmed, join(process.cwd(), trimmed)].find((candidate) => existsSync(candidate));
		if (direct) return { path: direct, loadedBy: "contextPath" };
		const telemetry = latestReconCompactionResumeTelemetry().telemetry;
		if (
			telemetry?.contextPath &&
			(telemetry.compactionEntryId === trimmed || telemetry.contextPath.includes(trimmed) || trimmed.includes(telemetry.contextPath))
		)
			return { path: telemetry.contextPath, loadedBy: "compactionEntryId" };
		const ledgerRows = readText(memoryPath("compaction-resume-ledger.jsonl"))
			.split(/\r?\n/)
			.map((line) => {
				try {
					return JSON.parse(line) as { contextPath?: string; contractId?: string; idempotencyKey?: string; entryHash?: string };
				} catch {
					return undefined;
				}
			})
			.filter((row): row is { contextPath?: string; contractId?: string; idempotencyKey?: string; entryHash?: string } =>
				Boolean(row?.contextPath),
			)
			.reverse();
		for (const row of ledgerRows) {
			if ([row.contextPath, row.contractId, row.idempotencyKey, row.entryHash].some((item) => item?.includes(trimmed)))
				return { path: row.contextPath, loadedBy: "compactionEntryId" };
		}
		for (const path of recentMarkdownArtifacts(evidenceContextsDir(), 50)) {
			const pack = parseContextPackArtifact(path);
			if (pack && contextPackReferenceMatches(pack, path, trimmed)) return { path, loadedBy: "compactionEntryId" };
		}
		return { loadedBy: "missing" };
	}
	return { path: latestContextPackArtifactPath(), loadedBy: "latest" };
}

function verifyContextPackResume(
	pack: ContextPackArtifact | undefined,
	sourcePath: string | undefined,
	loadedBy: ContextResumeVerification["loadedBy"],
	target?: string,
	ref?: string,
): ContextResumeVerification {
	const blocked: string[] = [];
	const warnings: string[] = [];
	if (!pack || !sourcePath) {
		return { ref, sourcePath, loadedBy: "missing", contextSha256: "missing", artifactHashes: "missing", scope: "missing", blocked: ["context pack not found"], warnings };
	}
	const actualContextHash = contextPackSha256(pack);
	const contextSha256 =
		!pack.contextSha256 ? "missing" : pack.contextSha256 === actualContextHash ? "pass" : "drift";
	if (contextSha256 !== "pass") blocked.push(`contextSha256 ${contextSha256}`);
	let artifactHashes: ContextResumeVerification["artifactHashes"] = "pass";
	if (!pack.artifactHashes?.length) {
		artifactHashes = "missing";
		blocked.push("artifactHashes missing");
	} else {
		for (const artifact of pack.artifactHashes.filter((item) => item.required)) {
			if (!existsSync(artifact.path)) {
				artifactHashes = "drift";
				blocked.push(`artifact missing: ${artifact.path}`);
				continue;
			}
			const current = createHash("sha256").update(readFileSync(artifact.path)).digest("hex");
			if (artifact.sha256 && current !== artifact.sha256) {
				artifactHashes = "drift";
				blocked.push(`artifact hash drift: ${artifact.path}`);
			}
		}
	}
	let scope: ContextResumeVerification["scope"] = "pass";
	if (!pack.scope) {
		scope = "missing";
		warnings.push("scope missing");
	} else {
		if (target && pack.scope.target && pack.scope.target !== target) {
			scope = "mismatch";
			blocked.push(`target mismatch: ${pack.scope.target} != ${target}`);
		}
		if (pack.scope.workspaceRoot && pack.scope.workspaceRoot !== process.cwd()) {
			scope = "mismatch";
			blocked.push(`workspaceRoot mismatch: ${pack.scope.workspaceRoot} != ${process.cwd()}`);
		}
		const currentBranchId = contextBranchId();
		if (pack.scope.branchId && pack.scope.branchId !== currentBranchId) {
			scope = "mismatch";
			blocked.push(`branch mismatch: ${pack.scope.branchId} != ${currentBranchId}`);
		}
	}
	return { ref, sourcePath, loadedBy, contextSha256, artifactHashes, scope, blocked: Array.from(new Set(blocked)), warnings };
}

function buildExactResumeContextPack(ref: string, target?: string): ContextPackArtifact {
	const resolved = resolveContextPackPathByRef(ref);
	const source = resolved.path ? parseContextPackArtifact(resolved.path) : undefined;
	const verification = verifyContextPackResume(source, resolved.path, resolved.loadedBy, target, ref);
	if (!source) {
		const fallback = buildContextPack({ target, mode: "resume" });
		fallback.exactResumeVerification = verification;
		fallback.resumeQueueStatus = "blocked";
		fallback.closure = { status: "blocked", closedAt: new Date().toISOString(), reason: verification.blocked.join("; "), verifiedBy: "re_context exact resume" };
		return fallback;
	}
	const timestamp = new Date().toISOString();
	const pack: ContextPackArtifact = {
		...source,
		timestamp,
		mode: "resume",
		contextPath: contextPackArtifactPathFor({ timestamp, route: source.route, target: target ?? source.target, mode: "resume" }),
		resumedFromContextPath: resolved.path,
		exactResumeVerification: verification,
		resumeQueueStatus: verification.blocked.length ? "blocked" : "done",
		closure: {
			status: verification.blocked.length ? "blocked" : "closed",
			closedAt: timestamp,
			reason: verification.blocked.length ? verification.blocked.join("; ") : "exact context resume verified",
			verifiedBy: "re_context exact resume",
		},
		sourceArtifacts: Array.from(new Set([resolved.path, ...(source.sourceArtifacts ?? [])].filter(Boolean) as string[])).slice(0, 48),
	};
	pack.contextSha256 = contextPackSha256(pack);
	return pack;
}

function contextRefLooksExplicit(ref?: string): boolean {
	return Boolean(ref && (/(?:recon|\.pi)\/evidence\/contexts|\.md$|^\/|^\.\.?\/|context-pack\/|compaction/i.test(ref) || existsSync(ref) || existsSync(join(process.cwd(), ref))));
}

function buildContextOutput(action: "pack" | "show" | "resume" = "pack", options: { target?: string; contextRef?: string } = {}): string {
	if (action === "show") {
		const path = latestContextPackArtifactPath();
		if (!path) return "context_pack:\nstatus: missing\nnext: re_context pack";
		return truncateMiddle(readText(path), 18000);
	}
	const contextRef = options.contextRef ?? (action === "resume" && contextRefLooksExplicit(options.target) ? options.target : undefined);
	const pack =
		action === "resume" && contextRef
			? buildExactResumeContextPack(contextRef, options.target === contextRef ? undefined : options.target)
			: buildContextPack({ target: options.target, mode: action === "resume" ? "resume" : "pack" });
	const path = writeContextPackArtifact(pack);
	return formatContextPack(pack, path);
}

function latestDecisionCoreArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceDecisionsDir(), 1)[0];
}

function decisionEvidencePriority(): string[] {
	const ledger = readText(evidenceLedgerPath());
	const kinds: EvidenceKind[] = ["runtime", "traffic", "served_asset", "process_config", "artifact", "source", "note"];
	const lines = ledger.split(/\r?\n/);
	const counts = kinds.map((kind) => `${kind}: ${lines.filter((line) => line.includes(`— ${kind} —`)).length}`);
	const decisive = lines
		.filter((line) => /^## .+ — P[1-4] — /.test(line))
		.slice(-8)
		.map((line) => line.replace(/^##\s*/, ""));
	return [
		"priority_order: runtime/memory > traffic > served_asset > process_config > artifact > source > note",
		`ledger_counts: ${counts.join(", ")}`,
		...(decisive.length ? decisive.map((item) => `decisive: ${item}`) : ["decisive: none yet"]),
	];
}

function decisionToolPosture(mission: MissionState | undefined): string[] {
	const index = parseToolIndex();
	const recommended = mission
		? recommendedToolsForRoute(mission.route)
		: ["file", "sha256sum", "rg", "python3", "curl"].filter((tool) => bootstrapCatalogFor(tool));
	const missing = recommended.filter((tool) => !index.get(tool)?.present);
	const present = recommended.filter((tool) => index.get(tool)?.present);
	return [
		`tool_index: ${index.size ? `${index.size} indexed` : "empty; refresh required"}`,
		`recommended: ${recommended.join(", ") || "none"}`,
		`present: ${present.join(", ") || "none"}`,
		`missing: ${missing.join(", ") || "none"}`,
		missing.length
			? `tool_next: re_tool_index refresh -> re_bootstrap plan ${missing.slice(0, 8).join(" ")}`
			: "tool_next: use fallback/direct execution",
	];
}

function decisionArtifactPosture(): string[] {
	const artifacts = contextArtifactIndex();
	const byKind = new Map(artifacts.map((artifact) => [artifact.kind, artifact.path]));
	const required = [
		"map",
		"run",
		"attack_graph",
		"exploit_chain",
		"context",
		"operator",
		"verifier",
		"compiler",
		"replayer",
		"autofix",
		"proof_loop",
		"knowledge",
	];
	return required.map((kind) => `${kind}: ${byKind.get(kind) ? `ok ${byKind.get(kind)}` : "missing"}`);
}

function decisionGatePressure(mission: MissionState | undefined): string[] {
	if (!mission) return ["no mission: re_mission new <task>"];
	const ranks = new Map(
		[
			"execution_kernel_ready",
			"decision_core_ready",
			"tool_index_checked",
			"passive_map_done",
			"repro_commands_ready",
			"minimal_path_proven",
			"attack_graph_ready",
			"exploit_chain_ready",
			"operator_queue_ready",
			"verifier_matrix_ready",
			"compiler_ready",
			"replay_ready",
			"autofix_ready",
			"proof_loop_ready",
			"knowledge_graph_ready",
			"report_or_writeup_ready",
			"memory_or_evolution_written",
		].map((gate, index) => [gate, index + 1]),
	);
	return [...mission.gates]
		.sort((a, b) => (ranks.get(a.name) ?? 99) - (ranks.get(b.name) ?? 99) || a.name.localeCompare(b.name))
		.map((gate) => `${gate.name}: ${gate.status}${gate.note ? ` — ${truncateMiddle(gate.note, 160)}` : ""}`);
}

function decisionObjectiveStack(
	mission: MissionState | undefined,
	active: MissionLane | undefined,
	target?: string,
): string[] {
	if (!mission) {
		const mapped = target?.trim() || "<task-or-target>";
		return [
			`bootstrap mission for ${mapped}`,
			`route task: re_route ${mapped}`,
			`create blackboard: re_mission new ${mapped}`,
			`build execution kernel: re_kernel build ${mapped}`,
		];
	}
	const pending = mission.gates.filter((gate) => gate.status !== "done").map((gate) => gate.name);
	return [
		`route=${mission.route.domain}`,
		`task=${truncateMiddle(mission.task, 180)}`,
		`active_lane=${active?.name ?? "none"}`,
		`active_objective=${active?.objective ?? "select next lane"}`,
		`target=${target ?? mission.task}`,
		`pending_gates=${pending.slice(0, 16).join(",") || "none"}`,
		"primary_invariant=prove one end-to-end evidence path before broad expansion",
	];
}

function decisionRulesFor(
	mission: MissionState | undefined,
	active: MissionLane | undefined,
	target?: string,
): string[] {
	const mappedTarget = target?.trim() || mission?.task || "<target>";
	if (!mission)
		return [
			`no_mission -> re_mission new ${mappedTarget}`,
			`no_kernel -> re_kernel build ${mappedTarget}`,
			`no_map -> re_map ${mappedTarget} 2`,
		];
	const pending = new Set(mission.gates.filter((gate) => gate.status !== "done").map((gate) => gate.name));
	const lane = active?.name ?? "triage";
	const rules: string[] = [];
	if (pending.has("execution_kernel_ready")) rules.push(`execution_kernel_gap -> re_kernel build ${mappedTarget}`);
	if (pending.has("tool_index_checked")) rules.push("tool_posture_unknown -> re_tool_index refresh");
	if (pending.has("passive_map_done")) rules.push(`map_gap -> re_map ${mappedTarget} 2`);
	if (pending.has("repro_commands_ready")) rules.push(`command_pack_gap -> re_lane plan ${lane} ${mappedTarget}`);
	if (pending.has("minimal_path_proven")) rules.push(`proof_gap -> re_lane run ${lane} ${mappedTarget}`);
	if (pending.has("attack_graph_ready")) rules.push("graph_gap -> re_graph build");
	if (pending.has("exploit_chain_ready")) rules.push(`chain_gap -> re_chain plan ${mappedTarget}`);
	if (pending.has("context_pack_ready")) rules.push(`context_gap -> re_context pack ${mappedTarget}`);
	if (pending.has("operator_queue_ready")) rules.push(`operator_gap -> re_operator plan ${mappedTarget}`);
	if (pending.has("verifier_matrix_ready")) rules.push(`verification_gap -> re_verifier matrix ${mappedTarget}`);
	if (pending.has("compiler_ready")) rules.push(`compiler_gap -> re_compiler draft ${mappedTarget}`);
	if (pending.has("replay_ready")) rules.push(`replay_gap -> re_replayer run ${mappedTarget} 1`);
	if (pending.has("autofix_ready")) rules.push(`repair_gap -> re_autofix plan ${mappedTarget}`);
	if (pending.has("proof_loop_ready")) rules.push(`proof_loop_gap -> re_proof_loop run ${mappedTarget} 4`);
	if (pending.has("knowledge_graph_ready")) rules.push(`knowledge_gap -> re_knowledge_graph build ${mappedTarget}`);
	if (pending.has("report_or_writeup_ready")) rules.push("report_gap -> re_complete scaffold");
	if (rules.length === 0) rules.push("all_gates_green -> re_complete audit");
	return rules;
}

function decisionOperatorQueue(rules: string[]): string[] {
	const commands = rules
		.map((rule) => rule.split("->")[1]?.trim())
		.filter((command): command is string => Boolean(command));
	return Array.from(new Set([...commands, "re_complete audit"])).slice(0, 18);
}

function buildDecisionCore(
	options: { target?: string; mode?: DecisionCoreArtifact["mode"] } = {},
): DecisionCoreArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const active = mission ? activeLane(mission) : undefined;
	const target = options.target ?? mission?.task;
	const objectiveStack = decisionObjectiveStack(mission, active, target);
	const gatePressure = decisionGatePressure(mission);
	const evidencePriority = decisionEvidencePriority();
	const toolPosture = decisionToolPosture(mission);
	const artifactPosture = decisionArtifactPosture();
	const decisionRules = decisionRulesFor(mission, active, target);
	const operatorQueue = decisionOperatorQueue(decisionRules);
	const nextActions = operatorQueue.slice(0, 10);
	const sourceArtifacts = Array.from(
		new Set(
			[
				currentMissionPath(),
				evidenceLedgerPath(),
				toolIndexPath(),
				memoryPath("execution-kernel.md"),
				memoryPath("decision-core.md"),
				latestKernelArtifactPath(),
				latestContextPackArtifactPath(),
				latestOperatorArtifactPath(),
				latestVerifierArtifactPath(),
				latestCompilerArtifactPath(),
				latestReplayerArtifactPath(),
				latestAutofixArtifactPath(),
				latestProofLoopArtifactPath(),
				latestKnowledgeGraphArtifactPath(),
				...contextArtifactIndex().map((artifact) => artifact.path),
			].filter((path): path is string => Boolean(path && existsSync(path))),
		),
	).slice(0, 48);
	return {
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route: mission?.route.domain,
		target,
		mode: options.mode ?? "plan",
		activeLane: active?.name,
		objectiveStack,
		gatePressure,
		evidencePriority,
		toolPosture,
		artifactPosture,
		decisionRules,
		operatorQueue,
		executed: [],
		blocked: [],
		nextActions,
		stopConditions: [
			"stop_only_when: mission gates done or each remaining gate has evidence-backed blocker",
			"stop_only_when: verifier/compiler/replayer outputs are bound to artifacts or explicit gaps",
			"never_stop_on: missing target/tool/context without emitting a concrete closure command",
		],
		sourceArtifacts,
	};
}

function formatDecisionCore(decision: DecisionCoreArtifact, path?: string): string {
	return [
		"decision_core:",
		path ? `decision_artifact: ${path}` : undefined,
		`timestamp: ${decision.timestamp}`,
		`mode: ${decision.mode}`,
		`mission_id: ${decision.missionId ?? "none"}`,
		`route: ${decision.route ?? "none"}`,
		`target: ${decision.target ?? "<none>"}`,
		`active_lane: ${decision.activeLane ?? "none"}`,
		"objective_stack:",
		...(decision.objectiveStack.length ? decision.objectiveStack.map((item) => `- ${item}`) : ["- none"]),
		"gate_pressure:",
		...(decision.gatePressure.length ? decision.gatePressure.map((item) => `- ${item}`) : ["- none"]),
		"evidence_priority:",
		...(decision.evidencePriority.length ? decision.evidencePriority.map((item) => `- ${item}`) : ["- none"]),
		"tool_posture:",
		...(decision.toolPosture.length ? decision.toolPosture.map((item) => `- ${item}`) : ["- none"]),
		"artifact_posture:",
		...(decision.artifactPosture.length ? decision.artifactPosture.map((item) => `- ${item}`) : ["- none"]),
		"decision_rules:",
		...(decision.decisionRules.length ? decision.decisionRules.map((item) => `- ${item}`) : ["- none"]),
		"operator_queue:",
		...(decision.operatorQueue.length ? decision.operatorQueue.map((item) => `- ${item}`) : ["- re_mission show"]),
		`executed_steps: ${decision.executed.length}`,
		...(decision.executed.length
			? decision.executed.map(
					(item) =>
						`- ${item.stepId} [${item.status}] ${item.command} :: ${truncateMiddle(item.output.replace(/\s+/g, " "), 260)}`,
				)
			: []),
		"blocked:",
		...(decision.blocked.length ? decision.blocked.map((item) => `- ${item}`) : ["- none"]),
		"decision_next_actions:",
		...(decision.nextActions.length ? decision.nextActions.map((item) => `- ${item}`) : ["- re_mission show"]),
		"stop_conditions:",
		...(decision.stopConditions.length ? decision.stopConditions.map((item) => `- ${item}`) : ["- none"]),
		`operator_next_command: ${decision.operatorQueue[0] ?? "re_mission show"}`,
		`next_decision_command: ${
			decision.mode === "run"
				? "re_verifier matrix"
				: decision.mode === "tick"
					? `re_decision_core run ${decision.target ?? "<target>"} 1`
					: `re_decision_core tick ${decision.target ?? "<target>"}`
		}`,
		"source_artifacts:",
		...(decision.sourceArtifacts.length ? decision.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeDecisionCoreArtifact(decision: DecisionCoreArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceDecisionsDir(),
		`${decision.timestamp.replace(/[:.]/g, "-")}-${slug(decision.route ?? "decision")}-${decision.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Decision Core Artifact",
			"",
			formatDecisionCore(decision, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(decision, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	writeFileSync(
		memoryPath("decision-core.md"),
		[
			"# Pi-RECON Decision Core",
			"",
			`Updated: ${decision.timestamp}`,
			`Artifact: ${path}`,
			"",
			"## Objective stack",
			...decision.objectiveStack.map((item) => `- ${item}`),
			"",
			"## Gate pressure",
			...decision.gatePressure.map((item) => `- ${item}`),
			"",
			"## Operator queue",
			...decision.operatorQueue.map((item) => `- ${item}`),
			"",
			"## Executed",
			...(decision.executed.length
				? decision.executed.map((item) => `- ${item.stepId} [${item.status}] ${item.command}`)
				: ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `decision-core-${decision.mode} ${decision.missionId ?? "no-mission"}`,
		fact: `Decision core ${decision.mode}: objectives=${decision.objectiveStack.length}, rules=${decision.decisionRules.length}, queue=${decision.operatorQueue.length}`,
		command: `re_decision_core ${decision.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "mission gates/evidence/tool posture decision core",
	});
	updateMissionGate("decision_core_ready", "done", path);
	return path;
}

function decisionOperatorSteps(decision: DecisionCoreArtifact): OperatorStep[] {
	const seen = new Set<string>();
	const steps: OperatorStep[] = [];
	for (const raw of decision.operatorQueue) {
		const concrete = operatorCommandConcrete(raw, decision.target);
		const command = concrete.command.trim();
		if (!command || seen.has(command)) continue;
		seen.add(command);
		steps.push({
			id: `decision:${steps.length + 1}:${slug(command).slice(0, 30)}`,
			command,
			status: concrete.blocked ? "blocked" : "ready",
			priority: operatorStepPriority(command),
			reason: concrete.blocked,
			sourceArtifacts: decision.sourceArtifacts,
		});
	}
	return steps.sort((a, b) => a.priority - b.priority || a.id.localeCompare(b.id));
}

async function runDecisionCore(
	pi: ExtensionAPI,
	options: { target?: string; maxSteps?: number } = {},
): Promise<string> {
	const decision = buildDecisionCore({ target: options.target, mode: "run" });
	const maxSteps = Math.max(1, Math.min(10, Math.floor(options.maxSteps ?? 1)));
	const steps = decisionOperatorSteps(decision);
	for (const step of steps.filter((item) => item.status === "ready").slice(0, maxSteps)) {
		const result = await executeOperatorStep(pi, step, decision.target);
		decision.executed.push(result);
		if (result.status === "blocked") decision.blocked.push(`${step.id}: ${result.output}`);
	}
	for (const step of steps.filter((item) => item.status === "blocked")) {
		decision.blocked.push(`${step.id}: ${step.reason ?? step.command}`);
	}
	decision.nextActions = [
		...steps
			.filter((step) => step.status === "ready")
			.slice(decision.executed.length, decision.executed.length + 8)
			.map((step) => `re_decision_core run ${decision.target ?? "<target>"} 1 # ${step.id}`),
		"re_verifier matrix",
		"re_complete audit",
	];
	const path = writeDecisionCoreArtifact(decision);
	return formatDecisionCore(decision, path);
}

function buildDecisionCoreOutput(action: "plan" | "show" | "tick" = "plan", options: { target?: string } = {}): string {
	if (action === "show") {
		const path = latestDecisionCoreArtifactPath();
		if (!path) return "decision_core:\nstatus: missing\nnext: re_decision_core plan <target>";
		return truncateMiddle(readText(path), 20000);
	}
	const decision = buildDecisionCore({ target: options.target, mode: action === "tick" ? "tick" : "plan" });
	const path = writeDecisionCoreArtifact(decision);
	return formatDecisionCore(decision, path);
}

function latestOperatorArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceOperatorsDir(), 1)[0];
}

function parseContextPackArtifact(path: string): ContextPackArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as ContextPackArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildContextPack(options: { target?: string } = {}): { context: ContextPackArtifact; path: string } {
	const latest = !options.target ? latestContextPackArtifactPath() : undefined;
	if (latest) {
		const context = parseContextPackArtifact(latest);
		if (context) return { context, path: latest };
	}
	const context = buildContextPack({ target: options.target, mode: "pack" });
	const path = writeContextPackArtifact(context);
	return { context, path };
}

function operatorCommandConcrete(command: string, target?: string): { command: string; blocked?: string } {
	const normalized = command.trim().replace(/^\//, "");
	if (/<target>|<TARGET>|<URL>|<none>/i.test(normalized)) {
		if (!target) return { command: normalized, blocked: "target placeholder is unresolved" };
		return { command: normalized.replace(/<target>|<TARGET>|<URL>|<none>/gi, target) };
	}
	return { command: normalized };
}

function isCommanderRuntimeCommand(command: string): boolean {
	return /^re[-_](swarm|supervisor|context|operator|proof[-_]loop|verifier|compiler|replayer|autofix)\b/i.test(
		command.trim().replace(/^\//, ""),
	);
}

function commanderBudgetValue(lines: string[] | undefined, key: string, fallback: number): number {
	const line = (lines ?? []).find((item) => item.startsWith(`${key}=`));
	const value = line ? Number(line.replace(/^.+?=/, "")) : Number.NaN;
	return Number.isFinite(value) ? value : fallback;
}

function commanderPolicyFromContext(context: ContextPackArtifact): string[] {
	const commanderQueueDepth = (context.repairQueue ?? []).filter(isCommanderRuntimeCommand).length;
	const inheritedBudget = context.commanderMergeBudget ?? [];
	return Array.from(
		new Set([
			...inheritedBudget,
			`context_commander_queue=${commanderQueueDepth}`,
			`worker_score_rows=${context.workerScoreboard?.length ?? 0}`,
			`swarm_retry_queue=${context.swarmRetryQueue?.length ?? 0}`,
			`case_memory_lane_plan=${context.caseMemoryLanePlan?.action ?? "none"}`,
			`case_memory_next_commands=${context.caseMemoryNextCommands?.length ?? 0}`,
			"retry_scope=commander-runtime-only",
			"stop_rule=halt dispatch when failure_budget is exhausted",
		]),
	).slice(0, 20);
}

function operatorStepPriority(command: string): number {
	if (/^re[-_]tool|^re[-_]bootstrap/i.test(command)) return 10;
	if (/^re[-_]decision[-_]core/i.test(command)) return 12;
	if (/^re[-_]autopilot|^re[-_]auto\b/i.test(command)) return 18;
	if (/^re[-_]map|^re[-_]lane\s+plan/i.test(command)) return 20;
	if (/^re[-_]lane\s+(run|run-auto)|^re[-_]graph/i.test(command)) return 30;
	if (/^re[-_]campaign|^re[-_]operation|^re[-_]delegate/i.test(command)) return 40;
	if (/^re[-_]swarm/i.test(command)) return 42;
	if (/^re[-_]supervisor|^re[-_]reflect/i.test(command)) return 50;
	if (/^re[-_]context|^re[-_]memory/i.test(command)) return 60;
	if (/^re[-_]verifier/i.test(command)) return 65;
	if (/^re[-_]proof[-_]loop/i.test(command)) return 66;
	if (/^re[-_]compiler/i.test(command)) return 68;
	if (/^re[-_]replayer/i.test(command)) return 69;
	if (
		/^re[-_]web[-_]authz[-_]state|^re[-_]exploit[-_]lab|^re[-_]mobile[-_]runtime|^re[-_]native[-_]runtime/i.test(
			command,
		)
	)
		return 69.3;
	if (/^re[-_]autofix/i.test(command)) return 69.5;
	if (/^re[-_]knowledge/i.test(command)) return 69.7;
	if (/^re[-_]complete/i.test(command)) return 70;
	return 90;
}

function operatorFeedbackCategory(row: string): string {
	return /\bcategory=([A-Za-z0-9_-]+)/i.exec(row)?.[1] ?? "unknown";
}

function operatorFeedbackPriority(category: string): number {
	if (/missing_tool_or_dependency/i.test(category)) return 5;
	if (/unresolved_target/i.test(category)) return 6;
	if (/runtime_failure|dispatcher_gap/i.test(category)) return 7;
	if (/failure_budget_exhausted/i.test(category)) return 8;
	if (/swarm_retry_queue|worker_retry_blocked/i.test(category)) return 9;
	if (/replay_or_exploit_candidate/i.test(category)) return 11;
	if (/worker_retry_progress/i.test(category)) return 15;
	if (/strong_evidence/i.test(category)) return 18;
	return 25;
}

function operatorFeedbackFallbackCommands(row: string, target?: string): string[] {
	const category = operatorFeedbackCategory(row);
	const targetRef = target ?? "<target>";
	const primary = operatorFeedbackNextCommands([row]);
	const fallback = /missing_tool_or_dependency/i.test(category)
		? ["re_tool_index refresh", ...primary]
		: /unresolved_target/i.test(category)
			? [`re_context pack ${targetRef}`, `re_map ${targetRef} 2`]
			: /dispatcher_gap/i.test(category)
				? [...primary, `re_operator escalate ${targetRef}`, `re_context pack ${targetRef}`]
				: /runtime_failure/i.test(category)
					? [...primary, `re_replayer run ${targetRef} 1`, `re_proof_loop run ${targetRef} 4 2`]
					: /failure_budget_exhausted/i.test(category)
						? [
								`re_proof_loop run ${targetRef} 4 2`,
								`re_context pack ${targetRef}`,
								`re_operator dispatch ${targetRef} 1`,
							]
						: /swarm_retry_queue|worker_retry_blocked|worker_retry_progress/i.test(category)
							? [
									...primary,
									`re_swarm merge`,
									`re_supervisor repair ${targetRef}`,
									`re_context pack ${targetRef}`,
								]
							: /replay_or_exploit_candidate/i.test(category)
								? [...primary, `re_replayer run ${targetRef} 1`, `re_exploit_lab run ${targetRef} 3 60000`]
								: /strong_evidence/i.test(category)
									? ["re_verifier matrix", "re_compiler draft"]
									: primary;
	return Array.from(
		new Set(
			fallback
				.flatMap(splitRetryNextCommands)
				.map((command) => operatorCommandConcrete(command, target).command)
				.filter((command) => /^re[-_]/i.test(command)),
		),
	).slice(0, 8);
}

function operatorFeedbackDispatchPlan(rows: string[], target?: string): string[] {
	return rows
		.map((row) => {
			const category = operatorFeedbackCategory(row);
			const fallback = operatorFeedbackFallbackCommands(row, target);
			const primary = operatorFeedbackNextCommands([row])[0] ?? fallback[0] ?? "re_operator dispatch";
			return [
				"dispatcher_feedback_priority",
				`category=${category}`,
				`priority=${operatorFeedbackPriority(category)}`,
				`primary=${shellQuote(operatorCommandConcrete(primary, target).command)}`,
				`fallback=${shellQuote(fallback.join(" && ") || "none")}`,
				`evidence=${shellQuote(truncateMiddle(row, 220))}`,
			].join(" ");
		})
		.sort((a, b) => {
			const left = Number(/\bpriority=(\d+)/.exec(a)?.[1] ?? 99);
			const right = Number(/\bpriority=(\d+)/.exec(b)?.[1] ?? 99);
			return left - right || a.localeCompare(b);
		})
		.slice(0, 24);
}

function operatorFeedbackDispatcherCommands(rows: string[], target?: string): string[] {
	return Array.from(
		new Set([
			...operatorFeedbackNextCommands(rows),
			...rows.flatMap((row) => operatorFeedbackFallbackCommands(row, target)),
		]),
	)
		.map((command) => operatorCommandConcrete(command, target).command)
		.filter((command) => /^re[-_]/i.test(command))
		.slice(0, 20);
}

function dispatcherFeedbackExecutionStatus(
	command: string,
	executions: OperationExecution[],
): "passed" | "failed" | "queued" {
	const normalized = command.trim().replace(/^\//, "");
	const execution = executions.find((item) => item.command.trim().replace(/^\//, "") === normalized);
	if (!execution) return "queued";
	return execution.status === "blocked" ? "failed" : "passed";
}

function dispatcherFeedbackScore(command: string, status: "passed" | "failed" | "queued", category: string): number {
	const base = status === "passed" ? 82 : status === "failed" ? 25 : 50;
	const categoryBoost = Math.max(0, 20 - operatorFeedbackPriority(category));
	const commandBoost = /^re[-_](?:verifier|compiler|knowledge)/i.test(command)
		? 3
		: /^re[-_](?:proof[-_]loop|replayer|exploit[-_]lab|autofix|swarm|supervisor)/i.test(command)
			? 6
			: 0;
	return Math.max(0, Math.min(100, base + categoryBoost + commandBoost));
}

function dispatcherFeedbackScoreboard(operator: {
	operatorFeedback?: string[];
	executed: OperationExecution[];
	target?: string;
}): string[] {
	return (operator.operatorFeedback ?? [])
		.flatMap((row) => {
			const category = operatorFeedbackCategory(row);
			const commands = operatorFeedbackFallbackCommands(row, operator.target);
			const candidates = commands.length ? commands : operatorFeedbackDispatcherCommands([row], operator.target);
			return candidates.slice(0, 5).map((command) => {
				const status = dispatcherFeedbackExecutionStatus(command, operator.executed);
				const score = dispatcherFeedbackScore(command, status, category);
				return [
					"dispatcher_score",
					`category=${category}`,
					`status=${status}`,
					`score=${score}`,
					`command=${shellQuote(command)}`,
					`evidence=${shellQuote(truncateMiddle(row, 220))}`,
				].join(" ");
			});
		})
		.filter((row, index, rows) => rows.indexOf(row) === index)
		.sort((a, b) => {
			const leftStatus = /\bstatus=passed\b/.test(a) ? 0 : /\bstatus=queued\b/.test(a) ? 1 : 2;
			const rightStatus = /\bstatus=passed\b/.test(b) ? 0 : /\bstatus=queued\b/.test(b) ? 1 : 2;
			const leftScore = Number(/\bscore=(\d+)/.exec(a)?.[1] ?? 0);
			const rightScore = Number(/\bscore=(\d+)/.exec(b)?.[1] ?? 0);
			return leftStatus - rightStatus || rightScore - leftScore || a.localeCompare(b);
		})
		.slice(0, 40);
}

function dispatcherLearningHints(scoreboard: string[], target?: string): string[] {
	const targetRef = target ?? "<target>";
	const hints = scoreboard.map((row) => {
		const status = /\bstatus=([a-z]+)/i.exec(row)?.[1] ?? "queued";
		const score = Number(/\bscore=(\d+)/.exec(row)?.[1] ?? 0);
		const category = /\bcategory=([A-Za-z0-9_-]+)/.exec(row)?.[1] ?? "unknown";
		const command = /\bcommand=(?:'([^']+)'|"([^"]+)"|(\S+))/i.exec(row);
		const commandText = command?.[1] ?? command?.[2] ?? command?.[3] ?? "re_operator dispatch";
		if (status === "passed" && score >= 80)
			return `promote_dispatcher category=${category} score=${score} command=${commandText} -> re_knowledge_graph build ${targetRef}`;
		if (status === "failed")
			return `demote_dispatcher category=${category} score=${score} command=${commandText} -> re_autofix plan ${targetRef}; re_context pack ${targetRef}`;
		return `retry_dispatcher category=${category} score=${score} command=${commandText} -> re_operator dispatch ${targetRef} 1`;
	});
	return Array.from(new Set(hints)).slice(0, 24);
}

function latestDispatcherFeedbackBoard(): { path: string; lines: string[]; hints: string[] } {
	const path = memoryPath("dispatcher-feedback-board.md");
	const text = readText(path);
	return {
		path,
		lines: interestingLines(text, /dispatcher_score|promote_dispatcher|demote_dispatcher|retry_dispatcher/i, 80),
		hints: interestingLines(text, /promote_dispatcher|demote_dispatcher|retry_dispatcher|re[-_]/i, 40),
	};
}

function writeDispatcherFeedbackBoard(operator: OperatorArtifact, artifactPath: string): string {
	const boardPath = memoryPath("dispatcher-feedback-board.md");
	const scoreboard = operator.dispatcherFeedbackScoreboard ?? [];
	const hints = operator.dispatcherLearningHints ?? [];
	const budget = autonomousExecutionBudget(operator.target, scoreboard);
	writeFileSync(
		boardPath,
		[
			"# Pi-RECON Dispatcher Feedback Board",
			"",
			`Updated: ${operator.timestamp}`,
			`Operator artifact: ${artifactPath}`,
			`Target: ${operator.target ?? "<none>"}`,
			`Mode: ${operator.mode}`,
			"",
			"## Scoreboard",
			...(scoreboard.length ? scoreboard.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Learning hints",
			...(hints.length ? hints.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Autonomous execution budget",
			...autonomousBudgetLines(budget).map((item) => `- ${item}`),
			"",
			"## Score decay",
			...(budget.scoreDecay.length ? budget.scoreDecay.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Repeated failure demotions",
			...(budget.demotionRules.length ? budget.demotionRules.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## High-score promotions",
			...(budget.promotionRules.length ? budget.promotionRules.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Fallback plan",
			...((operator.dispatcherFallbackPlan ?? []).length
				? (operator.dispatcherFallbackPlan ?? []).map((item) => `- ${item}`)
				: ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	writeDispatcherPromotionPlaybook({
		target: operator.target,
		timestamp: operator.timestamp,
		artifactPath,
		scoreboard,
		learningHints: hints,
	});
	return boardPath;
}

function operatorVerificationLines(
	context: ContextPackArtifact,
	contextArtifact: string | undefined,
	steps: OperatorStep[],
): string[] {
	const mission = readCurrentMission();
	const artifactChecks = context.artifactIndex.map(
		(item) => `${item.kind}: ${existsSync(item.path) ? "ok" : "missing"} ${item.path}`,
	);
	const gateChecks = mission?.gates.map((gate) => `${gate.name}: ${gate.status}`) ?? ["mission: missing"];
	const ready = steps.filter((step) => step.status === "ready").length;
	const blocked = steps.filter((step) => step.status === "blocked").length;
	return [
		`context_artifact: ${contextArtifact && existsSync(contextArtifact) ? "ok" : "missing"} ${contextArtifact ?? "none"}`,
		`operator_steps: ready=${ready} blocked=${blocked} total=${steps.length}`,
		...gateChecks,
		...artifactChecks.slice(0, 16),
	];
}

function operatorEscalationQueue(steps: OperatorStep[], pendingGates: string[]): string[] {
	const queue = [
		...steps
			.filter((step) => step.status === "blocked")
			.map((step) => `repair blocked ${step.id}: ${step.reason ?? step.command}`),
		...pendingGates.slice(0, 12).map((gate) => `close gate: ${gate}`),
	];
	if (pendingGates.includes("tool_index_checked")) queue.push("re_tool_index refresh");
	if (pendingGates.includes("passive_map_done")) queue.push("re_map <target> 2");
	if (pendingGates.includes("supervisor_review_ready")) queue.push("re_supervisor review");
	if (pendingGates.includes("reflection_memory_ready")) queue.push("re_reflect write");
	if (pendingGates.includes("context_pack_ready")) queue.push("re_context pack");
	queue.push("re_operator verify");
	return Array.from(new Set(queue)).slice(0, 24);
}

function buildOperator(options: { target?: string; mode?: OperatorArtifact["mode"] } = {}): OperatorArtifact {
	ensureReconStorage();
	const { context, path: contextArtifact } = latestOrBuildContextPack(options);
	const target = options.target ?? context.target;
	const feedback = latestOperatorFeedback(target);
	const compactResume = latestReconCompactionResumeTelemetry();
	const compactResumeTelemetry = compactResume.lines;
	const compactResumeQueue = (compactResume.telemetry?.commandStatus ?? [])
		.filter((row) => row.status === "queued")
		.map((row) => row.command)
		.filter((command) => /^re[-_]/i.test(command));
	const dispatcherCommands = operatorFeedbackDispatcherCommands(feedback.rows, target);
	const dispatcherFallbackPlan = operatorFeedbackDispatchPlan(feedback.rows, target);
	const commanderPolicy = Array.from(
		new Set([
			...commanderPolicyFromContext(context),
			`compact_resume_queue=${compactResumeQueue.length}`,
			`compact_resume_telemetry=${compactResumeTelemetry.length}`,
			`operator_feedback_queue=${dispatcherCommands.length}`,
			`operator_feedback_rows=${feedback.rows.length}`,
			`dispatcher_fallback_plan=${dispatcherFallbackPlan.length}`,
			"feedback_priority=missing_tool→target→runtime→budget→swarm→exploit→evidence",
		]),
	).slice(0, 28);
	const seen = new Set<string>();
	const steps: OperatorStep[] = [];
	const addStep = (raw: string, sourceArtifacts: string[] = context.sourceArtifacts) => {
		const concrete = operatorCommandConcrete(raw, target);
		const command = concrete.command.trim();
		if (!command || seen.has(command)) return;
		seen.add(command);
		steps.push({
			id: `operator:${steps.length + 1}:${slug(command).slice(0, 30)}`,
			command,
			status: concrete.blocked ? "blocked" : "ready",
			priority: operatorStepPriority(command),
			reason: concrete.blocked,
			sourceArtifacts,
		});
	};
	for (const command of compactResumeQueue) addStep(command, [compactResume.path]);
	for (const command of dispatcherCommands) addStep(command, feedback.sourceArtifacts);
	for (const command of context.nextCommands) addStep(command);
	if (steps.length === 0) {
		addStep("re_context resume");
		addStep("re_complete audit");
	}
	const sorted = [...steps].sort((a, b) => a.priority - b.priority || a.id.localeCompare(b.id));
	const pendingGates =
		readCurrentMission()
			?.gates.filter((gate) => gate.status !== "done")
			.map((gate) => gate.name) ?? [];
	const verification = operatorVerificationLines(context, contextArtifact, steps);
	const escalationQueue = operatorEscalationQueue(steps, pendingGates);
	const dispatcherFeedbackScoreboardRows = dispatcherFeedbackScoreboard({
		operatorFeedback: feedback.rows,
		executed: [],
		target,
	});
	const dispatcherLearning = dispatcherLearningHints(dispatcherFeedbackScoreboardRows, target);
	const autonomousBudget = autonomousExecutionBudget(target, dispatcherFeedbackScoreboardRows);
	return {
		timestamp: new Date().toISOString(),
		missionId: context.missionId,
		route: context.route,
		target,
		mode: options.mode ?? "plan",
		contextArtifact,
		steps: sorted,
		executed: [],
		commanderPolicy: Array.from(
			new Set([
				...commanderPolicy,
				`max_turns=${autonomousBudget.maxTurns}`,
				`max_dispatch=${autonomousBudget.maxDispatch}`,
				`max_proof_loops=${autonomousBudget.maxProofLoops}`,
				`retry_limit_per_worker=${autonomousBudget.maxWorkerRetries}`,
				`failure_budget=${Math.max(1, Math.min(autonomousBudget.maxDispatch, autonomousBudget.maxWorkerRetries))}`,
				`autonomous_budget=max_turns:${autonomousBudget.maxTurns},max_dispatch:${autonomousBudget.maxDispatch},max_proof_loops:${autonomousBudget.maxProofLoops},max_worker_retries:${autonomousBudget.maxWorkerRetries}`,
				`score_decay=${autonomousBudget.scoreDecay.length}; demotions=${autonomousBudget.demotionRules.length}; promotions=${autonomousBudget.promotionRules.length}`,
			]),
		).slice(0, 34),
		commanderDispatchReport: [],
		caseMemoryLanePlan: context.caseMemoryLanePlan,
		caseMemoryDispatchReport: caseMemoryLanePlanLines(context.caseMemoryLanePlan),
		operatorFeedback: feedback.rows,
		operatorFeedbackQueue: dispatcherCommands,
		dispatcherFallbackPlan,
		dispatcherFeedbackScoreboard: dispatcherFeedbackScoreboardRows,
		dispatcherLearningHints: dispatcherLearning,
		autonomousBudget,
		dispatcherScoreDecay: autonomousBudget.scoreDecay,
		repeatedFailureDemotions: autonomousBudget.demotionRules,
		highScorePromotions: autonomousBudget.promotionRules,
		compactResumeTelemetry,
		compactResumeQueue,
		verification,
		escalationQueue,
		nextActions: Array.from(
			new Set([
				...autonomousBudget.nextActions,
				...sorted
					.filter((step) => step.status === "ready")
					.slice(0, 8)
					.map((step) => `re_operator dispatch ${target ?? "<target>"} 1 # ${step.id}`),
			]),
		).slice(0, 12),
		sourceArtifacts: Array.from(
			new Set(
				[
					contextArtifact,
					autonomousBudget.dispatcherBoardPath,
					autonomousBudget.promotionPlaybookPath,
					compactResume.path,
					...context.sourceArtifacts,
					...feedback.sourceArtifacts,
				].filter(Boolean) as string[],
			),
		).slice(0, 40),
	};
}

function formatOperator(operator: OperatorArtifact, path?: string): string {
	return [
		"operator_queue:",
		path ? `operator_artifact: ${path}` : undefined,
		`timestamp: ${operator.timestamp}`,
		`mode: ${operator.mode}`,
		`mission_id: ${operator.missionId ?? "none"}`,
		`route: ${operator.route ?? "none"}`,
		`target: ${operator.target ?? "<none>"}`,
		`context_artifact: ${operator.contextArtifact ?? "none"}`,
		"dispatcher_policy:",
		"- priority: bootstrap/tool-index → map/plan → runtime/graph → campaign/operation/delegate → supervisor/reflect → context/memory → verifier/compiler → replayer/autofix → knowledge-graph → completion",
		"- feedback_priority: operator_feedback_queue is promoted ahead of context commands; fallback plan reroutes missing tools, unresolved targets, runtime failure, swarm retry, and exploit/replay candidates",
		"- bounded_dispatch: default max=1, hard max=10, unsupported commands become escalation items",
		"commander_runtime_policy:",
		...(operator.commanderPolicy.length ? operator.commanderPolicy.map((item) => `- ${item}`) : ["- none"]),
		"compact_resume_telemetry:",
		...((operator.compactResumeTelemetry ?? []).length
			? (operator.compactResumeTelemetry ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"compact_resume_queue:",
		...((operator.compactResumeQueue ?? []).length
			? (operator.compactResumeQueue ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"operator_feedback:",
		...((operator.operatorFeedback ?? []).length
			? (operator.operatorFeedback ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"operator_feedback_queue:",
		...((operator.operatorFeedbackQueue ?? []).length
			? (operator.operatorFeedbackQueue ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"dispatcher_fallback_plan:",
		...((operator.dispatcherFallbackPlan ?? []).length
			? (operator.dispatcherFallbackPlan ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"dispatcher_feedback_scoreboard:",
		...((operator.dispatcherFeedbackScoreboard ?? []).length
			? (operator.dispatcherFeedbackScoreboard ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"dispatcher_learning_hints:",
		...((operator.dispatcherLearningHints ?? []).length
			? (operator.dispatcherLearningHints ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"autonomous_execution_budget:",
		...autonomousBudgetLines(operator.autonomousBudget).map((item) => `- ${item}`),
		"dispatcher_score_decay:",
		...((operator.dispatcherScoreDecay ?? []).length
			? (operator.dispatcherScoreDecay ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"repeated_failure_demotions:",
		...((operator.repeatedFailureDemotions ?? []).length
			? (operator.repeatedFailureDemotions ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"high_score_promotions:",
		...((operator.highScorePromotions ?? []).length
			? (operator.highScorePromotions ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"steps:",
		...(operator.steps.length
			? operator.steps.map(
					(step) =>
						`- ${step.id} [${step.status}] p=${step.priority} command=${step.command}${step.reason ? ` reason=${step.reason}` : ""}`,
				)
			: ["- none"]),
		`executed_steps: ${operator.executed.length}`,
		...(operator.executed.length
			? operator.executed.map(
					(item) =>
						`- ${item.stepId} [${item.status}] ${item.command} :: ${truncateMiddle(item.output.replace(/\s+/g, " "), 260)}`,
				)
			: []),
		"commander_dispatch_report:",
		...(operator.commanderDispatchReport.length
			? operator.commanderDispatchReport.map((item) => `- ${item}`)
			: ["- none"]),
		"case_memory_lane_plan:",
		...(operator.caseMemoryLanePlan
			? caseMemoryLanePlanLines(operator.caseMemoryLanePlan).map((item) => `- ${item}`)
			: ["- none"]),
		"case_memory_dispatch_report:",
		...(operator.caseMemoryDispatchReport.length
			? operator.caseMemoryDispatchReport.map((item) => `- ${item}`)
			: ["- none"]),
		"verification_matrix:",
		...(operator.verification.length ? operator.verification.map((item) => `- ${item}`) : ["- none"]),
		"escalation_queue:",
		...(operator.escalationQueue.length ? operator.escalationQueue.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(operator.nextActions.length ? operator.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_operator_command: ${operator.mode === "dispatch" ? "re_operator verify" : `re_operator dispatch ${operator.target ?? "<target>"} 1`}`,
		"source_artifacts:",
		...(operator.sourceArtifacts.length ? operator.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeOperatorArtifact(operator: OperatorArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceOperatorsDir(),
		`${operator.timestamp.replace(/[:.]/g, "-")}-${slug(operator.route ?? "operator")}-${operator.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Operator Artifact",
			"",
			formatOperator(operator, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(operator, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	const dispatcherBoard = writeDispatcherFeedbackBoard(operator, path);
	appendEvidence({
		kind: "artifact",
		title: `operator-${operator.mode} ${operator.missionId ?? "no-mission"}`,
		fact: `Operator queue ${operator.mode}: ${operator.steps.length} step(s), ${operator.executed.length} executed, ${operator.escalationQueue.length} escalation item(s), commander_policy=${operator.commanderPolicy.length}, commander_dispatch=${operator.commanderDispatchReport.length}, compact_resume_queue=${(operator.compactResumeQueue ?? []).length}, compact_resume_telemetry=${(operator.compactResumeTelemetry ?? []).length}, operator_feedback=${(operator.operatorFeedback ?? []).length}, operator_feedback_queue=${(operator.operatorFeedbackQueue ?? []).length}, dispatcher_fallback_plan=${(operator.dispatcherFallbackPlan ?? []).length}, dispatcher_feedback_scoreboard=${(operator.dispatcherFeedbackScoreboard ?? []).length}, dispatcher_learning_hints=${(operator.dispatcherLearningHints ?? []).length}, autonomous_budget=${operator.autonomousBudget?.maxTurns ?? "none"}/${operator.autonomousBudget?.maxDispatch ?? "none"}, score_decay=${(operator.dispatcherScoreDecay ?? []).length}, demotions=${(operator.repeatedFailureDemotions ?? []).length}, promotions=${(operator.highScorePromotions ?? []).length}, case_memory_lane_plan=${operator.caseMemoryLanePlan?.action ?? "none"}`,
		command: `re_operator ${operator.mode}`,
		path,
		verify: `cat ${path} && cat ${dispatcherBoard}`,
		confidence: "context-pack/operator dispatcher",
	});
	updateMissionGate("operator_queue_ready", "done", path);
	appendRuntimeFailureRepairFromOperator(operator, path);
	return path;
}

function operationStepFromOperator(step: OperatorStep): OperationStep {
	return {
		id: step.id,
		phase: "operator",
		command: step.command.replace(/^re-/i, "re_"),
		status: step.status,
		reason: step.reason,
		sourceArtifacts: step.sourceArtifacts,
	};
}

async function executeOperatorStep(pi: ExtensionAPI, step: OperatorStep, target?: string): Promise<OperationExecution> {
	const command = step.command.trim().replace(/^\//, "");
	const done = (output: string): OperationExecution => ({ stepId: step.id, command, status: "done", output });
	const blocked = (output: string): OperationExecution => ({ stepId: step.id, command, status: "blocked", output });
	if (step.status === "blocked") return blocked(step.reason ?? "operator step is blocked");
	const missionMatch = /^re[-_]mission(?:\s+(show|new|gate))?(?:\s+(.+))?$/i.exec(command);
	if (missionMatch) {
		const action = (missionMatch[1] as "show" | "new" | "gate" | undefined) ?? "show";
		const rest = missionMatch[2]?.trim();
		if (action === "new") {
			const task = rest || target || "security task";
			return done(formatMission(writeCurrentMission(createMission(task, routeReconTask(task)))));
		}
		if (action === "gate") {
			const [gate = "manual_gate", status = "done", ...noteParts] = (rest ?? "").split(/\s+/).filter(Boolean);
			const normalizedStatus = ["pending", "done", "blocked"].includes(status)
				? (status as MissionGateStatus)
				: "done";
			return done(formatMission(updateMissionGate(gate, normalizedStatus, noteParts.join(" "))));
		}
		return done(buildMissionDigest());
	}
	const kernelMatch = /^re[-_]kernel(?:\s+(build|show|audit))?(?:\s+(.+))?$/i.exec(command);
	if (kernelMatch)
		return done(
			buildKernelOutput((kernelMatch[1] as "build" | "show" | "audit") ?? "build", {
				target: kernelMatch[2]?.trim() || target,
			}),
		);
	const contextMatch = /^re[-_]context\s+(pack|show|resume)?(?:\s+(.+))?$/i.exec(command);
	if (contextMatch)
		return done(
			buildContextOutput((contextMatch[1] as "pack" | "show" | "resume") ?? "pack", {
				target: contextMatch[2]?.trim() || target,
			}),
		);
	const autopilotMatch = /^re[-_](?:autopilot|auto)\s+(plan|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (autopilotMatch) {
		const action = (autopilotMatch[1] as "plan" | "run") ?? "run";
		const autoTarget = autopilotMatch[2]?.trim() || target;
		const maxAutoSteps = autopilotMatch[3] ? Number(autopilotMatch[3]) : undefined;
		return done(await runAutopilot(pi, { action, target: autoTarget, maxAutoSteps }));
	}
	const reflectMatch = /^re[-_]reflect\s+(plan|show|write)?(?:\s+(.+))?$/i.exec(command);
	if (reflectMatch)
		return done(
			buildReflectOutput((reflectMatch[1] as "plan" | "show" | "write") ?? "plan", {
				target: reflectMatch[2]?.trim() || target,
			}),
		);
	const supervisorMatch = /^re[-_]supervisor\s+(review|show|repair)?(?:\s+(.+))?$/i.exec(command);
	if (supervisorMatch)
		return done(
			buildSupervisorOutput((supervisorMatch[1] as "review" | "show" | "repair") ?? "review", {
				target: supervisorMatch[2]?.trim() || target,
			}),
		);
	const operationMatch = /^re[-_]operation\s+(plan|next|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (operationMatch) {
		const action = (operationMatch[1] as "plan" | "next" | "show" | "run") ?? "next";
		const opTarget = operationMatch[2]?.trim() || target;
		const maxSteps = operationMatch[3] ? Number(operationMatch[3]) : 1;
		return done(
			action === "run"
				? await runOperationQueue(pi, { target: opTarget, maxSteps })
				: buildOperationOutput(action, { target: opTarget }),
		);
	}
	const operatorMatch = /^re[-_]operator(?:\s+(plan|show|dispatch|verify|escalate))?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(
		command,
	);
	if (operatorMatch) {
		const action = (operatorMatch[1] as "plan" | "show" | "dispatch" | "verify" | "escalate") ?? "plan";
		const opTarget = operatorMatch[2]?.trim() || target;
		const maxSteps = operatorMatch[3] ? Number(operatorMatch[3]) : 1;
		return done(
			action === "dispatch"
				? await dispatchOperatorQueue(pi, { target: opTarget, maxSteps })
				: buildOperatorOutput(action, { target: opTarget }),
		);
	}
	const delegateMatch = /^re[-_]delegate\s+(plan|show|merge)?(?:\s+(.+))?$/i.exec(command);
	if (delegateMatch)
		return done(
			buildDelegateOutput((delegateMatch[1] as "plan" | "show" | "merge") ?? "plan", {
				target: delegateMatch[2]?.trim() || target,
			}),
		);
	const swarmMatch = /^re[-_]swarm\s+(plan|show|run|merge)?(?:\s+(.+?))?(?:\s+(\d+))?(?:\s+(\d+))?$/i.exec(command);
	if (swarmMatch) {
		const action = (swarmMatch[1] as "plan" | "show" | "run" | "merge") ?? "plan";
		const swarmTarget = swarmMatch[2]?.trim() || target;
		const maxWorkers = swarmMatch[3] ? Number(swarmMatch[3]) : undefined;
		const maxCommands = swarmMatch[4] ? Number(swarmMatch[4]) : undefined;
		return done(
			action === "run"
				? await runSwarm(pi, { target: swarmTarget, maxWorkers, maxCommands })
				: buildSwarmOutput(action, { target: swarmTarget }),
		);
	}
	const verifierMatch = /^re[-_]verifier\s+(check|show|matrix)?(?:\s+(.+))?$/i.exec(command);
	if (verifierMatch)
		return done(
			buildVerifierOutput((verifierMatch[1] as "check" | "show" | "matrix") ?? "check", {
				target: verifierMatch[2]?.trim() || target,
			}),
		);
	const compilerMatch = /^re[-_]compiler\s+(draft|show|final)?(?:\s+(.+))?$/i.exec(command);
	if (compilerMatch)
		return done(
			buildCompilerOutput((compilerMatch[1] as "draft" | "show" | "final") ?? "draft", {
				target: compilerMatch[2]?.trim() || target,
			}),
		);
	const webAuthzStateMatch = /^re[-_]web[-_]authz[-_]state\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(
		command,
	);
	if (webAuthzStateMatch) {
		const action = (webAuthzStateMatch[1] as "plan" | "show" | "run") ?? "plan";
		const authzTarget = webAuthzStateMatch[2]?.trim() || target;
		const timeoutMs = webAuthzStateMatch[3] ? Number(webAuthzStateMatch[3]) : undefined;
		return done(
			action === "run"
				? await runWebAuthzState(pi, { target: authzTarget, timeoutMs })
				: buildWebAuthzStateOutput(action, { target: authzTarget, timeoutMs }),
		);
	}
	const mobileRuntimeMatch =
		/^re[-_]mobile[-_]runtime\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+([A-Za-z][\w]*(?:\.[A-Za-z][\w]*){1,}))?(?:\s+(\d+))?$/i.exec(
			command,
		);
	if (mobileRuntimeMatch) {
		const action = (mobileRuntimeMatch[1] as "plan" | "show" | "run") ?? "plan";
		const mobileTarget = mobileRuntimeMatch[2]?.trim() || target;
		const packageName = mobileRuntimeMatch[3]?.trim();
		const timeoutMs = mobileRuntimeMatch[4] ? Number(mobileRuntimeMatch[4]) : undefined;
		return done(
			action === "run"
				? await runMobileRuntime(pi, { target: mobileTarget, packageName, timeoutMs })
				: buildMobileRuntimeOutput(action, { target: mobileTarget, packageName, timeoutMs }),
		);
	}
	const nativeRuntimeMatch = /^re[-_]native[-_]runtime\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (nativeRuntimeMatch) {
		const action = (nativeRuntimeMatch[1] as "plan" | "show" | "run") ?? "plan";
		const nativeTarget = nativeRuntimeMatch[2]?.trim() || target;
		const timeoutMs = nativeRuntimeMatch[3] ? Number(nativeRuntimeMatch[3]) : undefined;
		return done(
			action === "run"
				? await runNativeRuntime(pi, { target: nativeTarget, timeoutMs })
				: buildNativeRuntimeOutput(action, { target: nativeTarget, timeoutMs }),
		);
	}
	const exploitLabMatch =
		/^re[-_]exploit[-_]lab\s+(plan|show|run|bundle)?(?:\s+(.+?))?(?:\s+(\d+))?(?:\s+(\d+))?$/i.exec(command);
	if (exploitLabMatch) {
		const action = (exploitLabMatch[1] as "plan" | "show" | "run" | "bundle") ?? "plan";
		const labTarget = exploitLabMatch[2]?.trim() || target;
		const runs = exploitLabMatch[3] ? Number(exploitLabMatch[3]) : undefined;
		const timeoutMs = exploitLabMatch[4] ? Number(exploitLabMatch[4]) : undefined;
		return done(
			action === "run"
				? await runExploitLab(pi, { target: labTarget, runs, timeoutMs })
				: buildExploitLabOutput(action, { target: labTarget, runs, timeoutMs }),
		);
	}
	const replayerMatch = /^re[-_]replayer\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (replayerMatch) {
		const action = (replayerMatch[1] as "plan" | "show" | "run") ?? "plan";
		const replayTarget = replayerMatch[2]?.trim() || target;
		const maxSteps = replayerMatch[3] ? Number(replayerMatch[3]) : undefined;
		return done(
			action === "run"
				? await runReplayer(pi, { target: replayTarget, maxSteps })
				: buildReplayerOutput(action, { target: replayTarget }),
		);
	}
	const autofixMatch = /^re[-_]autofix\s+(plan|show|apply)?(?:\s+(.+))?$/i.exec(command);
	if (autofixMatch)
		return done(
			buildAutofixOutput((autofixMatch[1] as "plan" | "show" | "apply") ?? "plan", {
				target: autofixMatch[2]?.trim() || target,
			}),
		);
	const proofLoopMatch = /^re[-_]proof[-_]loop\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?(?:\s+(\d+))?$/i.exec(
		command,
	);
	if (proofLoopMatch) {
		const action = (proofLoopMatch[1] as "plan" | "show" | "run") ?? "plan";
		const loopTarget = proofLoopMatch[2]?.trim() || target;
		const maxSteps = proofLoopMatch[3] ? Number(proofLoopMatch[3]) : undefined;
		const replaySteps = proofLoopMatch[4] ? Number(proofLoopMatch[4]) : undefined;
		return done(
			action === "run"
				? await runProofLoop(pi, { target: loopTarget, maxSteps, replaySteps })
				: buildProofLoopOutput(action, { target: loopTarget, maxSteps, replaySteps }),
		);
	}
	const knowledgeMatch = /^re[-_]knowledge(?:[-_]graph)?\s+(build|show|query)?(?:\s+(.+))?$/i.exec(command);
	if (knowledgeMatch)
		return done(
			buildKnowledgeGraphOutput((knowledgeMatch[1] as "build" | "show" | "query") ?? "build", {
				target,
				query: knowledgeMatch[2]?.trim(),
			}),
		);
	if (/^re[-_]memory\s+playbooks$/i.test(command)) return done(formatPlaybookMaintenance(maintainPlaybooks()));
	if (/^re[-_]memory\s+prune-playbooks$/i.test(command))
		return done(formatPlaybookMaintenance(maintainPlaybooks({ archive: true })));
	const operationResult = await executeOperationStep(pi, operationStepFromOperator(step), target);
	return operationResult.status === "blocked" && /unsupported operation command/.test(operationResult.output)
		? blocked(`unsupported operator command: ${command}`)
		: operationResult;
}

async function dispatchOperatorQueue(
	pi: ExtensionAPI,
	options: { target?: string; maxSteps?: number } = {},
): Promise<string> {
	const operator = buildOperator({ target: options.target, mode: "dispatch" });
	const requestedMaxSteps = Math.max(1, Math.min(10, Math.floor(options.maxSteps ?? 1)));
	const policyMaxDispatch = commanderBudgetValue(operator.commanderPolicy, "max_dispatch", requestedMaxSteps);
	const maxSteps = Math.max(1, Math.min(10, requestedMaxSteps, policyMaxDispatch));
	const failureBudget = commanderBudgetValue(operator.commanderPolicy, "failure_budget", maxSteps);
	const retryLimit = commanderBudgetValue(operator.commanderPolicy, "retry_limit_per_worker", 1);
	let commanderFailures = 0;
	for (const step of operator.steps.filter((item) => item.status === "ready").slice(0, maxSteps)) {
		const result = await executeOperatorStep(pi, step, operator.target);
		operator.executed.push(result);
		step.status = result.status === "blocked" ? "blocked" : "done";
		step.reason = result.status === "blocked" ? result.output : step.reason;
		const commanderRuntime = isCommanderRuntimeCommand(step.command);
		if (commanderRuntime && result.status === "blocked") commanderFailures += 1;
		operator.commanderDispatchReport.push(
			`${step.id} commander=${commanderRuntime ? "yes" : "no"} status=${result.status} failures=${commanderFailures}/${failureBudget} retry_limit=${retryLimit} command=${step.command}`,
		);
		if (/^re[-_](?:autopilot|auto)\b/i.test(step.command) || /case_memory_lane_plan/i.test(result.output)) {
			const lines = interestingLines(
				result.output,
				/case_memory_lane_plan|case_memory_migrations|target_lane|added_lane|skipped_lane|action:\s*(?:reprioritized|added|skipped|none)/i,
				16,
			);
			operator.caseMemoryDispatchReport.push(
				`${step.id} status=${result.status} command=${step.command}`,
				...(lines.length ? lines : ["case_memory_lane_plan: no parsed output lines"]),
			);
		}
		if (commanderRuntime && commanderFailures >= failureBudget) {
			operator.commanderDispatchReport.push(`failure_budget_exhausted=${failureBudget}; stop_dispatch=true`);
			break;
		}
	}
	const pendingGates =
		readCurrentMission()
			?.gates.filter((gate) => gate.status !== "done")
			.map((gate) => gate.name) ?? [];
	const runtimeFeedback = classifyOperatorFeedback(operator, undefined, operator.target);
	operator.operatorFeedback = Array.from(new Set([...(operator.operatorFeedback ?? []), ...runtimeFeedback])).slice(
		0,
		64,
	);
	operator.operatorFeedbackQueue = operatorFeedbackDispatcherCommands(operator.operatorFeedback, operator.target);
	operator.dispatcherFallbackPlan = operatorFeedbackDispatchPlan(operator.operatorFeedback, operator.target);
	operator.dispatcherFeedbackScoreboard = dispatcherFeedbackScoreboard(operator);
	operator.dispatcherLearningHints = dispatcherLearningHints(operator.dispatcherFeedbackScoreboard, operator.target);
	operator.autonomousBudget = autonomousExecutionBudget(operator.target, operator.dispatcherFeedbackScoreboard);
	operator.dispatcherScoreDecay = operator.autonomousBudget.scoreDecay;
	operator.repeatedFailureDemotions = operator.autonomousBudget.demotionRules;
	operator.highScorePromotions = operator.autonomousBudget.promotionRules;
	const compactTelemetry = updateReconCompactionTelemetryFromOperator(operator);
	if (compactTelemetry) {
		operator.compactResumeTelemetry = formatReconCompactionResumeTelemetry(compactTelemetry);
		operator.compactResumeQueue = compactTelemetry.commandStatus
			.filter((row) => row.status === "queued")
			.map((row) => row.command)
			.slice(0, 12);
		operator.commanderDispatchReport.push(
			`compact_resume_runtime queue=${operator.compactResumeQueue.length} proof_loop_entered=${compactTelemetry.proofLoopEntered} telemetry=${compactionResumeTelemetryPath()}`,
		);
	}
	if (operator.operatorFeedback.length) {
		operator.commanderDispatchReport.push(
			`operator_feedback_runtime rows=${operator.operatorFeedback.length} queue=${operator.operatorFeedbackQueue.length} dispatcher_fallback_plan=${operator.dispatcherFallbackPlan.length} dispatcher_feedback_scoreboard=${operator.dispatcherFeedbackScoreboard.length} dispatcher_learning_hints=${operator.dispatcherLearningHints.length} autonomous_budget=${operator.autonomousBudget.maxTurns}/${operator.autonomousBudget.maxDispatch} score_decay=${operator.dispatcherScoreDecay.length} demotions=${operator.repeatedFailureDemotions.length} promotions=${operator.highScorePromotions.length}`,
		);
	}
	operator.escalationQueue = operatorEscalationQueue(operator.steps, pendingGates);
	const retryCommands = operator.steps
		.filter((step) => step.status === "blocked" && isCommanderRuntimeCommand(step.command))
		.slice(0, retryLimit)
		.map((step) => step.command);
	operator.nextActions = operator.steps
		.filter((step) => step.status === "ready")
		.slice(0, 8)
		.map((step) => `re_operator dispatch ${operator.target ?? "<target>"} 1 # ${step.id}`);
	operator.nextActions = Array.from(
		new Set([
			...operator.operatorFeedbackQueue,
			...retryCommands,
			...(operator.autonomousBudget?.nextActions ?? []),
			...operator.nextActions,
		]),
	).slice(0, 12);
	const path = writeOperatorArtifact(operator);
	return formatOperator(operator, path);
}

function buildOperatorOutput(
	action: "plan" | "show" | "verify" | "escalate" = "plan",
	options: { target?: string } = {},
): string {
	if (action === "show") {
		const path = latestOperatorArtifactPath();
		if (!path) return "operator_queue:\nstatus: missing\nnext: re_operator plan";
		return truncateMiddle(readText(path), 18000);
	}
	const operator = buildOperator({
		target: options.target,
		mode: action === "verify" || action === "escalate" ? action : "plan",
	});
	if (action === "escalate") operator.nextActions = operator.escalationQueue;
	const path = writeOperatorArtifact(operator);
	return formatOperator(operator, path);
}

function latestVerifierArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceVerifiersDir(), 1)[0];
}

function parseOperatorArtifact(path: string): OperatorArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as OperatorArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildOperator(options: { target?: string } = {}): { operator: OperatorArtifact; path: string } {
	const latest = !options.target ? latestOperatorArtifactPath() : undefined;
	if (latest) {
		const operator = parseOperatorArtifact(latest);
		if (operator) return { operator, path: latest };
	}
	const operator = buildOperator({ target: options.target, mode: "verify" });
	const path = writeOperatorArtifact(operator);
	return { operator, path };
}

function operatorFeedbackToolHint(text: string, command: string): string | undefined {
	const commandNotFound =
		/(?:command not found|not found|No such file or directory|cannot stat|ModuleNotFoundError|ImportError)[:\s]+([A-Za-z0-9_.+:-]+)/i.exec(
			text,
		)?.[1];
	const raw = commandNotFound ?? bootstrapToolFromCommand(command);
	if (!raw) return undefined;
	return raw
		.replace(/^['"]|['"]$/g, "")
		.split(/[/:]/)
		.pop();
}

function operatorFeedbackRow(params: {
	category: string;
	execution?: OperationExecution;
	command?: string;
	status?: string;
	next: string;
	evidence: string;
	operatorArtifact?: string;
}): string {
	const command = params.execution?.command ?? params.command ?? "none";
	const status = params.execution?.status ?? params.status ?? "unknown";
	const step = params.execution?.stepId ? ` step=${params.execution.stepId}` : "";
	return [
		`category=${params.category}`,
		`status=${status}`,
		step.trim(),
		`command=${shellQuote(truncateMiddle(command, 180))}`,
		`next=${params.next}`,
		`evidence=${shellQuote(truncateMiddle(params.evidence, 260))}`,
		params.operatorArtifact ? `source=${params.operatorArtifact}` : undefined,
	]
		.filter(Boolean)
		.join(" ");
}

function classifyOperatorFeedback(operator: OperatorArtifact, operatorArtifact?: string, target?: string): string[] {
	const rows: string[] = [];
	const targetRef = target ?? operator.target ?? "<target>";
	for (const execution of operator.executed) {
		const text = `${execution.command}\n${execution.output}`;
		const evidence = execution.output.replace(/\s+/g, " ");
		if (/target placeholder|unresolved target|<target>|<TARGET>|<URL>/i.test(text)) {
			rows.push(
				operatorFeedbackRow({
					category: "unresolved_target",
					execution,
					next: `re_context pack ${targetRef}`,
					evidence,
					operatorArtifact,
				}),
			);
			continue;
		}
		if (/unsupported operation command|internal Pi-RECON command/i.test(text)) {
			rows.push(
				operatorFeedbackRow({
					category: "dispatcher_gap",
					execution,
					next: `re_operator escalate ${targetRef}`,
					evidence,
					operatorArtifact,
				}),
			);
			continue;
		}
		if (
			/command not found|No such file|cannot stat|ModuleNotFoundError|ImportError|not found|cannot access/i.test(
				text,
			)
		) {
			const tool = operatorFeedbackToolHint(text, execution.command) ?? "tool";
			rows.push(
				operatorFeedbackRow({
					category: "missing_tool_or_dependency",
					execution,
					next: `re_bootstrap plan ${tool}`,
					evidence,
					operatorArtifact,
				}),
			);
			continue;
		}
		if (/retry_queue|swarm_retry_queue|execution_audit|coverage_matrix|re_swarm run|worker=/i.test(text)) {
			rows.push(
				operatorFeedbackRow({
					category: execution.status === "blocked" ? "worker_retry_blocked" : "worker_retry_progress",
					execution,
					next: `re_swarm run ${targetRef} 1 1`,
					evidence,
					operatorArtifact,
				}),
			);
			continue;
		}
		if (/exit=\s*(?:[1-9]|\d{2,})|failed|error|killed=true|blocked/i.test(text) || execution.status === "blocked") {
			rows.push(
				operatorFeedbackRow({
					category: "runtime_failure",
					execution,
					next: `re_autofix plan ${targetRef}`,
					evidence,
					operatorArtifact,
				}),
			);
			continue;
		}
		if (/stdout_sha256|stderr_sha256|replay_matrix|exploit_lab|PoC|poc|payload|crash|offset|RIP|EIP/i.test(text)) {
			rows.push(
				operatorFeedbackRow({
					category: "replay_or_exploit_candidate",
					execution,
					next: /exploit|poc|payload|crash|offset|RIP|EIP/i.test(text)
						? `re_exploit_lab run ${targetRef} 3 60000`
						: `re_replayer run ${targetRef} 1`,
					evidence,
					operatorArtifact,
				}),
			);
			continue;
		}
		if (/artifact|path:|verify:|hash|anchor|gate|proof|verifier_matrix|compiler_report/i.test(text)) {
			rows.push(
				operatorFeedbackRow({
					category: "strong_evidence",
					execution,
					next: "re_verifier matrix",
					evidence,
					operatorArtifact,
				}),
			);
		}
	}
	for (const line of operator.commanderDispatchReport) {
		if (/failure_budget_exhausted|stop_dispatch=true/i.test(line)) {
			rows.push(
				operatorFeedbackRow({
					category: "failure_budget_exhausted",
					command: "commander_dispatch_report",
					status: "blocked",
					next: `re_proof_loop run ${targetRef} 4 2`,
					evidence: line,
					operatorArtifact,
				}),
			);
		}
	}
	const swarmRetry = latestSwarmRetryQueue(target ?? operator.target);
	for (const row of swarmRetry.rows.slice(0, 8)) {
		rows.push(
			operatorFeedbackRow({
				category: "swarm_retry_queue",
				command: "swarm_retry_queue",
				status: "queued",
				next: swarmRetry.commands[0] ?? `re_swarm run ${targetRef} 1 1`,
				evidence: row,
				operatorArtifact,
			}),
		);
	}
	return Array.from(new Set(rows)).slice(0, 40);
}

function operatorFeedbackNextCommands(feedback: string[]): string[] {
	return Array.from(
		new Set(
			feedback
				.flatMap((row) => /\bnext=(.+?)(?:\s+evidence=|\s+source=|$)/i.exec(row)?.[1]?.trim() ?? "")
				.flatMap(splitRetryNextCommands)
				.filter((command) => /^re[-_]/i.test(command)),
		),
	).slice(0, 16);
}

function latestOperatorFeedback(target?: string): {
	rows: string[];
	commands: string[];
	sourceArtifacts: string[];
} {
	const specs: Array<
		[string | undefined, (path: string) => { target?: string; operatorFeedback?: string[] } | undefined]
	> = [
		[latestAutofixArtifactPath(), parseAutofixArtifact],
		[latestReplayerArtifactPath(), parseReplayArtifact],
		[latestCompilerArtifactPath(), parseCompilerArtifact],
		[latestVerifierArtifactPath(), parseVerifierArtifact],
	];
	const exactRows: string[] = [];
	const exactSources: string[] = [];
	const fallbackRows: string[] = [];
	const fallbackSources: string[] = [];
	for (const [path, parse] of specs) {
		if (!path || !existsSync(path)) continue;
		const artifact = parse(path);
		if (!artifact) continue;
		const feedback = artifact.operatorFeedback ?? [];
		if (feedback.length) {
			const exact = !target || !artifact.target || artifact.target === target;
			if (exact) {
				exactSources.push(path);
				exactRows.push(...feedback);
			} else {
				fallbackSources.push(path);
				fallbackRows.push(...feedback);
			}
		}
	}
	const rows = exactRows.length ? exactRows : fallbackRows;
	const sourceArtifacts = exactRows.length ? exactSources : fallbackSources;
	const dedupedRows = Array.from(new Set(rows)).slice(0, 48);
	const commands = operatorFeedbackNextCommands(dedupedRows)
		.map((command) => operatorCommandConcrete(command, target).command)
		.filter((command) => /^re[-_]/i.test(command))
		.filter((command) => !/^re[-_]proof[-_]loop\b/i.test(command));
	return {
		rows: dedupedRows,
		commands: Array.from(new Set(commands)).slice(0, 16),
		sourceArtifacts: Array.from(new Set(sourceArtifacts)).slice(0, 16),
	};
}

function verifierInterestingEvidence(output: string, fallback: string): string[] {
	const lines = output
		.split(/\r?\n/)
		.map((line) => line.trim())
		.filter(Boolean)
		.filter((line) =>
			/artifact|path:|verify:|hash:|offset:|mission_id|evidence_|ledger|status:|gate|proof|anchor|exit=|code=|operator_queue|reflection_cycle|context_pack|supervisor_review/i.test(
				line,
			),
		)
		.slice(0, 12);
	return lines.length ? lines.map((line) => truncateMiddle(line, 260)) : [fallback];
}

function verifierCounterEvidence(text: string): string[] {
	return text
		.split(/\r?\n/)
		.map((line) => line.trim())
		.filter((line) =>
			/blocked|pending gate|missing|unsupported|unresolved|error|failed|cannot|not found|weak|contradict/i.test(
				line,
			),
		)
		.slice(0, 12)
		.map((line) => truncateMiddle(line, 260));
}

function verifierStatusFromExecution(execution: OperationExecution): VerifierStatus {
	const counter = verifierCounterEvidence(execution.output);
	if (execution.status === "blocked") return counter.length ? "contradicted" : "missing";
	if (counter.some((line) => /unsupported|unresolved|error|failed|cannot|not found/i.test(line)))
		return "contradicted";
	if (
		/evidence_|artifact|path:|verify:|hash:|offset:|mission_id|operator_queue|reflection_cycle|context_pack|supervisor_review/i.test(
			execution.output,
		)
	)
		return "proved";
	return "weak";
}

function verifierConfidence(status: VerifierStatus): number {
	switch (status) {
		case "proved":
			return 85;
		case "weak":
			return 55;
		case "missing":
			return 25;
		case "contradicted":
			return 10;
	}
}

function executionAssertion(execution: OperationExecution, index: number, operatorPath: string): VerifierAssertion {
	const status = verifierStatusFromExecution(execution);
	const evidence = verifierInterestingEvidence(execution.output, `operator_execution: ${execution.command}`).slice(
		0,
		10,
	);
	const counterEvidence = verifierCounterEvidence(execution.output);
	return {
		id: `exec:${index + 1}:${slug(execution.command).slice(0, 24)}`,
		subject: execution.command,
		claim: `operator step ${execution.stepId} completed with status=${execution.status}`,
		status,
		confidence: verifierConfidence(status),
		evidence: [`operator_artifact: ${operatorPath}`, ...evidence],
		counterEvidence,
		requiredFollowups:
			status === "proved"
				? ["re_verifier matrix", "re_complete audit"]
				: [
						"re_operator escalate",
						`re_operator dispatch <target> 1 # retry ${execution.stepId}`,
						"re_verifier check",
					],
	};
}

function gateAssertions(): VerifierAssertion[] {
	const mission = readCurrentMission();
	if (!mission) {
		return [
			{
				id: "gate:no-mission",
				subject: "mission blackboard",
				claim: "active mission exists for verification",
				status: "missing",
				confidence: 15,
				evidence: [],
				counterEvidence: ["no active mission"],
				requiredFollowups: ["re_mission new <task>", "re_context pack", "re_operator plan"],
			},
		];
	}
	return mission.gates.map((gate, index) => ({
		id: `gate:${index + 1}:${gate.name}`,
		subject: `gate:${gate.name}`,
		claim: `mission gate ${gate.name} is ${gate.status}`,
		status: gate.status === "done" ? "proved" : gate.status === "blocked" ? "contradicted" : "missing",
		confidence: gate.status === "done" ? 80 : gate.status === "blocked" ? 20 : 35,
		evidence: gate.note ? [`note: ${gate.note}`] : [],
		counterEvidence: gate.status === "done" ? [] : [`gate status=${gate.status}`],
		requiredFollowups:
			gate.status === "done" ? ["re_complete audit"] : [`close gate: ${gate.name}`, "re_operator escalate"],
	}));
}

function artifactAssertions(operator: OperatorArtifact): VerifierAssertion[] {
	return operator.sourceArtifacts.slice(0, 24).map((artifact, index) => {
		const present = existsSync(artifact);
		return {
			id: `artifact:${index + 1}:${slug(artifact).slice(0, 24)}`,
			subject: artifact,
			claim: "source artifact exists and can be inspected",
			status: present ? "proved" : "contradicted",
			confidence: present ? 90 : 10,
			evidence: present ? [`path: ${artifact}`, `verify: test -f ${shellQuote(artifact)}`] : [],
			counterEvidence: present ? [] : [`missing artifact: ${artifact}`],
			requiredFollowups: present ? ["re_verifier matrix"] : ["re_context pack", "re_operator plan"],
		};
	});
}

function buildVerifier(options: { target?: string; mode?: "check" | "matrix" } = {}): VerifierArtifact {
	ensureReconStorage();
	const { operator, path: operatorArtifact } = latestOrBuildOperator(options);
	const operatorFeedback = classifyOperatorFeedback(operator, operatorArtifact, options.target);
	const executionAssertions = operator.executed.map((execution, index) =>
		executionAssertion(execution, index, operatorArtifact),
	);
	const assertions = [...executionAssertions, ...gateAssertions(), ...artifactAssertions(operator)];
	if (executionAssertions.length === 0) {
		assertions.unshift({
			id: "exec:none",
			subject: "operator executions",
			claim: "at least one operator dispatch execution exists",
			status: "missing",
			confidence: 20,
			evidence: [`operator_artifact: ${operatorArtifact}`],
			counterEvidence: ["operator.executed is empty"],
			requiredFollowups: ["re_operator dispatch <target> 1", "re_verifier check"],
		});
	}
	const contradictions = assertions
		.filter((assertion) => assertion.status === "contradicted")
		.map((assertion) => `${assertion.id}: ${assertion.counterEvidence.join(" | ") || assertion.claim}`);
	const gaps = assertions
		.filter((assertion) => assertion.status === "missing" || assertion.status === "weak")
		.map((assertion) => `${assertion.id}: ${assertion.claim}`);
	const nextActions = Array.from(
		new Set([
			...operatorFeedbackNextCommands(operatorFeedback),
			...(contradictions.length ? ["re_operator escalate"] : []),
			...(gaps.length ? ["re_operator dispatch <target> 1", "re_verifier check"] : []),
			"re_complete audit",
		]),
	).slice(0, 12);
	return {
		timestamp: new Date().toISOString(),
		missionId: operator.missionId,
		route: operator.route,
		target: options.target ?? operator.target,
		mode: options.mode ?? "check",
		operatorArtifact,
		operatorFeedback,
		assertions,
		contradictions,
		gaps,
		nextActions,
		sourceArtifacts: Array.from(new Set([operatorArtifact, ...operator.sourceArtifacts])).slice(0, 36),
	};
}

function formatVerifier(verifier: VerifierArtifact, path?: string): string {
	return [
		"verifier_matrix:",
		path ? `verifier_artifact: ${path}` : undefined,
		`timestamp: ${verifier.timestamp}`,
		`mode: ${verifier.mode}`,
		`mission_id: ${verifier.missionId ?? "none"}`,
		`route: ${verifier.route ?? "none"}`,
		`target: ${verifier.target ?? "<none>"}`,
		`operator_artifact: ${verifier.operatorArtifact ?? "none"}`,
		"operator_feedback:",
		...((verifier.operatorFeedback ?? []).length
			? (verifier.operatorFeedback ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"assertions:",
		...(verifier.assertions.length
			? verifier.assertions.map(
					(assertion) =>
						`- ${assertion.id} [${assertion.status}] confidence=${assertion.confidence} subject=${assertion.subject} claim=${assertion.claim}`,
				)
			: ["- none"]),
		"evidence_bindings:",
		...(verifier.assertions.length
			? verifier.assertions.flatMap((assertion) =>
					assertion.evidence.length
						? assertion.evidence.slice(0, 4).map((item) => `- ${assertion.id}: ${item}`)
						: [`- ${assertion.id}: none`],
				)
			: ["- none"]),
		"counter_evidence:",
		...(verifier.assertions.some((assertion) => assertion.counterEvidence.length)
			? verifier.assertions.flatMap((assertion) =>
					assertion.counterEvidence.map((item) => `- ${assertion.id}: ${item}`),
				)
			: ["- none"]),
		"contradictions:",
		...(verifier.contradictions.length ? verifier.contradictions.map((item) => `- ${item}`) : ["- none"]),
		"gaps:",
		...(verifier.gaps.length ? verifier.gaps.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(verifier.nextActions.length ? verifier.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_verifier_command: ${verifier.mode === "matrix" ? "re_complete audit" : "re_verifier matrix"}`,
		"source_artifacts:",
		...(verifier.sourceArtifacts.length ? verifier.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeVerifierArtifact(verifier: VerifierArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceVerifiersDir(),
		`${verifier.timestamp.replace(/[:.]/g, "-")}-${slug(verifier.route ?? "verifier")}-${verifier.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Verifier Artifact",
			"",
			formatVerifier(verifier, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(verifier, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `verifier-${verifier.mode} ${verifier.missionId ?? "no-mission"}`,
		fact: `Verifier matrix ${verifier.mode}: ${verifier.assertions.length} assertion(s), ${verifier.contradictions.length} contradiction(s), ${verifier.gaps.length} gap(s), operator_feedback=${(verifier.operatorFeedback ?? []).length}`,
		command: `re_verifier ${verifier.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "operator/evidence assertion verifier",
	});
	updateMissionGate("verifier_matrix_ready", "done", path);
	return path;
}

function buildVerifierOutput(action: "check" | "show" | "matrix" = "check", options: { target?: string } = {}): string {
	if (action === "show") {
		const path = latestVerifierArtifactPath();
		if (!path) return "verifier_matrix:\nstatus: missing\nnext: re_verifier check";
		return truncateMiddle(readText(path), 18000);
	}
	const verifier = buildVerifier({ target: options.target, mode: action === "matrix" ? "matrix" : "check" });
	const path = writeVerifierArtifact(verifier);
	return formatVerifier(verifier, path);
}

function latestCompilerArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceCompilersDir(), 1)[0];
}

function parseVerifierArtifact(path: string): VerifierArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as VerifierArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildVerifier(options: { target?: string } = {}): { verifier: VerifierArtifact; path: string } {
	const latest = !options.target ? latestVerifierArtifactPath() : undefined;
	if (latest) {
		const verifier = parseVerifierArtifact(latest);
		if (verifier) return { verifier, path: latest };
	}
	const verifier = buildVerifier({ target: options.target, mode: "matrix" });
	const path = writeVerifierArtifact(verifier);
	return { verifier, path };
}

function compilerStatusSummary(assertions: VerifierAssertion[]): Record<VerifierStatus, number> {
	return assertions.reduce<Record<VerifierStatus, number>>(
		(summary, assertion) => {
			summary[assertion.status] += 1;
			return summary;
		},
		{ proved: 0, weak: 0, contradicted: 0, missing: 0 },
	);
}

function compilerKeyEvidence(verifier: VerifierArtifact): string[] {
	const proved = verifier.assertions.filter((assertion) => assertion.status === "proved");
	const lines = proved.flatMap((assertion) => [
		`${assertion.id}: ${assertion.claim}`,
		...assertion.evidence.slice(0, 3).map((item) => `  evidence: ${item}`),
	]);
	const feedbackEvidence = (verifier.operatorFeedback ?? [])
		.filter((row) => /category=(strong_evidence|replay_or_exploit_candidate|worker_retry_progress)/i.test(row))
		.map((row) => `operator_feedback: ${row}`);
	if (lines.length || feedbackEvidence.length)
		return Array.from(new Set([...lines, ...feedbackEvidence])).slice(0, 36);
	return Array.from(
		new Set([
			`verifier_artifact: ${verifier.sourceArtifacts[0] ?? "none"}`,
			...verifier.sourceArtifacts.slice(0, 8).map((artifact) => `source_artifact: ${artifact}`),
		]),
	);
}

function compilerReproCommands(verifier: VerifierArtifact, verifierPath: string): string[] {
	const ledgerCommands = Array.from(readText(evidenceLedgerPath()).matchAll(/- command: `([^`]+)`/g))
		.map((match) => match[1]?.replace(/\\`/g, "`").trim())
		.filter((command): command is string => Boolean(command));
	const verifyCommands = verifier.assertions
		.flatMap((assertion) => assertion.evidence)
		.map((item) => /^verify:\s*(.+)$/i.exec(item)?.[1]?.trim())
		.filter((command): command is string => Boolean(command));
	return Array.from(
		new Set([
			...ledgerCommands.slice(-12),
			...verifyCommands.slice(0, 8),
			...operatorFeedbackNextCommands(verifier.operatorFeedback ?? []).slice(0, 6),
			`cat ${shellQuote(verifierPath)}`,
			...verifier.sourceArtifacts
				.slice(0, 5)
				.map((artifact) => `test -f ${shellQuote(artifact)} && cat ${shellQuote(artifact)}`),
		]),
	).slice(0, 24);
}

function compilerContradictions(verifier: VerifierArtifact): string[] {
	const contradictionAssertions = verifier.assertions
		.filter((assertion) => assertion.status === "contradicted")
		.map((assertion) => `${assertion.id}: ${assertion.counterEvidence.join(" | ") || assertion.claim}`);
	return Array.from(new Set([...verifier.contradictions, ...contradictionAssertions])).slice(0, 24);
}

function compilerGaps(verifier: VerifierArtifact): string[] {
	const gapAssertions = verifier.assertions
		.filter((assertion) => assertion.status === "missing" || assertion.status === "weak")
		.map((assertion) => `${assertion.id} [${assertion.status}]: ${assertion.claim}`);
	const feedbackGaps = (verifier.operatorFeedback ?? [])
		.filter((row) =>
			/category=(unresolved_target|dispatcher_gap|missing_tool_or_dependency|runtime_failure|failure_budget_exhausted|worker_retry_blocked|swarm_retry_queue)/i.test(
				row,
			),
		)
		.map((row) => `operator_feedback: ${row}`);
	return Array.from(new Set([...verifier.gaps, ...gapAssertions, ...feedbackGaps])).slice(0, 36);
}

function compilerNextOperatorQueue(verifier: VerifierArtifact): string[] {
	const needsRepair = verifier.assertions.some(
		(assertion) =>
			assertion.status === "missing" || assertion.status === "weak" || assertion.status === "contradicted",
	);
	const repair = verifier.assertions
		.filter((assertion) => assertion.status !== "proved")
		.flatMap((assertion) => assertion.requiredFollowups);
	return Array.from(
		new Set([
			...operatorFeedbackNextCommands(verifier.operatorFeedback ?? []),
			...(needsRepair ? ["re_operator escalate"] : []),
			...repair,
			...verifier.nextActions,
			needsRepair ? "re_verifier check" : "re_compiler final",
			"re_complete audit",
		]),
	).slice(0, 18);
}

function compilerOutcome(verifier: VerifierArtifact, summary: Record<VerifierStatus, number>): string[] {
	const total = verifier.assertions.length;
	if (summary.contradicted > 0)
		return [
			`status=blocked_by_contradiction proved=${summary.proved}/${total} contradicted=${summary.contradicted}`,
			"claim boundary: contradictions must be repaired before final success claims.",
		];
	if (summary.missing > 0 || summary.weak > 0)
		return [
			`status=partial proved=${summary.proved}/${total} weak=${summary.weak} missing=${summary.missing}`,
			"claim boundary: report only proved assertions and keep weak/missing items in next_operator_queue.",
		];
	return [
		`status=ready proved=${summary.proved}/${total}`,
		"claim boundary: verifier found no weak, missing, or contradicted assertion.",
	];
}

function compilerClaimGateReady(compiler: CompilerArtifact): boolean {
	return compiler.mode === "final" && compiler.strictClaimGate?.status === "pass";
}

function latestCompilerClaimGateInputs(): {
	supervisor?: SupervisorArtifact;
	supervisorPath?: string;
	swarm?: SwarmArtifact;
	swarmPath?: string;
	releaseGateMetadata: string[];
	claimGatePolicy: string[];
	strictClaimGate: StrictClaimGateSnapshot;
	claimGateResult: string[];
} {
	const supervisorPath = latestSupervisorArtifactPath();
	const supervisor = supervisorPath ? parseSupervisorArtifact(supervisorPath) : undefined;
	const swarmPath = latestSwarmArtifactPath();
	const swarm = swarmPath ? parseSwarmArtifact(swarmPath) : undefined;
	const releaseGateMetadata = supervisor?.releaseGateMetadata ?? swarm?.releaseGateMetadata ?? [];
	const claimGatePolicy =
		supervisor?.claimGatePolicy ?? supervisorClaimGatePolicy(swarm?.parallelPlan, supervisorPlanCoverage(swarm));
	const strictClaimGate = supervisor?.strictClaimGate ?? strictClaimGateSnapshot();
	const claimGateResult =
		supervisor?.claimGateResult ?? buildClaimGateResult(releaseGateMetadata, claimGatePolicy, strictClaimGate);
	return {
		supervisor,
		supervisorPath,
		swarm,
		swarmPath,
		releaseGateMetadata,
		claimGatePolicy,
		strictClaimGate,
		claimGateResult,
	};
}

function compilerReportLines(compiler: CompilerArtifact): string[] {
	const bullet = (items: string[]) => (items.length ? items.map((item) => `- ${item}`) : ["- none"]);
	return [
		"# Pi-RECON Compiled Report",
		"",
		"## Outcome",
		"",
		...bullet(compiler.outcome),
		"",
		"## Key Evidence",
		"",
		...bullet(compiler.keyEvidence),
		"",
		"## Verification",
		"",
		`- verifier_artifact: ${compiler.verifierArtifact ?? "none"}`,
		`- supervisor_artifact: ${compiler.supervisorArtifact ?? "none"}`,
		`- status_summary: proved=${compiler.statusSummary.proved} weak=${compiler.statusSummary.weak} contradicted=${compiler.statusSummary.contradicted} missing=${compiler.statusSummary.missing}`,
		`- strict_claim_gate: ${compiler.strictClaimGate?.status ?? "missing"}`,
		`- claim_release_marker: ${compiler.strictClaimGate?.markerPath ?? "missing"}`,
		`- claim_gate_final_publish_ready: ${compiler.strictClaimGate?.status === "pass" ? "yes" : "no"}`,
		"",
		"## Claim Gate",
		"",
		"### Release Gate Metadata",
		...bullet(compiler.releaseGateMetadata),
		"",
		"### Supervisor Claim Gate Policy",
		...bullet(compiler.claimGatePolicy),
		"",
		"### Strict Claim Gate",
		...formatStrictClaimGateSnapshot(compiler.strictClaimGate),
		"",
		"### Claim Gate Result",
		...bullet(compiler.claimGateResult),
		"",
		"## Operator Feedback",
		"",
		...bullet(compiler.operatorFeedback ?? []),
		"",
		"## Repro Commands",
		"",
		"```bash",
		...(compiler.reproCommands.length ? compiler.reproCommands : ["# no repro commands captured yet"]),
		"```",
		"",
		"## Contradictions",
		"",
		...bullet(compiler.contradictions),
		"",
		"## Gaps",
		"",
		...bullet(compiler.gaps),
		"",
		"## Next Step",
		"",
		...bullet(compiler.nextOperatorQueue),
		"",
	];
}

function writeCompiledReport(compiler: CompilerArtifact): string {
	ensureReconStorage();
	const safeTitle = slug(`${compiler.route ?? "pi-recon"}-${compiler.mode}-compiled-report`).slice(0, 90);
	const path = join(reportDir(), `${compiler.timestamp.replace(/[:.]/g, "-")}-${safeTitle}.md`);
	writeFileSync(path, compiler.finalReport.join("\n"), "utf-8");
	updateMissionGate("report_or_writeup_ready", "done", `${path} strict_claim_gate=pass`);
	return path;
}

function buildCompiler(options: { target?: string; mode?: "draft" | "final" } = {}): CompilerArtifact {
	ensureReconStorage();
	const { verifier, path: verifierArtifact } = latestOrBuildVerifier(options);
	const claimGateInputs = latestCompilerClaimGateInputs();
	const summary = compilerStatusSummary(verifier.assertions);
	const mode = options.mode ?? "draft";
	const strictBlocksFinal = mode === "final" && claimGateInputs.strictClaimGate.status !== "pass";
	const compiler: CompilerArtifact = {
		timestamp: new Date().toISOString(),
		missionId: verifier.missionId,
		route: verifier.route,
		target: options.target ?? verifier.target,
		mode,
		verifierArtifact,
		supervisorArtifact: claimGateInputs.supervisorPath,
		operatorFeedback: verifier.operatorFeedback ?? [],
		statusSummary: summary,
		outcome: [
			...compilerOutcome(verifier, summary),
			...(strictBlocksFinal
				? [
						`status=blocked_by_claim_gate strict_claim_gate=${claimGateInputs.strictClaimGate.status}`,
						"claim boundary: final reports require a passing strict claim release marker from gate:claim-release.",
					]
				: []),
		],
		keyEvidence: compilerKeyEvidence(verifier),
		reproCommands: compilerReproCommands(verifier, verifierArtifact),
		contradictions: compilerContradictions(verifier),
		gaps: [
			...compilerGaps(verifier),
			...(claimGateInputs.strictClaimGate.status !== "pass"
				? [
						`strict claim gate ${claimGateInputs.strictClaimGate.status}: ${claimGateInputs.strictClaimGate.markerPath ?? "missing marker"}`,
						...claimGateInputs.strictClaimGate.requiredGaps.map((gap) => `strict claim required gap: ${gap}`),
					]
				: []),
		],
		nextOperatorQueue: Array.from(
			new Set([
				...(claimGateInputs.strictClaimGate.status === "pass"
					? []
					: [
							"npm run gate:claim-release",
							"re_supervisor repair",
							"re_context pack",
							"re_operator dispatch <target> 2",
							"re_proof_loop run <target> 4 2",
						]),
				...compilerNextOperatorQueue(verifier),
			]),
		).slice(0, 24),
		finalReport: [],
		releaseGateMetadata: claimGateInputs.releaseGateMetadata,
		claimGatePolicy: claimGateInputs.claimGatePolicy,
		strictClaimGate: claimGateInputs.strictClaimGate,
		claimGateResult: claimGateInputs.claimGateResult,
		sourceArtifacts: Array.from(
			new Set(
				[
					verifierArtifact,
					claimGateInputs.supervisorPath,
					claimGateInputs.swarmPath,
					claimGateInputs.strictClaimGate.markerPath,
					...verifier.sourceArtifacts,
				].filter(Boolean) as string[],
			),
		).slice(0, 56),
	};
	compiler.finalReport = compilerReportLines(compiler);
	if (compiler.mode === "final") {
		if (compilerClaimGateReady(compiler)) compiler.reportPath = writeCompiledReport(compiler);
		else
			updateMissionGate(
				"report_or_writeup_ready",
				"blocked",
				`strict_claim_gate=${compiler.strictClaimGate?.status ?? "missing"} marker=${compiler.strictClaimGate?.markerPath ?? "missing"}`,
			);
	}
	return compiler;
}

function formatCompiler(compiler: CompilerArtifact, path?: string): string {
	return [
		"compiler_report:",
		path ? `compiler_artifact: ${path}` : undefined,
		`timestamp: ${compiler.timestamp}`,
		`mode: ${compiler.mode}`,
		`mission_id: ${compiler.missionId ?? "none"}`,
		`route: ${compiler.route ?? "none"}`,
		`target: ${compiler.target ?? "<none>"}`,
		`verifier_artifact: ${compiler.verifierArtifact ?? "none"}`,
		`supervisor_artifact: ${compiler.supervisorArtifact ?? "none"}`,
		`report_path: ${compiler.reportPath ?? "none"}`,
		`status_summary: proved=${compiler.statusSummary.proved} weak=${compiler.statusSummary.weak} contradicted=${compiler.statusSummary.contradicted} missing=${compiler.statusSummary.missing}`,
		"release_gate_metadata:",
		...(compiler.releaseGateMetadata.length ? compiler.releaseGateMetadata.map((item) => `- ${item}`) : ["- none"]),
		"claim_gate_policy:",
		...(compiler.claimGatePolicy.length ? compiler.claimGatePolicy.map((item) => `- ${item}`) : ["- none"]),
		"strict_claim_gate:",
		...formatStrictClaimGateSnapshot(compiler.strictClaimGate),
		"claim_gate_result:",
		...(compiler.claimGateResult.length ? compiler.claimGateResult.map((item) => `- ${item}`) : ["- none"]),
		"operator_feedback:",
		...((compiler.operatorFeedback ?? []).length
			? (compiler.operatorFeedback ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"outcome:",
		...(compiler.outcome.length ? compiler.outcome.map((item) => `- ${item}`) : ["- none"]),
		"key_evidence_block:",
		...(compiler.keyEvidence.length ? compiler.keyEvidence.map((item) => `- ${item}`) : ["- none"]),
		"repro_commands:",
		...(compiler.reproCommands.length ? compiler.reproCommands.map((item) => `- ${item}`) : ["- none"]),
		"contradictions:",
		...(compiler.contradictions.length ? compiler.contradictions.map((item) => `- ${item}`) : ["- none"]),
		"gaps:",
		...(compiler.gaps.length ? compiler.gaps.map((item) => `- ${item}`) : ["- none"]),
		"next_operator_queue:",
		...(compiler.nextOperatorQueue.length ? compiler.nextOperatorQueue.map((item) => `- ${item}`) : ["- none"]),
		"final_report_scaffold:",
		...compiler.finalReport.slice(0, 80),
		`next_compiler_command: ${compiler.mode === "final" ? "re_complete audit" : "re_compiler final"}`,
		"source_artifacts:",
		...(compiler.sourceArtifacts.length ? compiler.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeCompilerArtifact(compiler: CompilerArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceCompilersDir(),
		`${compiler.timestamp.replace(/[:.]/g, "-")}-${slug(compiler.route ?? "compiler")}-${compiler.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Compiler Artifact",
			"",
			formatCompiler(compiler, path),
			"",
			"## Final report scaffold",
			"",
			compiler.finalReport.join("\n"),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(compiler, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `compiler-${compiler.mode} ${compiler.missionId ?? "no-mission"}`,
		fact: `Compiler ${compiler.mode}: proved=${compiler.statusSummary.proved}, weak=${compiler.statusSummary.weak}, contradicted=${compiler.statusSummary.contradicted}, missing=${compiler.statusSummary.missing}, operator_feedback=${(compiler.operatorFeedback ?? []).length}, strict_claim_gate=${compiler.strictClaimGate?.status ?? "missing"}, claim_gate_result=${compiler.claimGateResult.length}`,
		command: `re_compiler ${compiler.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "verifier-to-report compiler",
	});
	updateMissionGate("compiler_ready", "done", path);
	if (compiler.mode === "final" && !compiler.reportPath) {
		updateMissionGate(
			"report_or_writeup_ready",
			"blocked",
			`strict_claim_gate=${compiler.strictClaimGate?.status ?? "missing"} marker=${compiler.strictClaimGate?.markerPath ?? "missing"}`,
		);
	}
	return path;
}

function buildCompilerOutput(action: "draft" | "show" | "final" = "draft", options: { target?: string } = {}): string {
	if (action === "show") {
		const path = latestCompilerArtifactPath();
		if (!path) return "compiler_report:\nstatus: missing\nnext: re_compiler draft";
		return truncateMiddle(readText(path), 20000);
	}
	const compiler = buildCompiler({ target: options.target, mode: action });
	const path = writeCompilerArtifact(compiler);
	return formatCompiler(compiler, path);
}

function latestReplayerArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceReplayersDir(), 1)[0];
}

function parseCompilerArtifact(path: string): CompilerArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as CompilerArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildCompiler(options: { target?: string } = {}): { compiler: CompilerArtifact; path: string } {
	const latest = !options.target ? latestCompilerArtifactPath() : undefined;
	if (latest) {
		const compiler = parseCompilerArtifact(latest);
		if (compiler) return { compiler, path: latest };
	}
	const compiler = buildCompiler({ target: options.target, mode: "draft" });
	const path = writeCompilerArtifact(compiler);
	return { compiler, path };
}

function replayCommandConcrete(command: string, target?: string): { command: string; blocked?: string } {
	let normalized = command.trim().replace(/^\//, "");
	if (!normalized) return { command: normalized, blocked: "empty replay command" };
	if (/<target>|<TARGET>|<URL>|<none>/i.test(normalized)) {
		if (!target) return { command: normalized, blocked: "target placeholder is unresolved" };
		normalized = normalized.replace(/<target>|<TARGET>|<URL>|<none>/gi, target);
	}
	if (/^re[-_]/i.test(normalized))
		return { command: normalized, blocked: "internal Pi-RECON command; dispatch through re_operator instead" };
	return { command: normalized };
}

function replayHash(text: string): string {
	return createHash("sha256").update(text).digest("hex");
}

function buildReplayMatrix(replay: ReplayArtifact): string[] {
	const executionByStep = new Map(replay.executions.map((execution) => [execution.stepId, execution]));
	return replay.steps.map((step) => {
		const execution = executionByStep.get(step.id);
		if (!execution) {
			return `${step.id} [${step.status}] exit=NA stdout_sha256=NA stderr_sha256=NA command=${step.command}${step.reason ? ` reason=${step.reason}` : ""}`;
		}
		return `${step.id} [${execution.status}] exit=${execution.exit} stdout_sha256=${execution.stdoutHash} stderr_sha256=${execution.stderrHash} command=${execution.command}`;
	});
}

function refreshReplayDerivedFields(replay: ReplayArtifact): ReplayArtifact {
	const passed = replay.executions.filter((execution) => execution.status === "passed").length;
	const failed = replay.executions.filter((execution) => execution.status === "failed").length;
	const blocked = replay.steps
		.filter((step) => step.status === "blocked")
		.map((step) => `${step.id}: ${step.reason ?? "blocked"} :: ${step.command}`);
	const readyCount = replay.steps.filter((step) => step.status === "ready").length;
	const nextActions = Array.from(
		new Set([
			...operatorFeedbackNextCommands(replay.operatorFeedback ?? []),
			...(readyCount ? [`re_replayer run ${replay.target ?? "<target>"} ${Math.min(readyCount, 3)}`] : []),
			...(failed ? ["re_autofix plan", "re_compiler draft", "re_verifier matrix"] : []),
			...(blocked.length ? ["re_autofix plan", "re_operator escalate", "re_compiler draft"] : []),
			"re_complete audit",
		]),
	).slice(0, 12);
	const replayMatrix = buildReplayMatrix({ ...replay, passed, failed, blocked, nextActions, replayMatrix: [] });
	return { ...replay, passed, failed, blocked, nextActions, replayMatrix };
}

function buildReplayer(options: { target?: string; mode?: "plan" | "run" } = {}): ReplayArtifact {
	ensureReconStorage();
	const { compiler, path: compilerArtifact } = latestOrBuildCompiler(options);
	const target = options.target ?? compiler.target;
	const seen = new Set<string>();
	const steps: ReplayStep[] = [];
	for (const rawCommand of compiler.reproCommands.slice(0, 40)) {
		const command = rawCommand.trim();
		if (!command || seen.has(command)) continue;
		seen.add(command);
		const concrete = replayCommandConcrete(command, target);
		steps.push({
			id: `replay:${steps.length + 1}:${slug(command).slice(0, 24)}`,
			command: concrete.command,
			status: concrete.blocked ? "blocked" : "ready",
			reason: concrete.blocked,
			sourceArtifacts: compiler.sourceArtifacts,
		});
	}
	if (steps.length === 0) {
		steps.push({
			id: "replay:0:no-commands",
			command: "re_compiler draft",
			status: "blocked",
			reason: "compiler artifact has no repro_commands",
			sourceArtifacts: compiler.sourceArtifacts,
		});
	}
	return refreshReplayDerivedFields({
		timestamp: new Date().toISOString(),
		missionId: compiler.missionId,
		route: compiler.route,
		target,
		mode: options.mode ?? "plan",
		compilerArtifact,
		operatorFeedback: compiler.operatorFeedback ?? [],
		steps,
		executions: [],
		replayMatrix: [],
		passed: 0,
		failed: 0,
		blocked: [],
		nextActions: [],
		sourceArtifacts: Array.from(new Set([compilerArtifact, ...compiler.sourceArtifacts])).slice(0, 56),
	});
}

function formatReplayer(replay: ReplayArtifact, path?: string): string {
	return [
		"replay_matrix:",
		path ? `replay_artifact: ${path}` : undefined,
		`timestamp: ${replay.timestamp}`,
		`mode: ${replay.mode}`,
		`mission_id: ${replay.missionId ?? "none"}`,
		`route: ${replay.route ?? "none"}`,
		`target: ${replay.target ?? "<none>"}`,
		`compiler_artifact: ${replay.compilerArtifact ?? "none"}`,
		"operator_feedback:",
		...((replay.operatorFeedback ?? []).length
			? (replay.operatorFeedback ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		`passed: ${replay.passed}`,
		`failed: ${replay.failed}`,
		`blocked_count: ${replay.blocked.length}`,
		"steps:",
		...(replay.steps.length
			? replay.steps.map(
					(step) =>
						`- ${step.id} [${step.status}] command=${step.command}${step.reason ? ` reason=${step.reason}` : ""}`,
				)
			: ["- none"]),
		`executed_steps: ${replay.executions.length}`,
		...(replay.executions.length
			? replay.executions.map(
					(execution) =>
						`- ${execution.stepId} [${execution.status}] exit=${execution.exit} stdout_sha256=${execution.stdoutHash} stderr_sha256=${execution.stderrHash} command=${execution.command}`,
				)
			: []),
		"replay_matrix_rows:",
		...(replay.replayMatrix.length ? replay.replayMatrix.map((item) => `- ${item}`) : ["- none"]),
		"blocked:",
		...(replay.blocked.length ? replay.blocked.map((item) => `- ${item}`) : ["- none"]),
		"next_replay_actions:",
		...(replay.nextActions.length ? replay.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_replay_command: ${replay.steps.some((step) => step.status === "ready") ? `re_replayer run ${replay.target ?? "<target>"} 1` : "re_complete audit"}`,
		"source_artifacts:",
		...(replay.sourceArtifacts.length ? replay.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeReplayerArtifact(replay: ReplayArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceReplayersDir(),
		`${replay.timestamp.replace(/[:.]/g, "-")}-${slug(replay.route ?? "replayer")}-${replay.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Replayer Artifact",
			"",
			formatReplayer(replay, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(replay, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: replay.mode === "run" ? "runtime" : "artifact",
		title: `replayer-${replay.mode} ${replay.missionId ?? "no-mission"}`,
		fact: `Replay ${replay.mode}: ${replay.executions.length} executed, passed=${replay.passed}, failed=${replay.failed}, blocked=${replay.blocked.length}, operator_feedback=${(replay.operatorFeedback ?? []).length}`,
		command: `re_replayer ${replay.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "compiler repro command replay matrix",
	});
	if (replay.mode === "run") updateMissionGate("replay_ready", replay.executions.length ? "done" : "blocked", path);
	appendRuntimeFailureRepairFromReplay(replay, path);
	return path;
}

async function runReplayer(
	pi: ExtensionAPI,
	options: { target?: string; maxSteps?: number; timeoutMs?: number } = {},
): Promise<string> {
	let replay = buildReplayer({ target: options.target, mode: "run" });
	const maxSteps = Math.max(1, Math.min(20, Math.floor(options.maxSteps ?? 3)));
	const timeout = Math.max(1000, Math.min(300000, Math.floor(options.timeoutMs ?? 60000)));
	for (const step of replay.steps.filter((item) => item.status === "ready").slice(0, maxSteps)) {
		const result = await pi.exec("bash", ["-lc", `set -o pipefail\n${step.command}`], { timeout });
		const status: ReplayStatus = result.code === 0 && !result.killed ? "passed" : "failed";
		step.status = status;
		step.reason = status === "failed" ? `exit=${result.code}${result.killed ? " killed=true" : ""}` : undefined;
		replay.executions.push({
			stepId: step.id,
			command: step.command,
			status,
			exit: result.code,
			killed: result.killed,
			stdoutHash: replayHash(result.stdout),
			stderrHash: replayHash(result.stderr),
			stdoutHead: truncateMiddle(result.stdout.trim(), 1200),
			stderrHead: truncateMiddle(result.stderr.trim(), 1200),
		});
	}
	replay = refreshReplayDerivedFields(replay);
	const path = writeReplayerArtifact(replay);
	return formatReplayer(replay, path);
}

function buildReplayerOutput(action: "plan" | "show" = "plan", options: { target?: string } = {}): string {
	if (action === "show") {
		const path = latestReplayerArtifactPath();
		if (!path) return "replay_matrix:\nstatus: missing\nnext: re_replayer plan";
		return truncateMiddle(readText(path), 20000);
	}
	const replay = buildReplayer({ target: options.target, mode: "plan" });
	const path = writeReplayerArtifact(replay);
	return formatReplayer(replay, path);
}

function latestAutofixArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceAutofixDir(), 1)[0];
}

function parseReplayArtifact(path: string): ReplayArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as ReplayArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildReplay(options: { target?: string } = {}): { replay: ReplayArtifact; path: string } {
	const latest = !options.target ? latestReplayerArtifactPath() : undefined;
	if (latest) {
		const replay = parseReplayArtifact(latest);
		if (replay) return { replay, path: latest };
	}
	const replay = buildReplayer({ target: options.target, mode: "plan" });
	const path = writeReplayerArtifact(replay);
	return { replay, path };
}

function autofixItem(
	kind: AutofixItemKind,
	source: string,
	reason: string,
	command: string,
	sourceArtifacts: string[],
	index: number,
): AutofixItem {
	return {
		id: `fix:${kind}:${index + 1}:${slug(source).slice(0, 18)}`,
		kind,
		source: truncateMiddle(source, 360),
		reason: truncateMiddle(reason, 360),
		command,
		status: "queued",
		sourceArtifacts,
	};
}

function replayFailureRows(replay: ReplayArtifact): string[] {
	const failed = replay.executions
		.filter((execution) => execution.status === "failed")
		.map(
			(execution) =>
				`${execution.stepId}: exit=${execution.exit} command=${execution.command} stderr=${truncateMiddle(execution.stderrHead, 240)}`,
		);
	return Array.from(new Set([...replay.blocked, ...failed])).slice(0, 40);
}

function bootstrapToolFromCommand(command: string): string | undefined {
	const token = command
		.trim()
		.split(/\s+/)[0]
		?.replace(/^['"]|['"]$/g, "");
	if (!token || /^(set|test|cat|printf|sed|grep|rg|awk|bash|sh|python|node)$/i.test(token)) return undefined;
	return token;
}

function buildAutofix(options: { target?: string; mode?: "plan" | "apply" } = {}): AutofixArtifact {
	ensureReconStorage();
	const { replay, path: replayArtifact } = latestOrBuildReplay(options);
	const compilerPath = replay.compilerArtifact ?? latestCompilerArtifactPath();
	const compiler = compilerPath ? parseCompilerArtifact(compilerPath) : undefined;
	const sourceArtifacts = Array.from(new Set([replayArtifact, compilerPath, ...replay.sourceArtifacts])).filter(
		(path): path is string => Boolean(path),
	);
	const failures = replayFailureRows(replay);
	const operatorFeedback = replay.operatorFeedback ?? compiler?.operatorFeedback ?? [];
	const patchQueue: AutofixItem[] = [];
	const commandSubstitutions: AutofixItem[] = [];
	const bootstrapQueue: AutofixItem[] = [];
	const evidenceRecaptureQueue: AutofixItem[] = [];
	const nextOperatorQueue: string[] = [];
	let index = 0;
	const add = (collection: AutofixItem[], kind: AutofixItemKind, source: string, reason: string, command: string) => {
		collection.push(autofixItem(kind, source, reason, command, sourceArtifacts, index++));
	};

	for (const blocked of replay.blocked) {
		const command = /::\s*(.+)$/.exec(blocked)?.[1]?.trim() ?? blocked;
		if (/internal Pi-RECON command/i.test(blocked) || /^re[-_]/i.test(command)) {
			add(
				commandSubstitutions,
				"command_substitution",
				blocked,
				"internal command captured as shell replay; reroute through operator dispatcher",
				`re_operator plan && re_operator dispatch ${options.target ?? replay.target ?? "<target>"} 1`,
			);
			nextOperatorQueue.push(command.replace(/^re-/i, "re_"));
			continue;
		}
		if (/target placeholder|unresolved/i.test(blocked)) {
			add(
				evidenceRecaptureQueue,
				"evidence_recapture",
				blocked,
				"replay command still has unresolved target placeholder",
				`re_map ${options.target ?? replay.target ?? "<target>"} 2 && re_context pack ${options.target ?? replay.target ?? "<target>"}`,
			);
			nextOperatorQueue.push(`re_context pack ${options.target ?? replay.target ?? "<target>"}`);
			continue;
		}
		add(
			commandSubstitutions,
			"command_substitution",
			blocked,
			"blocked replay row needs a safer replay wrapper",
			`printf '%s\\n' ${shellQuote(`blocked replay row: ${truncateMiddle(blocked, 160)}`)}; ${command} || true`,
		);
	}

	for (const execution of replay.executions.filter((item) => item.status === "failed")) {
		const stderr = `${execution.stderrHead}\n${execution.stdoutHead}`;
		const tool = /command not found|not found|No such file|cannot stat|ModuleNotFoundError|ImportError/i.test(stderr)
			? bootstrapToolFromCommand(execution.command)
			: undefined;
		if (tool) {
			add(
				bootstrapQueue,
				"bootstrap",
				execution.command,
				"replay failed with missing tool/dependency signal",
				`re_bootstrap plan ${tool}`,
			);
			nextOperatorQueue.push(`re_bootstrap plan ${tool}`);
		}
		add(
			commandSubstitutions,
			"command_substitution",
			execution.command,
			`replay failed exit=${execution.exit}`,
			`timeout 60s bash -lc ${shellQuote(execution.command)} || true`,
		);
		add(
			evidenceRecaptureQueue,
			"evidence_recapture",
			execution.command,
			"replay failure requires fresh evidence capture and verifier refresh",
			`re_replayer run ${options.target ?? replay.target ?? "<target>"} 1 && re_verifier matrix`,
		);
	}

	for (const feedback of operatorFeedback.slice(0, 16)) {
		const next = operatorFeedbackNextCommands([feedback])[0] ?? "re_operator escalate";
		if (/category=missing_tool_or_dependency/i.test(feedback)) {
			add(bootstrapQueue, "bootstrap", feedback, "operator feedback classified missing tool/dependency", next);
			nextOperatorQueue.push(next);
			continue;
		}
		if (/category=unresolved_target/i.test(feedback)) {
			add(
				evidenceRecaptureQueue,
				"evidence_recapture",
				feedback,
				"operator feedback classified unresolved target",
				next,
			);
			nextOperatorQueue.push(next);
			continue;
		}
		if (
			/category=swarm_retry_queue/i.test(feedback) ||
			/category=(worker_retry_blocked|failure_budget_exhausted)/i.test(feedback)
		) {
			add(
				evidenceRecaptureQueue,
				"evidence_recapture",
				feedback,
				"operator feedback requires bounded worker retry",
				next,
			);
			nextOperatorQueue.push(next);
			continue;
		}
		if (/category=(dispatcher_gap|runtime_failure)/i.test(feedback)) {
			add(
				commandSubstitutions,
				"command_substitution",
				feedback,
				"operator feedback requires dispatcher/autofix reroute",
				next,
			);
			nextOperatorQueue.push(next);
			continue;
		}
		if (/category=replay_or_exploit_candidate/i.test(feedback)) {
			nextOperatorQueue.push(next, `re_exploit_lab run ${options.target ?? replay.target ?? "<target>"} 3 60000`);
		}
	}

	for (const gap of [...(compiler?.gaps ?? []), ...(compiler?.contradictions ?? [])].slice(0, 12)) {
		add(
			patchQueue,
			"patch",
			gap,
			"compiler gap/contradiction requires a repair scaffold before final claim",
			`re_operator escalate && re_compiler draft${(options.target ?? replay.target) ? ` ${options.target ?? replay.target}` : ""}`,
		);
	}

	if (failures.length === 0 && patchQueue.length === 0) {
		nextOperatorQueue.push("re_complete audit");
	} else {
		nextOperatorQueue.push(
			...patchQueue.map((item) => item.command),
			...commandSubstitutions.map((item) => item.command),
			...bootstrapQueue.map((item) => item.command),
			...evidenceRecaptureQueue.map((item) => item.command),
			...(compiler?.nextOperatorQueue ?? []),
			"re_replayer run",
			"re_complete audit",
		);
	}

	const applied =
		options.mode === "apply" ? Array.from(new Set([...nextOperatorQueue, ...replay.nextActions])).slice(0, 24) : [];
	if (options.mode === "apply" && applied.length > 0) {
		appendJournal(
			"autofix",
			`autofix queue ${replay.missionId ?? "no-mission"}`,
			[`replay_artifact: ${replayArtifact}`, `compiler_artifact: ${compilerPath ?? "none"}`, ...applied].join("\n"),
		);
		updateMissionGate("memory_or_evolution_written", "done", "autofix queue");
	}

	return {
		timestamp: new Date().toISOString(),
		missionId: replay.missionId ?? compiler?.missionId,
		route: replay.route ?? compiler?.route,
		target: options.target ?? replay.target ?? compiler?.target,
		mode: options.mode ?? "plan",
		replayArtifact,
		compilerArtifact: compilerPath,
		operatorFeedback,
		failures,
		patchQueue,
		commandSubstitutions,
		bootstrapQueue,
		evidenceRecaptureQueue,
		nextOperatorQueue: Array.from(new Set(nextOperatorQueue)).slice(0, 36),
		applied,
		sourceArtifacts,
	};
}

function formatAutofix(autofix: AutofixArtifact, path?: string): string {
	const formatItems = (items: AutofixItem[]) =>
		items.length ? items.map((item) => `- ${item.id} [${item.status}] ${item.command} # ${item.reason}`) : ["- none"];
	return [
		"autofix_plan:",
		path ? `autofix_artifact: ${path}` : undefined,
		`timestamp: ${autofix.timestamp}`,
		`mode: ${autofix.mode}`,
		`mission_id: ${autofix.missionId ?? "none"}`,
		`route: ${autofix.route ?? "none"}`,
		`target: ${autofix.target ?? "<none>"}`,
		`replay_artifact: ${autofix.replayArtifact ?? "none"}`,
		`compiler_artifact: ${autofix.compilerArtifact ?? "none"}`,
		"operator_feedback:",
		...((autofix.operatorFeedback ?? []).length
			? (autofix.operatorFeedback ?? []).map((item) => `- ${item}`)
			: ["- none"]),
		"failures:",
		...(autofix.failures.length ? autofix.failures.map((item) => `- ${item}`) : ["- none"]),
		"patch_queue:",
		...formatItems(autofix.patchQueue),
		"command_substitutions:",
		...formatItems(autofix.commandSubstitutions),
		"bootstrap_queue:",
		...formatItems(autofix.bootstrapQueue),
		"evidence_recapture_queue:",
		...formatItems(autofix.evidenceRecaptureQueue),
		"next_operator_queue:",
		...(autofix.nextOperatorQueue.length
			? autofix.nextOperatorQueue.map((item) => `- ${item}`)
			: ["- re_complete audit"]),
		"applied:",
		...(autofix.applied.length ? autofix.applied.map((item) => `- ${item}`) : ["- none"]),
		`next_autofix_command: ${autofix.mode === "apply" ? "re_replayer run" : "re_autofix apply"}`,
		"source_artifacts:",
		...(autofix.sourceArtifacts.length ? autofix.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeAutofixArtifact(autofix: AutofixArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceAutofixDir(),
		`${autofix.timestamp.replace(/[:.]/g, "-")}-${slug(autofix.route ?? "autofix")}-${autofix.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Autofix Artifact",
			"",
			formatAutofix(autofix, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(autofix, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: "artifact",
		title: `autofix-${autofix.mode} ${autofix.missionId ?? "no-mission"}`,
		fact: `Autofix ${autofix.mode}: failures=${autofix.failures.length}, patch=${autofix.patchQueue.length}, substitutions=${autofix.commandSubstitutions.length}, bootstrap=${autofix.bootstrapQueue.length}, recapture=${autofix.evidenceRecaptureQueue.length}, operator_feedback=${(autofix.operatorFeedback ?? []).length}`,
		command: `re_autofix ${autofix.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "replay/compile repair queue",
	});
	updateMissionGate("autofix_ready", "done", path);
	appendRuntimeFailureRepairFromAutofix(autofix, path);
	return path;
}

function buildAutofixOutput(action: "plan" | "show" | "apply" = "plan", options: { target?: string } = {}): string {
	if (action === "show") {
		const path = latestAutofixArtifactPath();
		if (!path) return "autofix_plan:\nstatus: missing\nnext: re_autofix plan";
		return truncateMiddle(readText(path), 20000);
	}
	const autofix = buildAutofix({ target: options.target, mode: action === "apply" ? "apply" : "plan" });
	const path = writeAutofixArtifact(autofix);
	return formatAutofix(autofix, path);
}

function latestProofLoopArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceProofLoopsDir(), 1)[0];
}

function proofLoopSourceArtifacts(): string[] {
	return Array.from(
		new Set(
			[
				currentMissionPath(),
				evidenceLedgerPath(),
				latestDecisionCoreArtifactPath(),
				latestOperatorArtifactPath(),
				latestDelegateArtifactPath(),
				latestSwarmArtifactPath(),
				latestSupervisorArtifactPath(),
				latestVerifierArtifactPath(),
				latestCompilerArtifactPath(),
				latestReplayerArtifactPath(),
				latestAutofixArtifactPath(),
				latestKnowledgeGraphArtifactPath(),
				...contextArtifactIndex().map((artifact) => artifact.path),
			].filter((path): path is string => Boolean(path && existsSync(path))),
		),
	).slice(0, 64);
}

function proofLoopBridgeArtifacts(): string[] {
	return [latestDelegateArtifactPath(), latestSwarmArtifactPath(), latestSupervisorArtifactPath()].filter(
		(path): path is string => Boolean(path && existsSync(path)),
	);
}

function proofLoopGateStatus(): string[] {
	const mission = readCurrentMission();
	return (
		mission?.gates
			.filter((gate) =>
				/decision_core_ready|operator_queue_ready|verifier_matrix_ready|compiler_ready|replay_ready|autofix_ready|proof_loop_ready|knowledge_graph_ready|report_or_writeup_ready/i.test(
					gate.name,
				),
			)
			.map((gate) => `${gate.name}: ${gate.status}${gate.note ? ` — ${truncateMiddle(gate.note, 140)}` : ""}`) ?? [
			"mission: missing",
		]
	);
}

function proofLoopVerdict(target?: string): ProofLoopVerdict {
	const replayPath = latestReplayerArtifactPath();
	const replay = replayPath ? parseReplayArtifact(replayPath) : undefined;
	const compilerPath = latestCompilerArtifactPath();
	const compiler = compilerPath ? parseCompilerArtifact(compilerPath) : undefined;
	const compactResume = latestReconCompactionResumeTelemetry().telemetry;
	const feedbackRows = latestOperatorFeedback(target).rows.filter(
		(row) => !/category=(strong_evidence|worker_retry_progress)/i.test(row),
	);
	if (compactResume?.commandStatus.some((row) => row.status === "blocked")) return "needs_repair";
	if (
		compactResume?.contractVerified &&
		compactResume.autoResumeTriggered &&
		compactResume.commandStatus.some((row) => row.status === "queued")
	)
		return "partial";
	if (compactResume?.contractVerified && compactResume.autoResumeTriggered && !compactResume.proofLoopEntered)
		return "partial";
	if (replay?.failed || replay?.blocked.length) return "needs_repair";
	if (compiler && (compiler.statusSummary.contradicted > 0 || compiler.contradictions.length > 0))
		return "needs_repair";
	if (
		feedbackRows.some((row) =>
			/category=(unresolved_target|dispatcher_gap|missing_tool_or_dependency|worker_retry_blocked|runtime_failure|failure_budget_exhausted)/i.test(
				row,
			),
		)
	)
		return "needs_repair";
	if (feedbackRows.length) return "partial";
	if (!compiler || !replay) return "partial";
	if (compiler.statusSummary.missing > 0 || compiler.statusSummary.weak > 0 || compiler.gaps.length > 0)
		return "partial";
	if (replay.executions.length === 0) return "partial";
	return replay.passed > 0 ? "ready" : "blocked";
}

function proofLoopEvidenceSummary(target?: string): string[] {
	const verifierPath = latestVerifierArtifactPath();
	const verifier = verifierPath ? parseVerifierArtifact(verifierPath) : undefined;
	const compilerPath = latestCompilerArtifactPath();
	const compiler = compilerPath ? parseCompilerArtifact(compilerPath) : undefined;
	const replayPath = latestReplayerArtifactPath();
	const replay = replayPath ? parseReplayArtifact(replayPath) : undefined;
	const autofixPath = latestAutofixArtifactPath();
	const autofix = autofixPath ? parseAutofixArtifact(autofixPath) : undefined;
	const feedback = latestOperatorFeedback(target);
	const compactResume = latestReconCompactionResumeTelemetry();
	return [
		`verifier: ${verifierPath ?? "missing"} assertions=${verifier?.assertions.length ?? 0} contradictions=${verifier?.contradictions.length ?? 0} gaps=${verifier?.gaps.length ?? 0}`,
		`compiler: ${compilerPath ?? "missing"} proved=${compiler?.statusSummary.proved ?? 0} weak=${compiler?.statusSummary.weak ?? 0} contradicted=${compiler?.statusSummary.contradicted ?? 0} missing=${compiler?.statusSummary.missing ?? 0}`,
		`replayer: ${replayPath ?? "missing"} executed=${replay?.executions.length ?? 0} passed=${replay?.passed ?? 0} failed=${replay?.failed ?? 0} blocked=${replay?.blocked.length ?? 0}`,
		`autofix: ${autofixPath ?? "missing"} failures=${autofix?.failures.length ?? 0} applied=${autofix?.applied.length ?? 0}`,
		`operator_feedback: rows=${feedback.rows.length} commands=${feedback.commands.length} sources=${feedback.sourceArtifacts.length}`,
		`compact_resume: ${compactResume.path} rows=${compactResume.lines.length} queued=${compactResume.telemetry?.commandStatus.filter((row) => row.status === "queued").length ?? 0} blocked=${compactResume.telemetry?.commandStatus.filter((row) => row.status === "blocked").length ?? 0} proof_loop_entered=${compactResume.telemetry?.proofLoopEntered ?? false}`,
	];
}

function parseAutofixArtifact(path: string): AutofixArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as AutofixArtifact;
	} catch {
		return undefined;
	}
}

function proofLoopWorkerForText(text: string, mission?: MissionState): DelegateWorker {
	const haystack = `${mission?.route.domain ?? ""}\n${mission?.task ?? ""}\n${text}`;
	if (
		/web-authz|web|api|http|xhr|fetch|websocket|graphql|jwt|cookie|session|idor|bola|authz|csrf|cors/i.test(haystack)
	)
		return "web-authz";
	if (/mobile|android|ios|apk|ipa|frida|objection|smali|jni|objc|swift|emulator/i.test(haystack))
		return "mobile-runtime";
	if (/cloud|container|docker|k8s|kubernetes|metadata|serviceaccount|iam|rbac|privilege/i.test(haystack))
		return "cloud";
	if (/credential|principal|kerberos|ldap|ntlm|ticket|hash|identity|active directory|bloodhound/i.test(haystack))
		return "identity";
	if (/firmware|pcap|dfir|forensic|rootfs|tshark|binwalk|extract|filesystem|emulate|timeline|decode/i.test(haystack))
		return "firmware-dfir";
	if (/agentsec|agent|prompt|tool-boundary|memory|injection|delegation|mcp|rag|sub-agent/i.test(haystack))
		return "agentsec";
	if (/malware|ioc|yara|capa|floss|static-config|behavior|c2/i.test(haystack)) return "malware";
	if (/pwn|exploit|primitive|mitigation|rop|heap|overflow|shellcode|pwntools|crash|leak|gadget/i.test(haystack))
		return "pwn-exploit";
	if (
		/native|elf|pe|macho|binary|gdb|lldb|checksec|r2|radare|ghidra|ida|symbol|breakpoint|loader|libc/i.test(haystack)
	)
		return "native-runtime";
	if (/report|complete|writeup|compiler|final/i.test(haystack)) return "reporting";
	return "general";
}

function proofLoopGapItems(target?: string): ProofLoopGapItem[] {
	const mission = readCurrentMission();
	const targetRef = target ?? mission?.task;
	const items: Array<Omit<ProofLoopGapItem, "worker">> = [];
	const add = (source: ProofLoopGapSource, text: string | undefined, sourceArtifacts: string[]) => {
		const normalized = text?.replace(/\s+/g, " ").trim();
		if (!normalized) return;
		items.push({
			source,
			text: truncateMiddle(normalized, 520),
			sourceArtifacts: Array.from(new Set(sourceArtifacts.filter((path) => existsSync(path)))).slice(0, 16),
		});
	};
	const verifierPath = latestVerifierArtifactPath();
	const verifier = verifierPath ? parseVerifierArtifact(verifierPath) : undefined;
	if (verifierPath && verifier) {
		const sourceArtifacts = [verifierPath, ...verifier.sourceArtifacts];
		for (const gap of verifier.gaps.slice(0, 8)) add("verifier", `gap: ${gap}`, sourceArtifacts);
		for (const contradiction of verifier.contradictions.slice(0, 8))
			add("verifier", `contradiction: ${contradiction}`, sourceArtifacts);
		for (const assertion of verifier.assertions.filter((item) => item.status !== "proved").slice(0, 8)) {
			add(
				"verifier",
				`${assertion.status}: ${assertion.id} ${assertion.claim}; followups=${assertion.requiredFollowups.join(" | ") || "none"}`,
				sourceArtifacts,
			);
		}
	} else {
		add("artifact", "verifier artifact missing: run re_verifier matrix before final claim", []);
	}
	const compilerPath = latestCompilerArtifactPath();
	const compiler = compilerPath ? parseCompilerArtifact(compilerPath) : undefined;
	if (compilerPath && compiler) {
		const sourceArtifacts = [compilerPath, ...compiler.sourceArtifacts];
		for (const gap of compiler.gaps.slice(0, 10)) add("compiler", `gap: ${gap}`, sourceArtifacts);
		for (const contradiction of compiler.contradictions.slice(0, 10))
			add("compiler", `contradiction: ${contradiction}`, sourceArtifacts);
		if (compiler.statusSummary.weak > 0 || compiler.statusSummary.missing > 0) {
			add(
				"compiler",
				`summary: weak=${compiler.statusSummary.weak} missing=${compiler.statusSummary.missing} next=${compiler.nextOperatorQueue.slice(0, 6).join(" | ")}`,
				sourceArtifacts,
			);
		}
	} else {
		add("artifact", "compiler artifact missing: run re_compiler draft before proof-loop completion", []);
	}
	const replayPath = latestReplayerArtifactPath();
	const replay = replayPath ? parseReplayArtifact(replayPath) : undefined;
	if (replayPath && replay) {
		const sourceArtifacts = [replayPath, ...replay.sourceArtifacts];
		for (const blocked of replay.blocked.slice(0, 10)) add("replayer", `blocked: ${blocked}`, sourceArtifacts);
		for (const execution of replay.executions.filter((item) => item.status === "failed").slice(0, 10)) {
			add(
				"replayer",
				`failed: ${execution.stepId} exit=${execution.exit} command=${execution.command} stderr=${truncateMiddle(execution.stderrHead, 220)}`,
				sourceArtifacts,
			);
		}
		if (replay.executions.length === 0)
			add("replayer", "no replay execution yet: run bounded replay", sourceArtifacts);
	} else {
		add("artifact", "replayer artifact missing: run re_replayer run <target> 1", []);
	}
	const autofixPath = latestAutofixArtifactPath();
	const autofix = autofixPath ? parseAutofixArtifact(autofixPath) : undefined;
	if (autofixPath && autofix) {
		const sourceArtifacts = [autofixPath, ...autofix.sourceArtifacts];
		for (const failure of autofix.failures.slice(0, 8)) add("autofix", `failure: ${failure}`, sourceArtifacts);
		for (const item of [
			...autofix.patchQueue,
			...autofix.commandSubstitutions,
			...autofix.bootstrapQueue,
			...autofix.evidenceRecaptureQueue,
		]
			.filter((entry) => entry.status !== "applied")
			.slice(0, 12)) {
			add("autofix", `${item.kind}: ${item.reason}; command=${item.command}`, [
				autofixPath,
				...item.sourceArtifacts,
			]);
		}
	}
	const feedback = latestOperatorFeedback(targetRef);
	for (const row of feedback.rows
		.filter((item) => !/category=(strong_evidence|worker_retry_progress)/i.test(item))
		.slice(0, 16)) {
		add("operator_feedback", row, feedback.sourceArtifacts);
	}
	const compactResume = latestReconCompactionResumeTelemetry();
	const compactTelemetry = compactResume.telemetry;
	if (compactTelemetry) {
		for (const row of compactTelemetry.commandStatus) {
			if (row.status === "queued")
				add("compact_resume", `queued compact resume command: ${row.command}`, [
					compactResume.path,
					...compactTelemetry.sourceArtifacts,
				]);
			if (row.status === "blocked")
				add(
					"compact_resume",
					`blocked compact resume command: ${row.command}${row.outputSha256 ? ` output_sha256=${row.outputSha256}` : ""}`,
					[compactResume.path, ...compactTelemetry.sourceArtifacts],
				);
		}
		if (
			compactTelemetry.contractVerified &&
			compactTelemetry.autoResumeTriggered &&
			!compactTelemetry.proofLoopEntered
		)
			add("compact_resume", "compact resume proof loop has not been entered yet", [
				compactResume.path,
				...compactTelemetry.sourceArtifacts,
			]);
	}
	for (const gate of proofLoopGateStatus()
		.filter((item) => /pending|blocked|missing/i.test(item))
		.slice(0, 12))
		add("gate", gate, proofLoopSourceArtifacts());
	const deduped = new Map<string, Omit<ProofLoopGapItem, "worker">>();
	for (const item of items) {
		const key = `${item.source}:${item.text}`;
		if (!deduped.has(key)) deduped.set(key, item);
	}
	return [...deduped.values()].slice(0, 32).map((item, index) => ({
		...item,
		text: item.text || `gap ${index + 1}`,
		worker: proofLoopWorkerForText(item.text, mission),
	}));
}

function proofLoopSpecialistQueue(target?: string): string[] {
	const suffix = proofLoopCommandTarget(target);
	return proofLoopGapItems(target)
		.map(
			(item, index) =>
				`proof-gap:${index + 1}:${item.worker} source=${item.source} evidence=${item.sourceArtifacts.slice(0, 3).join(" | ") || "none"} :: ${item.text} -> re_delegate plan${suffix}`,
		)
		.slice(0, 24);
}

function proofLoopSwarmRetryQueue(target?: string): string[] {
	const retry = latestSwarmRetryQueue(target);
	return retry.rows
		.map((row, index) => {
			const commands = /\bnext=(.+)$/i.exec(row)?.[1]?.trim() ?? "re_swarm run";
			return `swarm-retry:${index + 1}: ${row} :: commands=${commands}`;
		})
		.slice(0, 24);
}

function proofLoopSwarmBridge(target?: string): string[] {
	const suffix = proofLoopCommandTarget(target);
	const retry = latestSwarmRetryQueue(target);
	const feedback = latestOperatorFeedback(target);
	const feedbackRows = feedback.rows
		.filter((row) => !/category=(strong_evidence|worker_retry_progress)/i.test(row))
		.map(
			(row, index) =>
				`operator_feedback:${index + 1} next="${feedback.commands[index] ?? "re_operator dispatch"}" row=${row}`,
		);
	const retryRows = retry.rows.map(
		(row, index) =>
			`retry_queue:${index + 1} source=swarm next="${retry.commands[index] ?? "re_swarm run"}" row=${row}`,
	);
	const grouped = new Map<DelegateWorker, ProofLoopGapItem[]>();
	for (const item of proofLoopGapItems(target)) grouped.set(item.worker, [...(grouped.get(item.worker) ?? []), item]);
	const rows = [...grouped.entries()].map(([worker, items]) => {
		const contracts = delegateEvidenceContract(worker).join(" | ");
		const sources = Array.from(new Set(items.flatMap((item) => item.sourceArtifacts))).slice(0, 5);
		return `${worker}: gaps=${items.length} delegate="re_delegate plan${suffix}" swarm="re_swarm run${suffix} 2 1" swarm_merge="re_swarm merge" supervisor="re_supervisor repair${suffix}" evidence_contract=${contracts} sources=${sources.join(" | ") || "none"}`;
	});
	if (rows.length || retryRows.length || feedbackRows.length)
		return [...feedbackRows, ...retryRows, ...rows].slice(0, 16);
	return [
		`general: no active proof gaps; bridge standby -> re_swarm run${suffix} 2 1 && re_swarm merge && re_supervisor review${suffix}`,
	];
}

function proofLoopCommandTarget(target?: string): string {
	return target?.trim() ? ` ${target.trim()}` : "";
}

function buildProofLoopSteps(target?: string): ProofLoopStep[] {
	const suffix = proofLoopCommandTarget(target);
	const replayTarget = target?.trim() || "<target>";
	const sourceArtifacts = proofLoopSourceArtifacts();
	const operatorFeedbackCommands = latestOperatorFeedback(target).commands;
	const swarmRetryCommands = latestSwarmRetryQueue(target).commands;
	const compactResume = latestReconCompactionResumeTelemetry();
	const compactResumeCommands = compactResumeProofQueue();
	const specs: Array<[ProofLoopPhase, string]> = [
		["verifier", `re_verifier matrix${suffix}`],
		["compiler", `re_compiler draft${suffix}`],
		["replayer", `re_replayer run ${replayTarget} 2`],
		["autofix", `re_autofix plan${suffix}`],
		["autofix", `re_autofix apply${suffix}`],
		["replayer", `re_replayer run ${replayTarget} 1`],
		["compiler", `re_compiler final${suffix}`],
		["knowledge", `re_knowledge_graph build${suffix}`],
		["completion", "re_complete audit"],
	];
	const caseMemoryPlan = currentCaseMemoryLanePlan(target);
	if (caseMemoryPlan?.migrations.length) {
		specs.push(["case-memory", `re_autopilot plan${suffix}`]);
		if (caseMemoryPlan.action !== "none") specs.push(["case-memory", `re_autopilot run${suffix} 1`]);
	}
	for (const command of compactResumeCommands.slice(0, 4)) specs.push(["compact-resume", command]);
	for (const command of operatorFeedbackCommands.slice(0, 4)) specs.push(["operator-feedback", command]);
	for (const command of swarmRetryCommands.slice(0, 4)) specs.push(["swarm-retry", command]);
	return specs.map(([phase, command], index) => {
		const placeholderBlocked = /<target>/i.test(command) && !target;
		return {
			id: `proof:${index + 1}:${phase}`,
			phase,
			command,
			status: placeholderBlocked ? "blocked" : "ready",
			reason: placeholderBlocked
				? "target placeholder is unresolved"
				: phase === "compact-resume"
					? "source=compact_resume"
					: undefined,
			sourceArtifacts: phase === "compact-resume" ? [compactResume.path, ...sourceArtifacts] : sourceArtifacts,
		};
	});
}

function proofLoopNextActions(proof: ProofLoopArtifact): string[] {
	const ready = proof.steps.filter((step) => step.status === "ready");
	const target = proof.target ?? "<target>";
	const caseMemoryActions = caseMemoryOperatorCommands(proof.caseMemoryLanePlan, proof.target);
	const swarmRetryCommands = latestSwarmRetryQueue(proof.target).commands;
	const autonomousBudgetActions =
		proof.autonomousBudget?.nextActions ?? autonomousExecutionBudget(proof.target).nextActions;
	const needsSpecialistBridge =
		proof.verdict === "partial" || proof.verdict === "needs_repair" || proof.specialistQueue.length > 0;
	const specialistBridge = needsSpecialistBridge
		? [`re_delegate plan ${target}`, `re_swarm run ${target} 2 1`, "re_swarm merge", `re_supervisor repair ${target}`]
		: [];
	const base =
		proof.mode === "run"
			? [
					...specialistBridge,
					...(proof.verdict === "needs_repair" ? ["re_autofix apply", `re_replayer run ${target} 1`] : []),
					...(proof.verdict === "ready"
						? ["re_compiler final", "re_knowledge_graph build", "re_complete audit"]
						: []),
					...(proof.verdict === "partial" ? [`re_proof_loop run ${target} 4 ${proof.replaySteps}`] : []),
				]
			: [...specialistBridge, `re_proof_loop run ${target} 4 ${proof.replaySteps}`];
	return Array.from(
		new Set([
			...(proof.compactResumeQueue ?? []),
			...(proof.operatorFeedbackQueue ?? []),
			...autonomousBudgetActions,
			...swarmRetryCommands,
			...caseMemoryActions,
			...ready.slice(proof.executed.length, proof.executed.length + 6).map((step) => step.command),
			...base,
		]),
	).slice(0, 16);
}

function refreshProofLoop(proof: ProofLoopArtifact): ProofLoopArtifact {
	const verdict = proofLoopVerdict(proof.target);
	const operatorFeedback = latestOperatorFeedback(proof.target);
	const existingCommands = new Set(proof.steps.map((step) => step.command));
	const compactResume = latestReconCompactionResumeTelemetry();
	const compactResumeQueue = compactResumeProofQueue();
	const compactResumeSteps: ProofLoopStep[] = compactResumeQueue
		.filter((command) => !existingCommands.has(command))
		.slice(0, 4)
		.map((command, index) => ({
			id: `proof:${proof.steps.length + index + 1}:compact-resume`,
			phase: "compact-resume",
			command,
			status: /<target>/i.test(command) && !proof.target ? "blocked" : "ready",
			reason:
				/<target>/i.test(command) && !proof.target ? "target placeholder is unresolved" : "source=compact_resume",
			sourceArtifacts: [compactResume.path],
		}));
	const operatorFeedbackSteps: ProofLoopStep[] = operatorFeedback.commands
		.filter((command) => !existingCommands.has(command))
		.slice(0, 4)
		.map((command, index) => ({
			id: `proof:${proof.steps.length + index + 1}:operator-feedback`,
			phase: "operator-feedback",
			command,
			status: /<target>/i.test(command) && !proof.target ? "blocked" : "ready",
			reason: /<target>/i.test(command) && !proof.target ? "target placeholder is unresolved" : undefined,
			sourceArtifacts: operatorFeedback.sourceArtifacts,
		}));
	const steps = [...proof.steps, ...compactResumeSteps, ...operatorFeedbackSteps];
	const swarmRetry = proofLoopSwarmRetryQueue(proof.target);
	const specialistQueue = proofLoopSpecialistQueue(proof.target);
	const swarmBridge = proofLoopSwarmBridge(proof.target);
	const bridgeArtifacts = proofLoopBridgeArtifacts();
	const caseMemoryLanePlan = currentCaseMemoryLanePlan(proof.target);
	const caseMemoryBridge = caseMemoryProofBridge(caseMemoryLanePlan, proof.target);
	const autonomousBudget = autonomousExecutionBudget(proof.target);
	return {
		...proof,
		steps,
		verdict,
		gateStatus: proofLoopGateStatus(),
		evidenceSummary: proofLoopEvidenceSummary(proof.target),
		caseMemoryLanePlan,
		caseMemoryBridge,
		autonomousBudget,
		dispatcherScoreDecay: autonomousBudget.scoreDecay,
		repeatedFailureDemotions: autonomousBudget.demotionRules,
		highScorePromotions: autonomousBudget.promotionRules,
		compactResumeTelemetry: compactResume.lines,
		compactResumeQueue,
		operatorFeedback: operatorFeedback.rows,
		operatorFeedbackQueue: operatorFeedback.commands,
		swarmRetryQueue: swarmRetry,
		specialistQueue,
		swarmBridge,
		bridgeArtifacts,
		nextActions: proofLoopNextActions({
			...proof,
			steps,
			verdict,
			caseMemoryLanePlan,
			caseMemoryBridge,
			autonomousBudget,
			dispatcherScoreDecay: autonomousBudget.scoreDecay,
			repeatedFailureDemotions: autonomousBudget.demotionRules,
			highScorePromotions: autonomousBudget.promotionRules,
			compactResumeTelemetry: compactResume.lines,
			compactResumeQueue,
			operatorFeedback: operatorFeedback.rows,
			operatorFeedbackQueue: operatorFeedback.commands,
			swarmRetryQueue: swarmRetry,
			specialistQueue,
			swarmBridge,
			bridgeArtifacts,
		}),
		sourceArtifacts: Array.from(
			new Set(
				[
					...proofLoopSourceArtifacts(),
					autonomousBudget.dispatcherBoardPath,
					autonomousBudget.promotionPlaybookPath,
					compactResume.path,
					...operatorFeedback.sourceArtifacts,
					...bridgeArtifacts,
				].filter(Boolean) as string[],
			),
		).slice(0, 72),
	};
}

function buildProofLoop(
	options: { target?: string; mode?: "plan" | "run"; maxSteps?: number; replaySteps?: number } = {},
): ProofLoopArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const maxSteps = Math.max(1, Math.min(12, Math.floor(options.maxSteps ?? 4)));
	const replaySteps = Math.max(1, Math.min(10, Math.floor(options.replaySteps ?? 2)));
	return refreshProofLoop({
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route: mission?.route.domain,
		target: options.target ?? mission?.task,
		mode: options.mode ?? "plan",
		maxSteps,
		replaySteps,
		steps: buildProofLoopSteps(options.target ?? mission?.task),
		executed: [],
		verdict: "partial",
		gateStatus: [],
		evidenceSummary: [],
		caseMemoryLanePlan: undefined,
		caseMemoryBridge: [],
		autonomousBudget: autonomousExecutionBudget(options.target ?? mission?.task),
		dispatcherScoreDecay: [],
		repeatedFailureDemotions: [],
		highScorePromotions: [],
		compactResumeTelemetry: [],
		compactResumeQueue: [],
		operatorFeedback: [],
		operatorFeedbackQueue: [],
		swarmRetryQueue: [],
		specialistQueue: [],
		swarmBridge: [],
		bridgeArtifacts: [],
		nextActions: [],
		sourceArtifacts: proofLoopSourceArtifacts(),
	});
}

function formatProofLoop(proof: ProofLoopArtifact, path?: string): string {
	return [
		"proof_loop:",
		path ? `proof_loop_artifact: ${path}` : undefined,
		`timestamp: ${proof.timestamp}`,
		`mode: ${proof.mode}`,
		`mission_id: ${proof.missionId ?? "none"}`,
		`route: ${proof.route ?? "none"}`,
		`target: ${proof.target ?? "<none>"}`,
		`max_steps: ${proof.maxSteps}`,
		`replay_steps: ${proof.replaySteps}`,
		`verdict: ${proof.verdict}`,
		"gate_status:",
		...(proof.gateStatus.length ? proof.gateStatus.map((item) => `- ${item}`) : ["- none"]),
		"evidence_summary:",
		...(proof.evidenceSummary.length ? proof.evidenceSummary.map((item) => `- ${item}`) : ["- none"]),
		"case_memory_lane_plan:",
		...(proof.caseMemoryLanePlan
			? caseMemoryLanePlanLines(proof.caseMemoryLanePlan).map((item) => `- ${item}`)
			: ["- none"]),
		"case_memory_bridge:",
		...(proof.caseMemoryBridge.length ? proof.caseMemoryBridge.map((item) => `- ${item}`) : ["- none"]),
		"compact_resume_telemetry:",
		...(proof.compactResumeTelemetry.length ? proof.compactResumeTelemetry.map((item) => `- ${item}`) : ["- none"]),
		"compact_resume_queue:",
		...(proof.compactResumeQueue.length ? proof.compactResumeQueue.map((item) => `- ${item}`) : ["- none"]),
		"operator_feedback:",
		...(proof.operatorFeedback.length ? proof.operatorFeedback.map((item) => `- ${item}`) : ["- none"]),
		"operator_feedback_queue:",
		...(proof.operatorFeedbackQueue.length ? proof.operatorFeedbackQueue.map((item) => `- ${item}`) : ["- none"]),
		"swarm_retry_queue:",
		...(proof.swarmRetryQueue.length ? proof.swarmRetryQueue.map((item) => `- ${item}`) : ["- none"]),
		"specialist_queue:",
		...(proof.specialistQueue.length ? proof.specialistQueue.map((item) => `- ${item}`) : ["- none"]),
		"swarm_bridge:",
		...(proof.swarmBridge.length ? proof.swarmBridge.map((item) => `- ${item}`) : ["- none"]),
		"autonomous_execution_budget:",
		...autonomousBudgetLines(proof.autonomousBudget).map((item) => `- ${item}`),
		"dispatcher_score_decay:",
		...(proof.dispatcherScoreDecay?.length ? proof.dispatcherScoreDecay.map((item) => `- ${item}`) : ["- none"]),
		"repeated_failure_demotions:",
		...(proof.repeatedFailureDemotions?.length
			? proof.repeatedFailureDemotions.map((item) => `- ${item}`)
			: ["- none"]),
		"high_score_promotions:",
		...(proof.highScorePromotions?.length ? proof.highScorePromotions.map((item) => `- ${item}`) : ["- none"]),
		"bridge_artifacts:",
		...(proof.bridgeArtifacts.length ? proof.bridgeArtifacts.map((item) => `- ${item}`) : ["- none"]),
		"steps:",
		...(proof.steps.length
			? proof.steps.map(
					(step) => `- ${step.id} [${step.status}] ${step.command}${step.reason ? ` # ${step.reason}` : ""}`,
				)
			: ["- none"]),
		`executed_steps: ${proof.executed.length}`,
		...(proof.executed.length
			? proof.executed.map(
					(item) =>
						`- ${item.stepId} [${item.status}] ${item.command} :: ${truncateMiddle(item.output.replace(/\s+/g, " "), 260)}`,
				)
			: []),
		"next_proof_actions:",
		...(proof.nextActions.length ? proof.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_proof_command: ${
			proof.mode === "run"
				? proof.verdict === "ready"
					? "re_complete audit"
					: `re_proof_loop run ${proof.target ?? "<target>"} 4 ${proof.replaySteps}`
				: `re_proof_loop run ${proof.target ?? "<target>"} ${proof.maxSteps} ${proof.replaySteps}`
		}`,
		"source_artifacts:",
		...(proof.sourceArtifacts.length ? proof.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeProofLoopArtifact(proof: ProofLoopArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceProofLoopsDir(),
		`${proof.timestamp.replace(/[:.]/g, "-")}-${slug(proof.route ?? "proof-loop")}-${proof.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Proof Loop Artifact",
			"",
			formatProofLoop(proof, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(proof, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	appendEvidence({
		kind: proof.mode === "run" ? "runtime" : "artifact",
		title: `proof-loop-${proof.mode} ${proof.missionId ?? "no-mission"}`,
		fact: `Proof loop ${proof.mode}: verdict=${proof.verdict}, executed=${proof.executed.length}, replay_steps=${proof.replaySteps}, compact_resume_queue=${proof.compactResumeQueue.length}, compact_resume_telemetry=${proof.compactResumeTelemetry.length}, operator_feedback=${proof.operatorFeedback.length}, operator_feedback_queue=${proof.operatorFeedbackQueue.length}, swarm_retry_queue=${proof.swarmRetryQueue.length}, specialist_queue=${proof.specialistQueue.length}, swarm_bridge=${proof.swarmBridge.length}, autonomous_budget=${proof.autonomousBudget?.maxTurns ?? "none"}/${proof.autonomousBudget?.maxProofLoops ?? "none"}, score_decay=${(proof.dispatcherScoreDecay ?? []).length}, demotions=${(proof.repeatedFailureDemotions ?? []).length}, promotions=${(proof.highScorePromotions ?? []).length}, case_memory_lane_plan=${proof.caseMemoryLanePlan?.action ?? "none"}`,
		command: `re_proof_loop ${proof.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "verifier/compiler/replayer/autofix bounded proof loop",
	});
	updateMissionGate("proof_loop_ready", proof.verdict === "blocked" ? "blocked" : "done", path);
	appendRuntimeFailureRepairFromProofLoop(proof, path);
	return path;
}

async function executeProofLoopStep(
	pi: ExtensionAPI,
	step: ProofLoopStep,
	target?: string,
	replaySteps = 2,
): Promise<OperationExecution> {
	const done = (output: string): OperationExecution => ({
		stepId: step.id,
		command: step.command,
		status: "done",
		output,
	});
	const blocked = (output: string): OperationExecution => ({
		stepId: step.id,
		command: step.command,
		status: "blocked",
		output,
	});
	if (step.status === "blocked") return blocked(step.reason ?? "proof loop step blocked");
	switch (step.phase) {
		case "compact-resume": {
			const concrete = operatorCommandConcrete(step.command, target);
			if (concrete.blocked) return blocked(concrete.blocked);
			if (/^re[-_]proof[-_]loop\s+run\b/i.test(concrete.command))
				return done(`compact resume proof loop entered by current re_proof_loop run; command=${concrete.command}`);
			return executeOperatorStep(
				pi,
				{
					id: step.id,
					command: concrete.command,
					status: "ready",
					priority: operatorStepPriority(concrete.command),
					sourceArtifacts: step.sourceArtifacts,
				},
				target,
			);
		}
		case "operator-feedback":
		case "swarm-retry":
			return executeOperatorStep(
				pi,
				{
					id: step.id,
					command: step.command,
					status: "ready",
					priority: operatorStepPriority(step.command),
					sourceArtifacts: step.sourceArtifacts,
				},
				target,
			);
		case "verifier":
			return done(buildVerifierOutput("matrix", { target }));
		case "compiler": {
			const action = /\sfinal\b/i.test(step.command) ? "final" : "draft";
			return done(buildCompilerOutput(action, { target }));
		}
		case "replayer":
			return done(await runReplayer(pi, { target, maxSteps: replaySteps }));
		case "autofix": {
			const action = /\sapply\b/i.test(step.command) ? "apply" : "plan";
			return done(buildAutofixOutput(action, { target }));
		}
		case "case-memory": {
			const action = /\splan\b/i.test(step.command) ? "plan" : "run";
			const maxAutoSteps = /(?:^|\s)(\d+)\s*$/.exec(step.command)?.[1];
			return done(await runAutopilot(pi, { action, target, maxAutoSteps: maxAutoSteps ? Number(maxAutoSteps) : 1 }));
		}
		case "knowledge":
			return done(buildKnowledgeGraphOutput("build", { target }));
		case "completion":
			return done(formatCompletionAudit());
	}
}

async function executeProofLoopBridgeStep(
	pi: ExtensionAPI,
	kind: "delegate" | "swarm" | "supervisor",
	target?: string,
	repairMode = false,
): Promise<OperationExecution> {
	const command =
		kind === "delegate"
			? `re_delegate plan${proofLoopCommandTarget(target)}`
			: kind === "swarm"
				? `re_swarm run${proofLoopCommandTarget(target)} 2 1 && re_swarm merge`
				: `re_supervisor ${repairMode ? "repair" : "review"}${proofLoopCommandTarget(target)}`;
	const output =
		kind === "delegate"
			? buildDelegateOutput("plan", { target })
			: kind === "swarm"
				? `${await runSwarm(pi, { target, maxWorkers: 2, maxCommands: 1 })}\n\n${buildSwarmOutput("merge", { target })}`
				: buildSupervisorOutput(repairMode ? "repair" : "review", { target });
	return {
		stepId: `proof:bridge:${kind}`,
		command,
		status: "done",
		output,
	};
}

async function runProofLoop(
	pi: ExtensionAPI,
	options: { target?: string; maxSteps?: number; replaySteps?: number } = {},
): Promise<string> {
	let proof = buildProofLoop({ ...options, mode: "run" });
	let remaining = proof.maxSteps;
	const runStep = async (step: ProofLoopStep, replaySteps = proof.replaySteps) => {
		if (remaining <= 0) return;
		const result = await executeProofLoopStep(pi, step, proof.target, replaySteps);
		proof.executed.push(result);
		step.status = result.status === "blocked" ? "blocked" : "done";
		step.reason = result.status === "blocked" ? result.output : step.reason;
		remaining -= 1;
		proof = refreshProofLoop(proof);
	};
	const stepById = (id: string) => proof.steps.find((step) => step.id === id && step.status === "ready");
	for (const step of proof.steps.filter((item) => item.phase === "compact-resume" && item.status === "ready")) {
		if (remaining <= 0) break;
		await runStep(step, 1);
	}
	for (const id of ["proof:1:verifier", "proof:2:compiler", "proof:3:replayer"]) {
		const step = stepById(id);
		if (step) await runStep(step, proof.replaySteps);
	}
	if (
		(proof.verdict === "needs_repair" || proof.verdict === "partial") &&
		proof.caseMemoryLanePlan?.migrations.length &&
		remaining > 0
	) {
		for (const step of proof.steps.filter((item) => item.phase === "case-memory" && item.status === "ready")) {
			if (remaining <= 0) break;
			await runStep(step, 1);
		}
	}
	if (
		(proof.verdict === "needs_repair" || proof.verdict === "partial") &&
		proof.operatorFeedbackQueue.length > 0 &&
		remaining > 0
	) {
		for (const step of proof.steps.filter((item) => item.phase === "operator-feedback" && item.status === "ready")) {
			if (remaining <= 0) break;
			await runStep(step, 1);
		}
	}
	if (
		(proof.verdict === "needs_repair" || proof.verdict === "partial") &&
		proof.swarmRetryQueue.length > 0 &&
		remaining > 0
	) {
		for (const step of proof.steps.filter((item) => item.phase === "swarm-retry" && item.status === "ready")) {
			if (remaining <= 0) break;
			await runStep(step, 1);
		}
	}
	if (
		(proof.verdict === "needs_repair" || proof.verdict === "partial") &&
		proof.specialistQueue.length > 0 &&
		remaining > 0
	) {
		for (const kind of ["delegate", "swarm", "supervisor"] as const) {
			if (remaining <= 0) break;
			const result = await executeProofLoopBridgeStep(pi, kind, proof.target, proof.verdict === "needs_repair");
			proof.executed.push(result);
			remaining -= 1;
			proof = refreshProofLoop(proof);
		}
	}
	if (proof.verdict === "needs_repair") {
		for (const id of ["proof:4:autofix", "proof:5:autofix", "proof:6:replayer"]) {
			const step = stepById(id);
			if (step) await runStep(step, id === "proof:6:replayer" ? 1 : proof.replaySteps);
		}
	}
	if (proof.verdict === "ready") {
		for (const id of ["proof:7:compiler", "proof:8:knowledge", "proof:9:completion"]) {
			const step = stepById(id);
			if (step) await runStep(step, proof.replaySteps);
		}
	}
	updateReconCompactionTelemetryFromExecutions(proof.executed, proof.sourceArtifacts);
	proof = refreshProofLoop(proof);
	const path = writeProofLoopArtifact(proof);
	return formatProofLoop(proof, path);
}

function buildProofLoopOutput(
	action: "plan" | "show" | "run" = "plan",
	options: { target?: string; maxSteps?: number; replaySteps?: number } = {},
): string {
	if (action === "show") {
		const path = latestProofLoopArtifactPath();
		if (!path) return "proof_loop:\nstatus: missing\nnext: re_proof_loop plan <target>";
		return truncateMiddle(readText(path), 20000);
	}
	const proof = buildProofLoop({ ...options, mode: "plan" });
	const path = writeProofLoopArtifact(proof);
	return formatProofLoop(proof, path);
}

function latestKnowledgeGraphArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceKnowledgeDir(), 1)[0];
}

function compactResumeKnowledgeSignals(target?: string): {
	path: string;
	lines: string[];
	caseMemory: string[];
	routingHints: string[];
	commandHints: string[];
	sourceArtifacts: string[];
	status: "missing" | "queued" | "blocked" | "partial" | "done";
} {
	const latest = latestReconCompactionResumeTelemetry();
	const telemetry = latest.telemetry;
	if (!telemetry && latest.lines.length === 0) {
		return {
			path: latest.path,
			lines: [],
			caseMemory: [],
			routingHints: [],
			commandHints: [],
			sourceArtifacts: [],
			status: "missing",
		};
	}
	const queued = telemetry?.commandStatus.filter((row) => row.status === "queued") ?? [];
	const blocked = telemetry?.commandStatus.filter((row) => row.status === "blocked") ?? [];
	const done = telemetry?.commandStatus.filter((row) => row.status === "done") ?? [];
	const status: "queued" | "blocked" | "partial" | "done" = blocked.length
		? "blocked"
		: queued.length
			? "queued"
			: telemetry?.contractVerified && telemetry.autoResumeTriggered && !telemetry.proofLoopEntered
				? "partial"
				: "done";
	const targetRef = target?.trim() || "<target>";
	const commandHints = Array.from(
		new Set([
			...queued.map((row) => row.command),
			...(status !== "done" ? [`re_proof_loop run ${targetRef} 4 2`] : []),
			"re_knowledge_graph build",
			"re_complete audit",
		]),
	).slice(0, 12);
	const caseMemory = [
		[
			"compact_resume_case_memory",
			`status=${status}`,
			`contract_verified=${telemetry?.contractVerified ?? false}`,
			`auto_resume=${telemetry?.autoResumeTriggered ?? false}`,
			`proof_loop_entered=${telemetry?.proofLoopEntered ?? false}`,
			`queued=${queued.length}`,
			`blocked=${blocked.length}`,
			`done=${done.length}`,
			`context_path=${telemetry?.contextPath ?? "none"}`,
		].join(" "),
		...blocked
			.slice(0, 6)
			.map((row) =>
				[
					"compact_resume_repair",
					`command=${shellQuote(row.command)}`,
					row.outputSha256 ? `output_sha256=${row.outputSha256}` : undefined,
					`source=${latest.path}`,
				]
					.filter(Boolean)
					.join(" "),
			),
		...queued
			.slice(0, 6)
			.map((row) => `compact_resume_queue command=${shellQuote(row.command)} next=${shellQuote(row.command)}`),
		...(status === "done" && telemetry?.proofLoopEntered
			? [`compact_resume_success resume_contract_survived=true proof_loop_entered=true source=${latest.path}`]
			: []),
	].slice(0, 20);
	const routingHints = [
		...(blocked.length
			? [
					`compact_resume_routing status=blocked -> re_operator plan ${targetRef}; re_autofix plan ${targetRef}; re_proof_loop run ${targetRef} 4 2`,
				]
			: []),
		...(queued.length
			? queued.slice(0, 6).map((row) => `compact_resume_routing status=queued -> ${row.command}`)
			: []),
		...(telemetry?.contractVerified && telemetry.autoResumeTriggered && !telemetry.proofLoopEntered
			? [`compact_resume_routing proof_loop_missing -> re_proof_loop run ${targetRef} 4 2`]
			: []),
		...(status === "done"
			? [`compact_resume_routing status=done -> re_knowledge_graph build ${targetRef}; re_complete audit`]
			: []),
	].slice(0, 20);
	return {
		path: latest.path,
		lines: latest.lines,
		caseMemory,
		routingHints,
		commandHints,
		sourceArtifacts: Array.from(new Set([latest.path, ...(telemetry?.sourceArtifacts ?? [])])).slice(0, 40),
		status,
	};
}

function knowledgeArtifactSources(limitPerKind = 5): Array<{ kind: string; path: string; text: string }> {
	const specs: Array<[string, string]> = [
		["map", evidenceMapsDir()],
		["browser", evidenceBrowserDir()],
		["web_authz", evidenceWebAuthzDir()],
		["exploit_lab", evidenceExploitLabDir()],
		["mobile_runtime", evidenceMobileRuntimeDir()],
		["native_runtime", evidenceNativeRuntimeDir()],
		["run", evidenceRunsDir()],
		["attack_graph", evidenceGraphsDir()],
		["exploit_chain", evidenceChainsDir()],
		["decision_core", evidenceDecisionsDir()],
		["campaign", evidenceCampaignsDir()],
		["operation", evidenceOperationsDir()],
		["delegation", evidenceDelegationsDir()],
		["swarm", evidenceSwarmsDir()],
		["supervisor", evidenceSupervisorsDir()],
		["reflection", evidenceReflectionsDir()],
		["context", evidenceContextsDir()],
		["operator", evidenceOperatorsDir()],
		["verifier", evidenceVerifiersDir()],
		["compiler", evidenceCompilersDir()],
		["replayer", evidenceReplayersDir()],
		["autofix", evidenceAutofixDir()],
		["proof_loop", evidenceProofLoopsDir()],
	];
	return specs.flatMap(([kind, dir]) =>
		recentMarkdownArtifacts(dir, limitPerKind).map((path) => ({
			kind,
			path,
			text: truncateMiddle(readText(path), 7000),
		})),
	);
}

function knowledgeTags(text: string, kind: string): string[] {
	const tags = new Set<string>([kind]);
	const patterns: Array<[RegExp, string]> = [
		[/decision_core|decision_artifact|objective_stack|gate_pressure|operator_next_command/i, "decision-core"],
		[/exploit_chain|chain_nodes|proof_path|exploit_path|operator_queue|chain_artifact/i, "exploit-chain"],
		[/web_authz|web-authz|authorization|authz|object ownership|idor|bola|cookie|jwt|oauth|csrf/i, "web-authz-state"],
		[/websocket|fetch|xhr|cookie|jwt|idor|bola|graphql|csrf|oauth/i, "web-authz"],
		[/sign|signature|crypto|nonce|timestamp|encrypt|decrypt|subtle/i, "js-signing"],
		[/exploit_lab|exploit-lab|flake|success_rate|poc|autopwn/i, "exploit-lab"],
		[/mobile_runtime|mobile-runtime|frida|adb|apk|jni|smali|android/i, "mobile-runtime"],
		[/native_runtime|native-runtime|elf|rop|libc|gdb|crash|cyclic|one_gadget|heap|tcache|canary/i, "native-runtime"],
		[/pcap|tshark|stream|dns|tls|http object|credential/i, "pcap-dfir"],
		[/firmware|squashfs|ubifs|binwalk|rootfs|qemu|nvram/i, "firmware"],
		[/aws|azure|gcp|k8s|kubernetes|metadata|iam|rbac|serviceaccount/i, "cloud"],
		[/ldap|kerberos|ntlm|bloodhound|certipy|spn|adcs|domain/i, "identity"],
		[/malware|yara|capa|floss|ioc|c2|sandbox/i, "malware"],
		[/prompt injection|tool boundary|memory poisoning|agent|mcp/i, "agentsec"],
		[/proved|verifier|assertion|counter_evidence/i, "verification"],
		[/replay_matrix|stdout_sha256|stderr_sha256|replay_ready/i, "replay"],
		[/autofix|patch_queue|bootstrap_queue|evidence_recapture/i, "repair"],
		[
			/pi-recon-compaction|compact_resume|compaction_auto_resume|compaction-auto-resume|re_context resume/i,
			"compact-resume",
		],
		[
			/dispatcher_feedback|dispatcher_score|dispatcher_fallback_plan|operator_feedback_runtime|autonomous_execution_budget|score_decay|dispatcher-promotion-playbook/i,
			"dispatcher-feedback",
		],
	];
	for (const [pattern, tag] of patterns) if (pattern.test(text)) tags.add(tag);
	return Array.from(tags).slice(0, 12);
}

function knowledgeScore(kind: string, text: string): number {
	let score = 20;
	if (/runtime|exit:|stdout_sha256|proved|evidence_quality|artifact:|path:|verify:/i.test(text)) score += 25;
	if (/contradiction|failed|blocked|gap|repair|autofix/i.test(text)) score += 15;
	if (/key_evidence_block|repro_commands|replay_matrix|patch_queue|worker_packets|attack_graph/i.test(text))
		score += 20;
	if (kind === "run" || kind === "replayer") score += 20;
	if (kind === "verifier" || kind === "compiler" || kind === "autofix") score += 15;
	return Math.min(100, score);
}

function knowledgeCommandHints(text: string): string[] {
	const lines = text
		.split(/\r?\n/)
		.map((line) => line.trim().replace(/^- /, ""))
		.filter(Boolean)
		.filter((line) =>
			/^(re_|re-|\/re-|curl|python|node|gdb|r2|radare2|objdump|tshark|binwalk|kubectl|aws|az|gcloud|nmap|ffuf|rg|cat|test|timeout)\b/i.test(
				line,
			),
		)
		.map((line) => line.replace(/^\//, ""))
		.slice(0, 60);
	return Array.from(new Set(lines)).slice(0, 18);
}

function knowledgeWorkerHints(tags: string[]): string[] {
	const workers = new Set<string>();
	const add = (tag: string, worker: string) => {
		if (tags.includes(tag)) workers.add(worker);
	};
	add("decision-core", "worker:commander -> decision core gate pressure + operator_next_command arbitration");
	add("exploit-chain", "worker:commander -> exploit chain composer + proof path/replay queue");
	add("web-authz", "worker:web-authz -> browser/XHR/WS + authz state replay");
	add("js-signing", "worker:jsre -> signing normalizer + first-divergence harness");
	add("pwn", "worker:pwn-exploit -> primitive/leak/ROP verifier");
	add("pcap-dfir", "worker:firmware-dfir -> stream ranking + transform-chain extraction");
	add("firmware", "worker:firmware-dfir -> rootfs/service/emulation chain");
	add("cloud", "worker:cloud -> identity/RBAC/metadata edge proof");
	add("identity", "worker:identity -> principal/credential/graph edge proof");
	add("malware", "worker:malware -> config/IOC/behavior replay");
	add("agentsec", "worker:agentsec -> prompt/tool/memory boundary replay");
	add("repair", "worker:supervisor -> autofix/replay repair queue");
	add("dispatcher-feedback", "worker:commander -> dispatcher feedback scoring + fallback route promotion");
	add(
		"compact-resume",
		"worker:commander -> compact resume contract, telemetry, proof-loop recovery, and case-memory promotion",
	);
	if (workers.size === 0) workers.add("worker:general -> map→prove→verify→replay loop");
	return Array.from(workers).slice(0, 12);
}

function buildKnowledgeGraph(
	options: { target?: string; query?: string; mode?: "build" | "query" } = {},
): KnowledgeGraphArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const sources = knowledgeArtifactSources();
	const query = options.query?.trim().toLowerCase();
	const nodes: KnowledgeNode[] = [];
	const edges: KnowledgeEdge[] = [];
	const tagToNode = new Map<string, string>();
	const route = mission?.route.domain;
	const missionId = mission?.id;
	const missionNodeId = missionId ? `mission:${missionId}` : "mission:none";
	nodes.push({
		id: missionNodeId,
		kind: "mission",
		label: mission ? `${mission.route.domain}: ${truncateMiddle(mission.task, 120)}` : "no active mission",
		route,
		score: 50,
		tags: ["mission"],
	});
	const filtered = query
		? sources.filter((source) => `${source.kind}\n${source.path}\n${source.text}`.toLowerCase().includes(query))
		: sources;
	for (const [index, source] of filtered.entries()) {
		const tags = knowledgeTags(source.text, source.kind);
		const id = `artifact:${index + 1}:${source.kind}:${slug(source.path).slice(0, 28)}`;
		nodes.push({
			id,
			kind: source.kind,
			label: `${source.kind}: ${source.path}`,
			path: source.path,
			route,
			score: knowledgeScore(source.kind, source.text),
			tags,
		});
		edges.push({ from: missionNodeId, to: id, kind: "contains", label: source.kind });
		if (index > 0) {
			const previous = filtered[index - 1]!;
			edges.push({
				from: `artifact:${index}:${previous.kind}:${slug(previous.path).slice(0, 28)}`,
				to: id,
				kind: "derived_from",
				label: "recent-sequence",
			});
		}
		for (const tag of tags) {
			let tagNode = tagToNode.get(tag);
			if (!tagNode) {
				tagNode = `tag:${slug(tag)}`;
				tagToNode.set(tag, tagNode);
				nodes.push({ id: tagNode, kind: "tag", label: tag, route, score: 40, tags: [tag] });
			}
			edges.push({
				from: id,
				to: tagNode,
				kind:
					tag === "repair"
						? "repairs"
						: tag === "verification"
							? "verifies"
							: tag === "replay"
								? "replays"
								: "suggests",
				label: tag,
			});
		}
	}
	const scoreboard = latestWorkerScoreboard();
	for (const entry of scoreboard.entries) {
		const id = `worker-score:${entry.worker}:${slug(entry.packetId).slice(0, 24)}`;
		nodes.push({
			id,
			kind: "worker_score",
			label: `${entry.worker} ${entry.verdict} score=${entry.score}`,
			path: scoreboard.path,
			route,
			score: entry.score,
			tags: ["worker-score", entry.worker, entry.verdict],
		});
		edges.push({
			from: missionNodeId,
			to: id,
			kind: entry.score >= 80 ? "suggests" : "repairs",
			label: "worker-scoreboard",
		});
	}
	const adaptiveRoutingHints = Array.from(
		new Set([
			...workerAdaptiveRoutingHints(scoreboard.entries, options.target ?? mission?.task),
			...dispatcherAdaptiveRoutingHints(options.target ?? mission?.task),
		]),
	).slice(0, 32);
	const workerPromotionQueue = Array.from(
		new Set([
			...buildWorkerPromotionQueue(scoreboard.entries, options.target ?? mission?.task),
			...dispatcherPromotionQueue(options.target ?? mission?.task),
		]),
	).slice(0, 24);
	const dispatcherBoard = latestDispatcherFeedbackBoard();
	const autonomousBudget = autonomousExecutionBudget(options.target ?? mission?.task, dispatcherBoard.lines);
	const dispatcherScoreDecay = autonomousBudget.scoreDecay;
	const repeatedFailureDemotions = autonomousBudget.demotionRules;
	const highScorePromotions = autonomousBudget.promotionRules;
	for (const [index, line] of dispatcherBoard.lines.slice(0, 16).entries()) {
		const category = /\bcategory=([A-Za-z0-9_-]+)/.exec(line)?.[1] ?? "unknown";
		const score = Number(/\bscore=(\d+)/.exec(line)?.[1] ?? 45);
		const id = `dispatcher-feedback:${index + 1}:${slug(category).slice(0, 20)}`;
		nodes.push({
			id,
			kind: "dispatcher_feedback",
			label: truncateMiddle(line, 160),
			path: dispatcherBoard.path,
			route,
			score,
			tags: ["dispatcher-feedback", category, /\bstatus=passed\b/.test(line) ? "passed" : "repair"],
		});
		edges.push({
			from: missionNodeId,
			to: id,
			kind: score >= 80 ? "suggests" : "repairs",
			label: "dispatcher-feedback-scoreboard",
		});
	}
	for (const [index, line] of dispatcherScoreDecay.slice(0, 12).entries()) {
		const effective = Number(/\beffective=(\d+)/.exec(line)?.[1] ?? 45);
		const id = `dispatcher-score-decay:${index + 1}`;
		nodes.push({
			id,
			kind: "dispatcher_score_decay",
			label: truncateMiddle(line, 160),
			path: dispatcherBoard.path,
			route,
			score: effective,
			tags: ["score-decay", /demote_dispatcher/.test(line) ? "repair" : "adaptive"],
		});
		edges.push({
			from: missionNodeId,
			to: id,
			kind: effective < 50 ? "repairs" : "suggests",
			label: "dispatcher-score-decay",
		});
	}
	for (const [index, line] of repeatedFailureDemotions.slice(0, 12).entries()) {
		const id = `dispatcher-demotion:${index + 1}`;
		nodes.push({
			id,
			kind: "dispatcher_demotion",
			label: truncateMiddle(line, 160),
			path: autonomousBudget.promotionPlaybookPath ?? dispatcherBoard.path,
			route,
			score: 35,
			tags: ["demotion", "dispatcher-feedback", "repair"],
		});
		edges.push({ from: missionNodeId, to: id, kind: "repairs", label: "repeated-failure-demotion" });
	}
	for (const [index, line] of highScorePromotions.slice(0, 12).entries()) {
		const score = Number(/\bscore=(\d+)/.exec(line)?.[1] ?? 88);
		const id = `dispatcher-promotion:${index + 1}`;
		nodes.push({
			id,
			kind: "dispatcher_promotion",
			label: truncateMiddle(line, 160),
			path: autonomousBudget.promotionPlaybookPath ?? dispatcherBoard.path,
			route,
			score,
			tags: ["promotion", "dispatcher-feedback", "playbook"],
		});
		edges.push({ from: missionNodeId, to: id, kind: "suggests", label: "high-score-promotion" });
	}
	const compactResumeSignals = compactResumeKnowledgeSignals(options.target ?? mission?.task);
	if (compactResumeSignals.lines.length || compactResumeSignals.caseMemory.length) {
		const id = "compact-resume:telemetry";
		nodes.push({
			id,
			kind: "compact_resume_telemetry",
			label: `compact resume ${compactResumeSignals.status}: ${compactResumeSignals.path}`,
			path: compactResumeSignals.path,
			route,
			score: compactResumeSignals.status === "done" ? 85 : compactResumeSignals.status === "blocked" ? 45 : 65,
			tags: [
				"compact-resume",
				"context-resume",
				compactResumeSignals.status,
				...(compactResumeSignals.status === "blocked" ? ["repair"] : ["playbook"]),
			],
		});
		edges.push({
			from: missionNodeId,
			to: id,
			kind: compactResumeSignals.status === "blocked" ? "repairs" : "suggests",
			label: "compact-resume-telemetry",
		});
		for (const [index, line] of compactResumeSignals.caseMemory.slice(0, 12).entries()) {
			const nodeId = `compact-resume-case:${index + 1}`;
			nodes.push({
				id: nodeId,
				kind: "compact_resume_case_memory",
				label: truncateMiddle(line, 180),
				path: compactResumeSignals.path,
				route,
				score: /status=done|compact_resume_success/.test(line)
					? 88
					: /status=blocked|compact_resume_repair/.test(line)
						? 55
						: 70,
				tags: ["compact-resume", "case-memory", /repair|blocked/.test(line) ? "repair" : "playbook"],
			});
			edges.push({
				from: id,
				to: nodeId,
				kind: /repair|blocked/.test(line) ? "repairs" : "suggests",
				label: "compact-resume-case-memory",
			});
		}
	}
	const dispatcherRoutingHints = dispatcherBoard.hints.slice(0, 24);
	const allTags = Array.from(new Set(nodes.flatMap((node) => node.tags))).filter((tag) => tag !== "mission");
	const caseSignatures = [
		`route=${route ?? "unknown"}`,
		`target=${options.target ?? mission?.task ?? "<none>"}`,
		`tags=${allTags.slice(0, 16).join(",") || "none"}`,
		`artifacts=${filtered.length}`,
		`high_score=${nodes.filter((node) => node.score >= 70).length}`,
		`worker_scoreboard=${scoreboard.entries.length}`,
		`adaptive_routes=${adaptiveRoutingHints.length}`,
		`worker_promotions=${workerPromotionQueue.length}`,
		`dispatcher_feedback=${dispatcherBoard.lines.length}`,
		`dispatcher_routes=${dispatcherRoutingHints.length}`,
		`autonomous_budget=${autonomousBudget.maxTurns}/${autonomousBudget.maxDispatch}/${autonomousBudget.maxProofLoops}`,
		`score_decay=${dispatcherScoreDecay.length}`,
		`demotions=${repeatedFailureDemotions.length}`,
		`promotions=${highScorePromotions.length}`,
		`compact_resume_status=${compactResumeSignals.status}`,
		`compact_resume_case_memory=${compactResumeSignals.caseMemory.length}`,
		`compact_resume_routes=${compactResumeSignals.routingHints.length}`,
	];
	const similarityIndex = nodes
		.filter((node) => node.path)
		.sort((a, b) => b.score - a.score)
		.slice(0, 16)
		.map((node) => `${node.score} ${node.kind} ${node.tags.join(",")} ${node.path}`);
	const workerRoutingHints = Array.from(new Set([...knowledgeWorkerHints(allTags), ...adaptiveRoutingHints])).slice(
		0,
		24,
	);
	const commandStrategyHints = Array.from(
		new Set([
			...filtered.flatMap((source) => knowledgeCommandHints(source.text)),
			...adaptiveRoutingHints.flatMap((hint) => knowledgeCommandHints(hint)),
			...workerPromotionQueue.flatMap((hint) => knowledgeCommandHints(hint)),
			...dispatcherRoutingHints.flatMap((hint) => knowledgeCommandHints(hint)),
			...dispatcherScoreDecay.flatMap((hint) => knowledgeCommandHints(hint)),
			...repeatedFailureDemotions.flatMap((hint) => knowledgeCommandHints(hint)),
			...highScorePromotions.flatMap((hint) => knowledgeCommandHints(hint)),
			...compactResumeSignals.commandHints,
			...compactResumeSignals.routingHints.flatMap((hint) => knowledgeCommandHints(hint)),
			...compactResumeSignals.caseMemory.flatMap((hint) => knowledgeCommandHints(hint)),
			...autonomousBudget.nextActions,
			...adaptiveRoutingHints.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
			...workerPromotionQueue.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
			...dispatcherRoutingHints.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
			...dispatcherScoreDecay.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
			...repeatedFailureDemotions.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
			...highScorePromotions.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
			...compactResumeSignals.routingHints.flatMap((hint) => hint.match(/re[-_][\w-]+(?:\s+[^\s;&]+){0,4}/gi) ?? []),
		]),
	).slice(0, 24);
	const nextActions = Array.from(
		new Set([
			...compactResumeSignals.commandHints,
			...(commandStrategyHints.length ? commandStrategyHints.slice(0, 8) : ["re_map <target> 2"]),
			...autonomousBudget.nextActions,
			"re_context pack",
			"re_operator plan",
			"re_complete audit",
		]),
	).slice(0, 16);
	return {
		timestamp: new Date().toISOString(),
		missionId,
		route,
		target: options.target,
		mode: options.mode ?? (query ? "query" : "build"),
		query: options.query,
		nodes,
		edges: edges.slice(0, 240),
		caseSignatures,
		similarityIndex,
		workerRoutingHints,
		workerScoreboard: scoreboard.lines.slice(0, 32),
		adaptiveRoutingHints,
		workerPromotionQueue,
		commandStrategyHints,
		dispatcherFeedbackScoreboard: dispatcherBoard.lines.slice(0, 32),
		dispatcherRoutingHints,
		compactResumeTelemetry: compactResumeSignals.lines,
		compactResumeCaseMemory: compactResumeSignals.caseMemory,
		compactResumeRoutingHints: compactResumeSignals.routingHints,
		autonomousBudget,
		dispatcherScoreDecay,
		repeatedFailureDemotions,
		highScorePromotions,
		nextActions,
		sourceArtifacts: Array.from(
			new Set(
				[
					...filtered.map((source) => source.path),
					dispatcherBoard.path,
					autonomousBudget.promotionPlaybookPath,
					...compactResumeSignals.sourceArtifacts,
				].filter(Boolean) as string[],
			),
		).slice(0, 80),
	};
}

function formatKnowledgeGraph(graph: KnowledgeGraphArtifact, path?: string): string {
	return [
		"knowledge_graph:",
		path ? `knowledge_artifact: ${path}` : undefined,
		`timestamp: ${graph.timestamp}`,
		`mode: ${graph.mode}`,
		`mission_id: ${graph.missionId ?? "none"}`,
		`route: ${graph.route ?? "none"}`,
		`target: ${graph.target ?? "<none>"}`,
		`query: ${graph.query ?? "<none>"}`,
		`nodes: ${graph.nodes.length}`,
		`edges: ${graph.edges.length}`,
		"case_signatures:",
		...(graph.caseSignatures.length ? graph.caseSignatures.map((item) => `- ${item}`) : ["- none"]),
		"artifact_nodes:",
		...graph.nodes
			.filter((node) => node.path)
			.sort((a, b) => b.score - a.score)
			.slice(0, 24)
			.map((node) => `- ${node.id} score=${node.score} tags=${node.tags.join(",")} path=${node.path}`),
		"high_value_edges:",
		...(graph.edges.length
			? graph.edges.slice(0, 32).map((edge) => `- ${edge.from} -> ${edge.to} [${edge.kind}] ${edge.label ?? ""}`)
			: ["- none"]),
		"similarity_index:",
		...(graph.similarityIndex.length ? graph.similarityIndex.map((item) => `- ${item}`) : ["- none"]),
		"worker_routing_hints:",
		...(graph.workerRoutingHints.length ? graph.workerRoutingHints.map((item) => `- ${item}`) : ["- none"]),
		"worker_scoreboard:",
		...(graph.workerScoreboard?.length ? graph.workerScoreboard.map((item) => `- ${item}`) : ["- none"]),
		"adaptive_routing_hints:",
		...(graph.adaptiveRoutingHints?.length ? graph.adaptiveRoutingHints.map((item) => `- ${item}`) : ["- none"]),
		"worker_promotion_queue:",
		...(graph.workerPromotionQueue?.length ? graph.workerPromotionQueue.map((item) => `- ${item}`) : ["- none"]),
		"command_strategy_hints:",
		...(graph.commandStrategyHints.length ? graph.commandStrategyHints.map((item) => `- ${item}`) : ["- none"]),
		"dispatcher_feedback_scoreboard:",
		...(graph.dispatcherFeedbackScoreboard?.length
			? graph.dispatcherFeedbackScoreboard.map((item) => `- ${item}`)
			: ["- none"]),
		"dispatcher_routing_hints:",
		...(graph.dispatcherRoutingHints?.length ? graph.dispatcherRoutingHints.map((item) => `- ${item}`) : ["- none"]),
		"compact_resume_telemetry:",
		...(graph.compactResumeTelemetry?.length ? graph.compactResumeTelemetry.map((item) => `- ${item}`) : ["- none"]),
		"compact_resume_case_memory:",
		...(graph.compactResumeCaseMemory?.length
			? graph.compactResumeCaseMemory.map((item) => `- ${item}`)
			: ["- none"]),
		"compact_resume_routing_hints:",
		...(graph.compactResumeRoutingHints?.length
			? graph.compactResumeRoutingHints.map((item) => `- ${item}`)
			: ["- none"]),
		"autonomous_execution_budget:",
		...autonomousBudgetLines(graph.autonomousBudget).map((item) => `- ${item}`),
		"dispatcher_score_decay:",
		...(graph.dispatcherScoreDecay?.length ? graph.dispatcherScoreDecay.map((item) => `- ${item}`) : ["- none"]),
		"repeated_failure_demotions:",
		...(graph.repeatedFailureDemotions?.length
			? graph.repeatedFailureDemotions.map((item) => `- ${item}`)
			: ["- none"]),
		"high_score_promotions:",
		...(graph.highScorePromotions?.length ? graph.highScorePromotions.map((item) => `- ${item}`) : ["- none"]),
		"knowledge_next_actions:",
		...(graph.nextActions.length ? graph.nextActions.map((item) => `- ${item}`) : ["- re_context pack"]),
		`next_knowledge_command: ${graph.mode === "query" ? "re_knowledge_graph build" : "re_knowledge_graph query <term>"}`,
		"source_artifacts:",
		...(graph.sourceArtifacts.length ? graph.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeKnowledgeGraphArtifact(graph: KnowledgeGraphArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceKnowledgeDir(),
		`${graph.timestamp.replace(/[:.]/g, "-")}-${slug(graph.route ?? "knowledge")}-${graph.mode}.md`,
	);
	writeFileSync(
		path,
		[
			"# Pi-RECON Knowledge Graph Artifact",
			"",
			formatKnowledgeGraph(graph, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(graph, null, 2),
			"```",
			"",
		].join("\n"),
		"utf-8",
	);
	writeFileSync(
		memoryPath("knowledge-graph-index.md"),
		[
			"# Pi-RECON Knowledge Graph Index",
			"",
			`Updated: ${graph.timestamp}`,
			`Artifact: ${path}`,
			"",
			"## Case signatures",
			...graph.caseSignatures.map((item) => `- ${item}`),
			"",
			"## Similarity index",
			...graph.similarityIndex.map((item) => `- ${item}`),
			"",
			"## Worker routing hints",
			...graph.workerRoutingHints.map((item) => `- ${item}`),
			"",
			"## Worker scoreboard",
			...(graph.workerScoreboard?.length ? graph.workerScoreboard.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Adaptive routing hints",
			...(graph.adaptiveRoutingHints?.length ? graph.adaptiveRoutingHints.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Worker promotion queue",
			...(graph.workerPromotionQueue?.length ? graph.workerPromotionQueue.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Dispatcher feedback scoreboard",
			...(graph.dispatcherFeedbackScoreboard?.length
				? graph.dispatcherFeedbackScoreboard.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Dispatcher routing hints",
			...(graph.dispatcherRoutingHints?.length
				? graph.dispatcherRoutingHints.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Compact resume telemetry",
			...(graph.compactResumeTelemetry?.length
				? graph.compactResumeTelemetry.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Compact resume case memory",
			...(graph.compactResumeCaseMemory?.length
				? graph.compactResumeCaseMemory.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Compact resume routing hints",
			...(graph.compactResumeRoutingHints?.length
				? graph.compactResumeRoutingHints.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## Autonomous execution budget",
			...autonomousBudgetLines(graph.autonomousBudget).map((item) => `- ${item}`),
			"",
			"## Dispatcher score decay",
			...(graph.dispatcherScoreDecay?.length ? graph.dispatcherScoreDecay.map((item) => `- ${item}`) : ["- none"]),
			"",
			"## Repeated failure demotions",
			...(graph.repeatedFailureDemotions?.length
				? graph.repeatedFailureDemotions.map((item) => `- ${item}`)
				: ["- none"]),
			"",
			"## High-score promotions",
			...(graph.highScorePromotions?.length ? graph.highScorePromotions.map((item) => `- ${item}`) : ["- none"]),
			"",
		].join("\n"),
		"utf-8",
	);
	writeDispatcherPromotionPlaybook({
		target: graph.target,
		timestamp: graph.timestamp,
		artifactPath: path,
		scoreboard: graph.dispatcherFeedbackScoreboard,
		learningHints: graph.dispatcherRoutingHints,
	});
	appendEvidence({
		kind: "artifact",
		title: `knowledge-graph-${graph.mode} ${graph.missionId ?? "no-mission"}`,
		fact: `Knowledge graph ${graph.mode}: nodes=${graph.nodes.length}, edges=${graph.edges.length}, signatures=${graph.caseSignatures.length}, adaptive_routes=${graph.adaptiveRoutingHints.length}, promotions=${graph.workerPromotionQueue.length}, dispatcher_feedback=${graph.dispatcherFeedbackScoreboard.length}, dispatcher_routes=${graph.dispatcherRoutingHints.length}, compact_resume_case_memory=${graph.compactResumeCaseMemory.length}, compact_resume_routes=${graph.compactResumeRoutingHints.length}, autonomous_budget=${graph.autonomousBudget?.maxTurns ?? "none"}/${graph.autonomousBudget?.maxDispatch ?? "none"}, score_decay=${(graph.dispatcherScoreDecay ?? []).length}, demotions=${(graph.repeatedFailureDemotions ?? []).length}, high_score_promotions=${(graph.highScorePromotions ?? []).length}`,
		command: `re_knowledge_graph ${graph.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "cross-artifact knowledge graph",
	});
	updateMissionGate("knowledge_graph_ready", "done", path);
	updateMissionGate("memory_or_evolution_written", "done", memoryPath("knowledge-graph-index.md"));
	return path;
}

function buildKnowledgeGraphOutput(
	action: "build" | "show" | "query" = "build",
	options: { target?: string; query?: string } = {},
): string {
	if (action === "show") {
		const path = latestKnowledgeGraphArtifactPath();
		if (!path) return "knowledge_graph:\nstatus: missing\nnext: re_knowledge_graph build";
		return truncateMiddle(readText(path), 22000);
	}
	const graph = buildKnowledgeGraph({
		target: options.target,
		query: action === "query" ? options.query : undefined,
		mode: action === "query" ? "query" : "build",
	});
	const path = writeKnowledgeGraphArtifact(graph);
	return formatKnowledgeGraph(graph, path);
}

function latestHarnessArtifactPath(): string | undefined {
	return recentMarkdownArtifacts(evidenceHarnessDir(), 1)[0];
}

function harnessWorkspacePath(relativePath: string): string {
	return join(process.cwd(), relativePath);
}

function harnessWritableDirCheck(id: string, dir: string): HarnessCheck {
	try {
		mkdirSync(dir, { recursive: true });
		const probe = join(dir, `.pi-recon-harness-probe-${Date.now()}.tmp`);
		writeFileSync(probe, "ok\n", "utf-8");
		unlinkSync(probe);
		return { id, status: "pass", evidence: [`writable=${dir}`] };
	} catch (error) {
		return {
			id,
			status: "fail",
			evidence: [`not_writable=${dir}`, `error=${error instanceof Error ? error.message : String(error)}`],
			next: [`mkdir -p ${shellQuote(dir)}`, `re_harness install`],
		};
	}
}

function harnessFileCheck(params: {
	id: string;
	path: string;
	markers?: string[];
	missingStatus?: HarnessCheckStatus;
}): HarnessCheck {
	const missingStatus = params.missingStatus ?? "warn";
	if (!existsSync(params.path)) {
		return {
			id: params.id,
			status: missingStatus,
			evidence: [`missing=${params.path}`],
			next: [`restore_or_install ${params.path}`],
		};
	}
	const text = readText(params.path);
	const missingMarkers = (params.markers ?? []).filter((marker) => !text.includes(marker));
	if (missingMarkers.length > 0) {
		return {
			id: params.id,
			status: "fail",
			evidence: [`path=${params.path}`, `missing_markers=${missingMarkers.join(",")}`],
			next: [`repair markers in ${params.path}`, "re_harness full"],
		};
	}
	return {
		id: params.id,
		status: "pass",
		evidence: [`path=${params.path}`, ...(params.markers?.length ? [`markers=${params.markers.join(",")}`] : [])],
	};
}

