				const maxSteps = maxText && /^\d+$/.test(maxText) ? Number(maxText) : undefined;
				const text = await runAutoLaneChain(pi, { lane: laneName, maxSteps });
				sendDisplayMessage(pi, "Pi-RECON Lane Auto Runner", text);
