	pi.registerTool({
		name: "re_memory",
		label: "RE Memory",
		description: "Read, search, append, evolve, or maintain Pi-RECON long-term memory and playbooks.",
		promptSnippet: "Use long-term reverse/pentest memory for reusable evidence and lessons.",
		promptGuidelines: ["Before repeating a known security workflow, inspect re_memory for similar cases."],
		parameters: Type.Object({
			action: Type.Union([
				Type.Literal("show"),
				Type.Literal("search"),
				Type.Literal("append"),
				Type.Literal("evolve"),
				Type.Literal("playbooks"),
				Type.Literal("prune-playbooks"),
			]),
			query: Type.Optional(Type.String()),
			scene: Type.Optional(Type.String()),
			title: Type.Optional(Type.String()),
			text: Type.Optional(Type.String()),
		}),
		async execute(_toolCallId, params) {
			if (params.action === "append") {
				const anchor = appendJournal(params.scene ?? "agent", params.title ?? "field-note", params.text ?? "");
				updateMissionGate("memory_or_evolution_written", "done", anchor);
				return {
					content: [{ type: "text" as const, text: `Appended field journal entry: ${anchor}` }],
					details: { anchor } as Record<string, unknown>,
				};
			}
			if (params.action === "evolve") {
				const anchor = appendEvolution(params.title ?? "agent evolution", params.text ?? "");
				updateMissionGate("memory_or_evolution_written", "done", anchor);
				return {
					content: [{ type: "text" as const, text: `Appended evolution entry: ${anchor}` }],
					details: { anchor } as Record<string, unknown>,
				};
			}
			if (params.action === "playbooks" || params.action === "prune-playbooks") {
				const result = maintainPlaybooks({ archive: params.action === "prune-playbooks" });
				return {
					content: [{ type: "text" as const, text: formatPlaybookMaintenance(result) }],
					details: result as unknown as Record<string, unknown>,
				};
			}
			const memory = buildMemoryDigest();
			if (params.action === "search") {
				updateMissionGate("memory_checked", "done", `search:${params.query ?? ""}`);
				const query = (params.query ?? "").toLowerCase();
				const lines = memory
					.split(/\r?\n/)
					.filter((line) => !query || line.toLowerCase().includes(query))
					.slice(0, 120);
				return {
					content: [{ type: "text" as const, text: lines.length ? lines.join("\n") : "No matching memory lines" }],
					details: { query, matches: lines.length } as Record<string, unknown>,
				};
			}
			updateMissionGate("memory_checked", "done", "show");
			return { content: [{ type: "text" as const, text: memory }], details: { path: reconDir() } };
		},
	});
